        stage.setTitle("Agenda Científica Pessoal — Planejamento Integrado");
        stage.setScene(scene);
        stage.setOnCloseRequest(e -> {
            WindowManager.closeAll();
            Platform.exit();
        });
        stage.show();

        // Carga inicial de todos os dados
        refreshAllData(YearMonth.now());
