    // ── Coordenação de refreshes ───────────────────────────────────────────

    private void refreshAllData(YearMonth month) {
        ctx.refreshCategories();
        agendaCtrl.refresh();              // agenda + alertas + upcoming
        checklistCtrl.refresh();
        financeCtrl.refresh();
        salesCtrl.refresh();
        studyCtrl.refresh();
        ideasCtrl.refresh();
