package com.pessoal.agenda.ui.view;

import com.pessoal.agenda.app.AppContextHolder;
import com.pessoal.agenda.model.IdeaChecklistItem;
import com.pessoal.agenda.model.ProjectIdea;
import com.pessoal.agenda.repository.IdeaChecklistRepository;
import javafx.application.Platform;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.input.Clipboard;
import javafx.scene.input.ClipboardContent;
import javafx.scene.input.MouseButton;
import javafx.scene.layout.*;
import javafx.stage.Modality;
import javafx.stage.Stage;

import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.HashMap;

/**
 * Janela dedicada de Checklist/Kanban para Ideia / Projeto Científico.
 *
 * Modos de visualização:
 *   • Lista  — flat list com filtros (Todos / Pendentes / Concluídos)
 *   • Kanban — board com 4 colunas: Backlog | Em Andamento | Em Revisão | Concluído
 */
public class ProjectChecklistWindow {

    // ── Colunas do Kanban ─────────────────────────────────────────────────────
    private static final String[][] KANBAN_COLS = {
        {"backlog",      "  Backlog",        "#546e7a"},
        {"em_andamento", "⚡  Em Andamento",   "#1565c0"},
        {"em_revisao",   "  Em Revisão",     "#7b1fa2"},
        {"concluido",    "✅  Concluído",       "#2e7d32"},
    };

    // ── Prevenção de janela duplicada ─────────────────────────────────────────
    private static final Map<Long, Stage> openWindows = new HashMap<>();

    private final ProjectIdea idea;
    private final IdeaChecklistRepository repo;
    private final Runnable onChanged;

    // ── Estado em memória ─────────────────────────────────────────────────────
    private final List<MutableItem> items = new ArrayList<>();

    // ── Modo de visualização ──────────────────────────────────────────────────
    private boolean isKanban = false;

    // ── Filtro de exibição (lista) ────────────────────────────────────────────
    private enum Filter { ALL, PENDING, DONE }
    private Filter currentFilter = Filter.ALL;

    // ── Componentes da UI ─────────────────────────────────────────────────────
    private VBox itemsBox;
    private StackPane contentArea;
    private Label kpiTotal, kpiDone, kpiPending, kpiPercent;
    private ProgressBar progressBar;
    private Label progressLabel;

    // ── Context menu único reutilizável para itens ────────────────────────────
    private final ContextMenu itemContextMenu = new ContextMenu();

    // ── Modelo mutável de item ────────────────────────────────────────────────
    private static class MutableItem {
        long    id;
        String  text;
        boolean done;
        int     position;
        String  kanbanColumn;

        MutableItem(IdeaChecklistItem src) {
            this.id           = src.id();
            this.text         = src.text();
            this.done         = src.done();
            this.position     = src.position();
            this.kanbanColumn = src.kanbanColumn() != null ? src.kanbanColumn() : "backlog";
        }
    }

    // ── Construtor ────────────────────────────────────────────────────────────

    public ProjectChecklistWindow(ProjectIdea idea, IdeaChecklistRepository repo, Runnable onChanged) {
        this.idea      = idea;
        this.repo      = repo;
        this.onChanged = onChanged;
    }

    // ── Ponto de entrada ──────────────────────────────────────────────────────

    public void show() {
        if (openWindows.containsKey(idea.id())) {
            openWindows.get(idea.id()).toFront();
            openWindows.get(idea.id()).requestFocus();
            return;
        }

        loadItems();

        Stage stage = new Stage();
        stage.initModality(Modality.NONE);
        stage.setTitle("Checklist — " + idea.title());
        stage.setMinWidth(640);
        stage.setMinHeight(540);
        openWindows.put(idea.id(), stage);
        stage.setOnHidden(e -> openWindows.remove(idea.id()));

        VBox root = new VBox(0);
        root.getStylesheets().add(
                getClass().getResource("/com/pessoal/agenda/app.css").toExternalForm());
        root.getStyleClass().add("app-root");

        contentArea = new StackPane();
        VBox.setVgrow(contentArea, Priority.ALWAYS);

        root.getChildren().addAll(
                buildHeader(),
                buildKpiBar(),
                buildProgressSection(),
                buildViewToolbar(),
                contentArea,
                buildFooter(stage)
        );

        refreshContentArea();

        stage.setScene(new Scene(root, 880, 660));
        stage.show();
    }

    // ── Carregamento ──────────────────────────────────────────────────────────

    private void loadItems() {
        items.clear();
        repo.findByIdeaId(idea.id()).forEach(i -> items.add(new MutableItem(i)));
    }

    // ── Cabeçalho ─────────────────────────────────────────────────────────────

    private HBox buildHeader() {
        Label icon = new Label("☑");
        icon.setStyle("-fx-font-size: 28px; -fx-text-fill: #00b4d8;");

        Label title = new Label("Checklist do Projeto");
        title.getStyleClass().add("page-title");

        Label subtitle = new Label(idea.title()
                + "  ·  " + idea.typeLabel()
                + "  ·  " + idea.priorityLabel());
        subtitle.getStyleClass().add("page-subtitle");

        VBox texts = new VBox(2, title, subtitle);
        Region spacer = new Region();
        HBox.setHgrow(spacer, Priority.ALWAYS);

        Label statusBadge = new Label(idea.statusLabel());
        statusBadge.setStyle(
                "-fx-background-color: #1565c0; -fx-text-fill: white;"
                + " -fx-font-size: 11px; -fx-font-weight: 700;"
                + " -fx-padding: 4 10 4 10; -fx-background-radius: 12;");

        HBox hdr = new HBox(14, icon, texts, spacer, statusBadge);
        hdr.getStyleClass().add("header-bar");
        hdr.setPadding(new Insets(14, 20, 14, 20));
        hdr.setAlignment(Pos.CENTER_LEFT);
        return hdr;
    }

    // ── KPI bar ───────────────────────────────────────────────────────────────

    private HBox buildKpiBar() {
        kpiTotal   = kpiValue("0");
        kpiDone    = kpiValue("0");
        kpiPending = kpiValue("0");
        kpiPercent = kpiValue("0%");

        HBox bar = new HBox(10,
                kpiCard("TOTAL DE ITENS",   kpiTotal,   "kpi-blue"),
                kpiCard("CONCLUÍDOS",       kpiDone,    "kpi-green"),
                kpiCard("PENDENTES",        kpiPending, "kpi-indigo"),
                kpiCard("PROGRESSO",        kpiPercent, "kpi-cyan"));
        bar.setPadding(new Insets(12, 14, 4, 14));
        for (javafx.scene.Node n : bar.getChildren()) HBox.setHgrow(n, Priority.ALWAYS);
        refreshKpiAndProgress();
        return bar;
    }

    private Label kpiValue(String v) {
        Label l = new Label(v); l.getStyleClass().add("kpi-value"); return l;
    }
    private VBox kpiCard(String title, Label value, String cls) {
        Label lbl = new Label(title); lbl.getStyleClass().add("kpi-title");
        VBox c = new VBox(4, lbl, value); c.getStyleClass().addAll("kpi-card", cls); return c;
    }

    // ── Barra de progresso ────────────────────────────────────────────────────

    private VBox buildProgressSection() {
        progressBar = new ProgressBar(0);
        progressBar.setMaxWidth(Double.MAX_VALUE);
        progressBar.setPrefHeight(14);

        progressLabel = new Label("0 de 0 itens concluídos");
        progressLabel.setStyle("-fx-font-size: 11.5px; -fx-text-fill: #5a7a9e;"
                + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");

        VBox section = new VBox(6, progressBar, progressLabel);
        section.setPadding(new Insets(8, 14, 8, 14));
        section.setStyle("-fx-background-color: white;"
                + " -fx-border-color: transparent transparent #dce8f5 transparent;"
                + " -fx-border-width: 0 0 1 0;");
        return section;
    }

    // ── Barra de ferramentas com toggle Lista/Kanban + filtros ─────────────────

    private HBox buildViewToolbar() {
        // Toggle: Lista / Kanban
        ToggleGroup viewGroup = new ToggleGroup();
        ToggleButton listBtn   = new ToggleButton("☰  Lista");
        ToggleButton kanbanBtn = new ToggleButton("⬛  Kanban");
        listBtn.setToggleGroup(viewGroup);   listBtn.setSelected(true);
        kanbanBtn.setToggleGroup(viewGroup);
        listBtn.getStyleClass().add("view-toggle-btn");
        kanbanBtn.getStyleClass().add("view-toggle-btn");
        HBox viewToggle = new HBox(2, listBtn, kanbanBtn);
        viewToggle.getStyleClass().add("view-toggle-bar");

        listBtn.setOnAction(e -> {
            if (!listBtn.isSelected()) { listBtn.setSelected(true); return; }
            isKanban = false; refreshContentArea();
        });
        kanbanBtn.setOnAction(e -> {
            if (!kanbanBtn.isSelected()) { kanbanBtn.setSelected(true); return; }
            isKanban = true; refreshContentArea();
        });

        // Separador
        Separator sep = new Separator(javafx.geometry.Orientation.VERTICAL);
        sep.setPadding(new Insets(0, 4, 0, 4));

        // Filtros de lista
        ToggleGroup filterGroup = new ToggleGroup();
        ToggleButton allBtn   = filterToggle("Todos",      filterGroup, Filter.ALL);
        ToggleButton pendBtn  = filterToggle("Pendentes",  filterGroup, Filter.PENDING);
        ToggleButton doneBtn  = filterToggle("Concluídos", filterGroup, Filter.DONE);
        allBtn.setSelected(true);
        HBox filterBar = new HBox(2, allBtn, pendBtn, doneBtn);
        filterBar.getStyleClass().add("view-toggle-bar");

        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);

        Button checkAllBtn   = new Button("✔  Marcar Todos");
        Button uncheckAllBtn = new Button("☐  Desmarcar Todos");
        Button clearDoneBtn  = new Button("  Limpar Concluídos");
        checkAllBtn.getStyleClass().add("secondary-button");
        uncheckAllBtn.getStyleClass().add("secondary-button");
        clearDoneBtn.getStyleClass().add("danger-button");
        checkAllBtn.setStyle("-fx-font-size: 11px;");
        uncheckAllBtn.setStyle("-fx-font-size: 11px;");
        clearDoneBtn.setStyle("-fx-font-size: 11px;");
        checkAllBtn.setOnAction(e -> markAll(true));
        uncheckAllBtn.setOnAction(e -> markAll(false));
        clearDoneBtn.setOnAction(e -> clearDoneItems());

        Button addBtn = new Button("＋  Novo Item");
        addBtn.getStyleClass().add("primary-button");
        addBtn.setStyle("-fx-font-size: 11px;");
        addBtn.setOnAction(e -> showAddItemDialog());

        Button printBtn = new Button("  Imprimir");
        printBtn.getStyleClass().add("secondary-button");
        printBtn.setStyle("-fx-font-size: 11px;");
        printBtn.setOnAction(e -> printChecklist());

        HBox bar = new HBox(8, viewToggle, sep, filterBar, spacer,
                checkAllBtn, uncheckAllBtn, clearDoneBtn, printBtn, addBtn);
        bar.setPadding(new Insets(8, 14, 8, 14));
        bar.setAlignment(Pos.CENTER_LEFT);
        bar.setStyle("-fx-background-color: #f2f7fc;"
                + " -fx-border-color: transparent transparent #dce8f5 transparent;"
                + " -fx-border-width: 0 0 1 0;");
        return bar;
    }

    private ToggleButton filterToggle(String label, ToggleGroup tg, Filter filter) {
        ToggleButton btn = new ToggleButton(label);
        btn.setToggleGroup(tg);
        btn.getStyleClass().add("view-toggle-btn");
        btn.setOnAction(e -> {
            if (!btn.isSelected()) { btn.setSelected(true); return; }
            currentFilter = filter;
            if (!isKanban) refreshContentArea();
        });
        return btn;
    }

    // ── Impressão do checklist ────────────────────────────────────────────────

    private void printChecklist() {
        // ── Diálogo de filtros ────────────────────────────────────────────
        ComboBox<String> dlgItemsFilter = new ComboBox<>();
        dlgItemsFilter.getItems().addAll("Todos os itens", "Apenas Pendentes", "Apenas Concluídos");
        dlgItemsFilter.setValue(switch (currentFilter) {
            case PENDING -> "Apenas Pendentes";
            case DONE    -> "Apenas Concluídos";
            default      -> "Todos os itens";
        });
        dlgItemsFilter.getStyleClass().add("input-control");
        dlgItemsFilter.setMaxWidth(Double.MAX_VALUE);

        ComboBox<String> dlgColFilter = new ComboBox<>();
        dlgColFilter.getItems().add("Todas as colunas");
        for (String[] c : KANBAN_COLS) dlgColFilter.getItems().add(c[1].replace("  ", " ").trim());
        dlgColFilter.setValue("Todas as colunas");
        dlgColFilter.getStyleClass().add("input-control");
        dlgColFilter.setMaxWidth(Double.MAX_VALUE);

        javafx.scene.layout.GridPane grid = new javafx.scene.layout.GridPane();
        grid.setHgap(10); grid.setVgap(8); grid.setPadding(new Insets(10, 0, 0, 0));
        grid.add(new Label("Mostrar:"), 0, 0); grid.add(dlgItemsFilter, 1, 0);
        grid.add(new Label("Coluna:"),  0, 1); grid.add(dlgColFilter,   1, 1);
        javafx.scene.layout.GridPane.setHgrow(dlgItemsFilter, Priority.ALWAYS);
        javafx.scene.layout.GridPane.setHgrow(dlgColFilter,   Priority.ALWAYS);

        Dialog<ButtonType> printDlg = new Dialog<>();
        printDlg.setTitle("Opções de Impressão");
        printDlg.setHeaderText("Checklist — " + idea.title());
        printDlg.getDialogPane().setContent(grid);
        printDlg.getDialogPane().setMinWidth(380);
        printDlg.getDialogPane().getButtonTypes().addAll(ButtonType.OK, ButtonType.CANCEL);
        ((Button) printDlg.getDialogPane().lookupButton(ButtonType.OK)).setText(" Gerar Checklist");
        ((Button) printDlg.getDialogPane().lookupButton(ButtonType.CANCEL)).setText("Cancelar");

        var dlgResult = printDlg.showAndWait();
        if (dlgResult.isEmpty() || dlgResult.get() != ButtonType.OK) return;

        // ── Determinar coluna selecionada ─────────────────────────────────
        String colSel = dlgColFilter.getValue();
        String colKey = "Todas as colunas".equals(colSel) ? null :
                java.util.Arrays.stream(KANBAN_COLS)
                        .filter(c -> c[1].replace("  ", " ").trim().equals(colSel))
                        .map(c -> c[0])
                        .findFirst().orElse(null);

        // ── Filtrar itens conforme seleção ────────────────────────────────
        String itemsSel = dlgItemsFilter.getValue();
        List<com.pessoal.agenda.model.IdeaChecklistItem> checkItems = items.stream()
                .filter(mi -> switch (itemsSel) {
                    case "Apenas Pendentes"  -> !mi.done;
                    case "Apenas Concluídos" ->  mi.done;
                    default                  -> true;
                })
                .filter(mi -> colKey == null || colKey.equals(mi.kanbanColumn))
                .map(mi -> new com.pessoal.agenda.model.IdeaChecklistItem(
                        mi.id, idea.id(), mi.text, mi.done, mi.position, mi.kanbanColumn))
                .toList();

        String html = com.pessoal.agenda.ui.util.PrintReportService
                .generateProjectChecklistReport(idea, checkItems);
        PrintPreviewWindow.open(html, "Checklist — " + idea.title());
    }

    // ── Diálogo de adição de item ─────────────────────────────────────────────

    private void showAddItemDialog() {
        TextField field = new TextField();
        field.getStyleClass().add("input-control");
        field.setPromptText("Descreva o item...");
        field.setPrefWidth(380);

        ComboBox<String> colCombo = new ComboBox<>();
        colCombo.getStyleClass().add("input-control");
        for (String[] c : KANBAN_COLS) colCombo.getItems().add(c[1].replace("  ", " ").trim());
        colCombo.setValue(KANBAN_COLS[0][1].replace("  ", " ").trim());

        VBox content = new VBox(8,
                new Label("Texto do item:"), field,
                new Label("Coluna inicial:"), colCombo);
        content.setPadding(new Insets(10));

        Dialog<ButtonType> dlg = new Dialog<>();
        dlg.setTitle("Novo Item");
        dlg.setHeaderText("Adicionar item ao checklist");
        dlg.getDialogPane().setContent(content);
        dlg.getDialogPane().getButtonTypes().addAll(ButtonType.OK, ButtonType.CANCEL);
        Platform.runLater(field::requestFocus);

        dlg.showAndWait().ifPresent(btn -> {
            if (btn != ButtonType.OK) return;
            String text = field.getText().trim();
            if (text.isBlank()) return;
            int colIdx = colCombo.getSelectionModel().getSelectedIndex();
            String colKey = KANBAN_COLS[Math.max(0, colIdx)][0];
            IdeaChecklistItem saved = repo.addItem(idea.id(), text);
            // Atualiza a coluna se não for backlog
            if (!"backlog".equals(colKey)) repo.updateColumn(saved.id(), colKey);
            MutableItem mi = new MutableItem(saved);
            mi.kanbanColumn = colKey;
            mi.done = "concluido".equals(colKey);
            items.add(mi);
            refreshAll();
            if (onChanged != null) onChanged.run();
        });
    }

    // ── Área de conteúdo principal ────────────────────────────────────────────

    private void refreshContentArea() {
        if (contentArea == null) return;
        contentArea.getChildren().setAll(isKanban ? buildKanbanView() : buildListView());
    }

    // ──────────────────────────────────────────────────────────────────────────
    // VISTA LISTA
    // ──────────────────────────────────────────────────────────────────────────

    private javafx.scene.Node buildListView() {
        itemsBox = new VBox(0);
        itemsBox.setFillWidth(true);

        ScrollPane sp = new ScrollPane(itemsBox);
        sp.setFitToWidth(true);
        sp.setFitToHeight(false);
        sp.setHbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
        sp.setVbarPolicy(ScrollPane.ScrollBarPolicy.AS_NEEDED);
        sp.getStyleClass().add("edge-to-edge");
        sp.setStyle("-fx-background-color: #f7fbff;");

        refreshItemsUI();
        return sp;
    }

    private void refreshItemsUI() {
        if (itemsBox == null) return;
        itemsBox.getChildren().clear();

        List<MutableItem> visible = items.stream()
                .filter(it -> switch (currentFilter) {
                    case ALL     -> true;
                    case PENDING -> !it.done;
                    case DONE    -> it.done;
                }).toList();

        if (visible.isEmpty()) {
            Label empty = new Label(switch (currentFilter) {
                case PENDING -> "Nenhum item pendente.  Todos os itens foram concluídos!";
                case DONE    -> "Nenhum item concluído ainda.";
                default      -> "Nenhum item no checklist.\nUse o botão ＋ Novo Item para adicionar.";
            });
            empty.setStyle("-fx-text-fill: #9eafc0; -fx-font-size: 12px; -fx-padding: 30 20 30 20;");
            empty.setWrapText(true); empty.setMaxWidth(Double.MAX_VALUE);
            empty.setAlignment(Pos.CENTER);
            itemsBox.getChildren().add(empty);
            return;
        }
        for (int i = 0; i < visible.size(); i++) itemsBox.getChildren().add(buildItemRow(visible.get(i), i));
    }

    private VBox buildItemRow(MutableItem item, int index) {
        CheckBox cb = new CheckBox();
        cb.setSelected(item.done);
        cb.setStyle("-fx-cursor: hand;");

        int globalIdx = items.indexOf(item) + 1;
        Label numLbl = new Label(String.format("%02d", globalIdx));
        numLbl.setStyle("-fx-font-family:'JetBrains Mono','Consolas',monospace;"
                + " -fx-font-size:10px; -fx-text-fill:#9eafc0; -fx-min-width:24px;");

        Label textLbl = new Label(item.text);
        textLbl.setWrapText(true); textLbl.setMaxWidth(Double.MAX_VALUE);
        HBox.setHgrow(textLbl, Priority.ALWAYS);
        applyDoneStyle(textLbl, item.done);

        // Badge de coluna
        String colLabel = columnLabel(item.kanbanColumn);
        String colColor = columnColor(item.kanbanColumn);
        Label colBadge = new Label(colLabel);
        colBadge.setStyle("-fx-background-color:" + colColor + "22; -fx-text-fill:" + colColor + ";"
                + " -fx-font-size:9px; -fx-font-weight:700; -fx-padding:2 6 2 6; -fx-background-radius:8;");

        TextField editField = new TextField(item.text);
        editField.getStyleClass().add("input-control");
        editField.setStyle("-fx-font-size:12px;");
        editField.setVisible(false); editField.setManaged(false);
        HBox.setHgrow(editField, Priority.ALWAYS);

        Button editBtn = new Button("✏");
        editBtn.setTooltip(new Tooltip("Editar (duplo clique)"));
        editBtn.setStyle("-fx-background-color:transparent; -fx-text-fill:#5a7a9e;"
                + " -fx-font-size:12px; -fx-cursor:hand; -fx-padding:2 6 2 6; -fx-background-radius:4;");
        editBtn.setOnAction(e -> enterEditMode(textLbl, editField, item, editBtn));

        Button delBtn = new Button("✕");
        delBtn.setTooltip(new Tooltip("Excluir item"));
        delBtn.setStyle("-fx-background-color:transparent; -fx-text-fill:#9eafc0;"
                + " -fx-font-size:12px; -fx-cursor:hand; -fx-padding:2 6 2 6; -fx-background-radius:4;");
        delBtn.setOnMouseEntered(e -> delBtn.setStyle(
                "-fx-background-color:#fdecea; -fx-text-fill:#c62828;"
                + " -fx-font-size:12px; -fx-cursor:hand; -fx-padding:2 6 2 6; -fx-background-radius:4;"));
        delBtn.setOnMouseExited(e -> delBtn.setStyle(
                "-fx-background-color:transparent; -fx-text-fill:#9eafc0;"
                + " -fx-font-size:12px; -fx-cursor:hand; -fx-padding:2 6 2 6; -fx-background-radius:4;"));
        delBtn.setOnAction(e -> deleteItem(item));

        cb.selectedProperty().addListener((obs, o, n) -> {
            item.done = n;
            item.kanbanColumn = n ? "concluido" : (item.kanbanColumn.equals("concluido") ? "backlog" : item.kanbanColumn);
            repo.updateDone(item.id, n);
            applyDoneStyle(textLbl, n);
            colBadge.setText(columnLabel(item.kanbanColumn));
            colBadge.setStyle("-fx-background-color:" + columnColor(item.kanbanColumn) + "22;"
                    + " -fx-text-fill:" + columnColor(item.kanbanColumn) + ";"
                    + " -fx-font-size:9px; -fx-font-weight:700;"
                    + " -fx-padding:2 6 2 6; -fx-background-radius:8;");
            refreshKpiAndProgress();
            if (onChanged != null) onChanged.run();
        });

        HBox contentRow = new HBox(8, numLbl, textLbl, editField, colBadge);
        contentRow.setAlignment(Pos.CENTER_LEFT);
        HBox.setHgrow(contentRow, Priority.ALWAYS);
        contentRow.setOnMouseClicked(e -> {
            if (e.getClickCount() == 2) enterEditMode(textLbl, editField, item, editBtn);
        });

        HBox row = new HBox(10, cb, contentRow, editBtn, delBtn);
        row.setAlignment(Pos.CENTER_LEFT);
        row.setPadding(new Insets(9, 12, 9, 14));

        String baseColor = index % 2 == 0 ? "#ffffff" : "#f7fbff";
        row.setStyle("-fx-background-color:" + baseColor
                + "; -fx-border-color:transparent transparent #e8f0fa transparent; -fx-border-width:0 0 1 0;");
        row.setOnMouseEntered(e -> row.setStyle("-fx-background-color:#eef6ff;"
                + " -fx-border-color:transparent transparent #e8f0fa transparent; -fx-border-width:0 0 1 0;"));
        row.setOnMouseExited(e  -> row.setStyle("-fx-background-color:" + baseColor
                + "; -fx-border-color:transparent transparent #e8f0fa transparent; -fx-border-width:0 0 1 0;"));

        Region stripe = new Region();
        stripe.setMinWidth(4); stripe.setMaxWidth(4);
        stripe.setStyle("-fx-background-color:" + columnColor(item.kanbanColumn)
                + "; -fx-background-radius:2 0 0 2;");

        HBox outerRow = new HBox(0, stripe, row);
        HBox.setHgrow(row, Priority.ALWAYS);
        outerRow.setAlignment(Pos.CENTER_LEFT);
        outerRow.setOnMouseClicked(e -> {
            if (e.getButton() == MouseButton.SECONDARY) {
                showItemContextMenu(item, textLbl, editField, editBtn, outerRow, e.getScreenX(), e.getScreenY());
                e.consume();
            } else if (e.getButton() == MouseButton.PRIMARY) {
                itemContextMenu.hide();
            }
        });

        return new VBox(outerRow);
    }

    // ──────────────────────────────────────────────────────────────────────────
    // VISTA KANBAN
    // ──────────────────────────────────────────────────────────────────────────

    private javafx.scene.Node buildKanbanView() {
        HBox board = new HBox(10);
        board.setPadding(new Insets(12, 14, 14, 14));
        board.setFillHeight(true);

        for (String[] colDef : KANBAN_COLS) {
            List<MutableItem> colItems = items.stream()
                    .filter(it -> colDef[0].equals(it.kanbanColumn))
                    .toList();
            board.getChildren().add(buildKanbanColumn(colDef, colItems));
        }

        ScrollPane sp = new ScrollPane(board);
        sp.setFitToHeight(true);
        sp.setFitToWidth(false);
        sp.setHbarPolicy(ScrollPane.ScrollBarPolicy.AS_NEEDED);
        sp.setVbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
        sp.getStyleClass().add("edge-to-edge");
        return sp;
    }

    private VBox buildKanbanColumn(String[] colDef, List<MutableItem> colItems) {
        String key = colDef[0], label = colDef[1].replace("  ", " ").trim(), color = colDef[2];

        Label headerLbl = new Label(label + "  (" + colItems.size() + ")");
        headerLbl.setStyle("-fx-font-size:12px; -fx-font-weight:700; -fx-text-fill:white;"
                + " -fx-padding:6 10 6 10; -fx-background-radius:6 6 0 0;"
                + " -fx-background-color:" + color + ";");
        headerLbl.setMaxWidth(Double.MAX_VALUE);

        // Botão + rápido
        Button addColBtn = new Button("+");
        addColBtn.setStyle("-fx-background-color:rgba(255,255,255,0.3); -fx-text-fill:white;"
                + " -fx-background-radius:4; -fx-font-weight:bold; -fx-font-size:14; -fx-cursor:hand;"
                + " -fx-padding:1 7 1 7;");
        addColBtn.setTooltip(new Tooltip("Adicionar item nesta coluna"));
        addColBtn.setOnAction(e -> showAddItemDialogForColumn(key));

        HBox colHeader = new HBox(headerLbl, addColBtn);
        colHeader.setAlignment(Pos.CENTER_LEFT);
        colHeader.setStyle("-fx-background-color:" + color + "; -fx-background-radius:6 6 0 0;");
        HBox.setHgrow(headerLbl, Priority.ALWAYS);

        VBox cards = new VBox(6);
        cards.setPadding(new Insets(8));
        if (colItems.isEmpty()) {
            Label empty = new Label("Sem itens");
            empty.setStyle("-fx-text-fill:#aabbcc; -fx-font-size:11px; -fx-padding:12;");
            cards.getChildren().add(empty);
        } else {
            for (MutableItem it : colItems) cards.getChildren().add(buildKanbanCard(it, color));
        }

        ScrollPane cardScroll = new ScrollPane(cards);
        cardScroll.setFitToWidth(true);
        cardScroll.setHbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
        cardScroll.setStyle("-fx-background-color:#f7fbff; -fx-border-color:transparent;");
        VBox.setVgrow(cardScroll, Priority.ALWAYS);

        VBox col = new VBox(0, colHeader, cardScroll);
        col.setPrefWidth(210); col.setMinWidth(190); col.setMaxWidth(240);
        col.setStyle("-fx-background-color:#f7fbff;"
                + " -fx-border-color:#b8cfe8; -fx-border-radius:6; -fx-background-radius:6;"
                + " -fx-effect:dropshadow(gaussian,rgba(3,24,62,0.07),8,0.2,0,2);");
        VBox.setVgrow(col, Priority.ALWAYS);
        return col;
    }

    private VBox buildKanbanCard(MutableItem item, String accentColor) {
        Label numLbl = new Label(String.format("#%02d", items.indexOf(item) + 1));
        numLbl.setStyle("-fx-font-family:'JetBrains Mono','Consolas',monospace;"
                + " -fx-font-size:9px; -fx-text-fill:#9eafc0;");

        Label textLbl = new Label(item.text);
        textLbl.setWrapText(true); textLbl.setMaxWidth(Double.MAX_VALUE);
        textLbl.setStyle((item.done
                ? "-fx-text-fill:#9eafc0; -fx-strikethrough:true;"
                : "-fx-text-fill:#0d1b2a;") + " -fx-font-size:12px; -fx-wrap-text:true;");

        HBox topRow = new HBox(4, numLbl);
        topRow.setAlignment(Pos.CENTER_LEFT);
        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);

        // Ações rápidas no card
        Button cbBtn = new Button(item.done ? "☑" : "☐");
        cbBtn.setStyle("-fx-background-color:transparent; -fx-cursor:hand;"
                + " -fx-font-size:14px; -fx-padding:0 2 0 2;");
        cbBtn.setTooltip(new Tooltip(item.done ? "Marcar como pendente" : "Marcar como concluído"));
        cbBtn.setOnAction(e -> {
            item.done = !item.done;
            item.kanbanColumn = item.done ? "concluido" : "backlog";
            repo.updateDone(item.id, item.done);
            refreshAll();
            if (onChanged != null) onChanged.run();
        });

        topRow.getChildren().addAll(spacer, cbBtn);

        VBox card = new VBox(4, topRow, textLbl);
        card.setStyle("-fx-background-color:white; -fx-background-radius:5;"
                + " -fx-border-color:" + accentColor + "; -fx-border-width:0 0 0 3;"
                + " -fx-border-radius:5; -fx-padding:8 10 8 10; -fx-cursor:hand;"
                + " -fx-effect:dropshadow(gaussian,rgba(0,0,0,0.06),4,0.2,0,1);");

        // Hover
        card.setOnMouseEntered(e -> card.setStyle(
                "-fx-background-color:#f0f7ff; -fx-background-radius:5;"
                + " -fx-border-color:" + accentColor + "; -fx-border-width:0 0 0 3;"
                + " -fx-border-radius:5; -fx-padding:8 10 8 10; -fx-cursor:hand;"
                + " -fx-effect:dropshadow(gaussian,rgba(0,0,0,0.12),6,0.3,0,2);"));
        card.setOnMouseExited(e -> card.setStyle(
                "-fx-background-color:white; -fx-background-radius:5;"
                + " -fx-border-color:" + accentColor + "; -fx-border-width:0 0 0 3;"
                + " -fx-border-radius:5; -fx-padding:8 10 8 10; -fx-cursor:hand;"
                + " -fx-effect:dropshadow(gaussian,rgba(0,0,0,0.06),4,0.2,0,1);"));

        // Tooltip com texto completo
        if (item.text.length() > 60) {
            Tooltip tp = new Tooltip(item.text);
            tp.setWrapText(true); tp.setMaxWidth(280);
            Tooltip.install(card, tp);
        }

        // Clique direito → context menu
        card.setOnMouseClicked(e -> {
            if (e.getButton() == MouseButton.SECONDARY) {
                showItemContextMenu(item, textLbl, null, null, card, e.getScreenX(), e.getScreenY());
                e.consume();
            } else if (e.getButton() == MouseButton.PRIMARY) {
                itemContextMenu.hide();
            }
        });

        return card;
    }

    private void showAddItemDialogForColumn(String colKey) {
        TextInputDialog dlg = new TextInputDialog();
        dlg.setTitle("Novo Item");
        dlg.setHeaderText("Adicionar item na coluna \u201c" + columnLabel(colKey) + "\u201d");
        dlg.setContentText("Texto:");
        dlg.showAndWait().ifPresent(text -> {
            if (text.isBlank()) return;
            IdeaChecklistItem saved = repo.addItem(idea.id(), text);
            if (!"backlog".equals(colKey)) repo.updateColumn(saved.id(), colKey);
            MutableItem mi = new MutableItem(saved);
            mi.kanbanColumn = colKey;
            mi.done = "concluido".equals(colKey);
            items.add(mi);
            refreshAll();
            if (onChanged != null) onChanged.run();
        });
    }

    // ── Modo de edição inline ─────────────────────────────────────────────────

    private void enterEditMode(Label textLbl, TextField editField, MutableItem item, Button editBtn) {
        if (editField == null) return; // kanban card — usa diálogo
        textLbl.setVisible(false); textLbl.setManaged(false);
        editField.setText(item.text);
        editField.setVisible(true); editField.setManaged(true);
        editField.requestFocus(); editField.selectAll();
        if (editBtn != null) editBtn.setText("");

        Runnable save = () -> {
            String newText = editField.getText().trim();
            if (!newText.isBlank() && !newText.equals(item.text)) {
                item.text = newText; repo.updateText(item.id, newText);
                if (onChanged != null) onChanged.run();
            }
            textLbl.setText(item.text);
            textLbl.setVisible(true); textLbl.setManaged(true);
            editField.setVisible(false); editField.setManaged(false);
            if (editBtn != null) editBtn.setText("✏");
        };
        Runnable cancel = () -> {
            textLbl.setVisible(true); textLbl.setManaged(true);
            editField.setVisible(false); editField.setManaged(false);
            if (editBtn != null) editBtn.setText("✏");
        };
        editField.setOnAction(e -> save.run());
        editField.setOnKeyPressed(e -> { if (e.getCode() == javafx.scene.input.KeyCode.ESCAPE) cancel.run(); });
        if (editBtn != null) editBtn.setOnAction(e -> {
            if ("".equals(editBtn.getText())) save.run();
            else enterEditMode(textLbl, editField, item, editBtn);
        });
    }

    // ── Context menu ──────────────────────────────────────────────────────────

    private void showItemContextMenu(MutableItem item, Label textLbl,
                                     TextField editField, Button editBtn,
                                     javafx.scene.Node anchor, double sx, double sy) {
        itemContextMenu.hide();
        itemContextMenu.getItems().clear();
        itemContextMenu.setAutoHide(true);

        MenuItem copyItem = new MenuItem("  Copiar Texto");
        copyItem.setOnAction(e -> copyToClipboard(item.text));

        MenuItem editItem = new MenuItem("✏  Editar");
        if (editField != null) {
            editItem.setOnAction(e -> enterEditMode(textLbl, editField, item, editBtn));
        } else {
            // No Kanban — usa TextInputDialog
            editItem.setOnAction(e -> {
                TextInputDialog dlg = new TextInputDialog(item.text);
                dlg.setTitle("Editar Item"); dlg.setHeaderText(null);
                dlg.setContentText("Texto:");
                dlg.showAndWait().ifPresent(t -> {
                    if (!t.isBlank() && !t.equals(item.text)) {
                        item.text = t; repo.updateText(item.id, t);
                        refreshAll();
                        if (onChanged != null) onChanged.run();
                    }
                });
            });
        }

        MenuItem toggleItem = item.done
                ? new MenuItem("☐  Marcar como Pendente")
                : new MenuItem("✔  Marcar como Concluído");
        toggleItem.setOnAction(e -> {
            item.done = !item.done;
            item.kanbanColumn = item.done ? "concluido"
                    : (item.kanbanColumn.equals("concluido") ? "backlog" : item.kanbanColumn);
            repo.updateDone(item.id, item.done);
            refreshAll();
            if (onChanged != null) onChanged.run();
        });

        // Submenu "Mover para..."
        Menu moveMenu = new Menu("  Mover para...");
        for (String[] c : KANBAN_COLS) {
            String cKey = c[0], cLabel = c[1].replace("  ", " ").trim();
            MenuItem mi = new MenuItem(cLabel);
            if (cKey.equals(item.kanbanColumn)) mi.setStyle("-fx-font-weight:bold; -fx-text-fill:#1565c0;");
            mi.setOnAction(e -> moveItemToColumn(item, cKey));
            moveMenu.getItems().add(mi);
        }

        SeparatorMenuItem sep = new SeparatorMenuItem();

        MenuItem deleteItem = new MenuItem("  Excluir Item");
        deleteItem.setStyle("-fx-text-fill:#c62828;");
        deleteItem.setOnAction(e -> deleteItem(item));

        itemContextMenu.getItems().addAll(copyItem, editItem, toggleItem, moveMenu, sep, deleteItem);
        itemContextMenu.show(anchor, sx, sy);
    }

    private void moveItemToColumn(MutableItem item, String colKey) {
        item.kanbanColumn = colKey;
        item.done = "concluido".equals(colKey);
        repo.updateColumn(item.id, colKey);
        refreshAll();
        if (onChanged != null) onChanged.run();
    }

    private void deleteItem(MutableItem item) {
        repo.deleteItem(item.id);
        items.remove(item);
        refreshAll();
        if (onChanged != null) onChanged.run();
    }

    // ── Ações em lote ─────────────────────────────────────────────────────────

    private void markAll(boolean done) {
        for (MutableItem it : items) {
            if (it.done != done) {
                it.done = done;
                it.kanbanColumn = done ? "concluido"
                        : (it.kanbanColumn.equals("concluido") ? "backlog" : it.kanbanColumn);
                repo.updateDone(it.id, done);
            }
        }
        refreshAll();
        if (onChanged != null) onChanged.run();
    }

    private void clearDoneItems() {
        long count = items.stream().filter(it -> it.done).count();
        if (count == 0) { new Alert(Alert.AlertType.INFORMATION, "Sem itens concluídos para remover.", ButtonType.OK).showAndWait(); return; }
        Alert confirm = new Alert(Alert.AlertType.CONFIRMATION);
        confirm.setTitle("Limpar Concluídos");
        confirm.setHeaderText("Remover itens concluídos?");
        confirm.setContentText(count + " item(ns) serão excluídos permanentemente.");
        confirm.showAndWait().ifPresent(btn -> {
            if (btn == ButtonType.OK) {
                List<MutableItem> done = items.stream().filter(it -> it.done).toList();
                done.forEach(it -> repo.deleteItem(it.id));
                items.removeAll(done);
                refreshAll();
                if (onChanged != null) onChanged.run();
            }
        });
    }

    // ── Refresh ───────────────────────────────────────────────────────────────

    private void refreshAll() {
        refreshKpiAndProgress();
        refreshContentArea();
    }

    private void refreshKpiAndProgress() {
        int total   = items.size();
        int done    = (int) items.stream().filter(it -> it.done).count();
        int pending = total - done;
        double pct  = total == 0 ? 0.0 : (double) done / total;

        if (kpiTotal   != null) kpiTotal.setText(String.valueOf(total));
        if (kpiDone    != null) kpiDone.setText(String.valueOf(done));
        if (kpiPending != null) kpiPending.setText(String.valueOf(pending));
        if (kpiPercent != null) kpiPercent.setText(Math.round(pct * 100) + "%");

        if (progressBar != null) {
            progressBar.setProgress(pct);
            String accent = pct == 1.0 ? "#1b5e20" : pct >= 0.7 ? "#2e7d32" : pct >= 0.4 ? "#f57f17" : "#c62828";
            progressBar.setStyle("-fx-accent:" + accent
                    + "; -fx-background-color:#d6e4f5; -fx-background-radius:7; -fx-border-radius:7;");
        }
        if (progressLabel != null) progressLabel.setText(
                done + " de " + total + " itens concluídos"
                + (total > 0 ? "  (" + Math.round(pct * 100) + "%)" : ""));
    }

    // ── Rodapé ────────────────────────────────────────────────────────────────

    private HBox buildFooter(Stage stage) {
        Label hint = new Label("  Duplo clique para editar  ·  Botão direito para mais opções  ·  ⬛ Kanban mostra colunas de progresso");
        hint.setStyle("-fx-font-size:11px; -fx-text-fill:#7a9abc;"
                + " -fx-font-family:'JetBrains Mono','Consolas',monospace;");
        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);

        Button printBtn = new Button("  Imprimir Checklist");
        printBtn.getStyleClass().add("secondary-button");
        printBtn.setOnAction(e -> printChecklist());

        Button closeBtn = new Button("✕  Fechar");
        closeBtn.getStyleClass().add("secondary-button");
        closeBtn.setOnAction(e -> stage.close());
        HBox footer = new HBox(12, hint, spacer, printBtn, closeBtn);
        footer.setPadding(new Insets(10, 18, 10, 18)); footer.setAlignment(Pos.CENTER_LEFT);
        footer.setStyle("-fx-background-color:#edf1f8; -fx-border-color:#b8cfe8; -fx-border-width:1 0 0 0;");
        return footer;
    }


    // ── Helpers de Kanban ─────────────────────────────────────────────────────

    private String columnLabel(String key) {
        for (String[] c : KANBAN_COLS) if (c[0].equals(key)) return c[1].replace("  ", " ").trim();
        return key;
    }
    private String columnColor(String key) {
        for (String[] c : KANBAN_COLS) if (c[0].equals(key)) return c[2];
        return "#546e7a";
    }

    // ── Helpers visuais ───────────────────────────────────────────────────────

    private void applyDoneStyle(Label lbl, boolean done) {
        lbl.setStyle(done
                ? "-fx-text-fill:#9eafc0; -fx-strikethrough:true;  -fx-font-size:12px;"
                : "-fx-text-fill:#0d1b2a; -fx-strikethrough:false; -fx-font-size:12px;");
    }

    private void copyToClipboard(String text) {
        ClipboardContent c = new ClipboardContent(); c.putString(text);
        Clipboard.getSystemClipboard().setContent(c);
    }

    // ── Fábrica estática ──────────────────────────────────────────────────────

    public static void open(ProjectIdea idea, Runnable onChanged) {
        IdeaChecklistRepository repo = AppContextHolder.get().ideaChecklistRepository();
        new ProjectChecklistWindow(idea, repo, onChanged).show();
    }
}

package com.pessoal.agenda.ui.view;

import com.pessoal.agenda.app.AppContextHolder;
import com.pessoal.agenda.model.IdeaChecklistItem;
import com.pessoal.agenda.model.ProjectIdea;
import com.pessoal.agenda.repository.IdeaChecklistRepository;
import javafx.application.Platform;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.input.Clipboard;
import javafx.scene.input.ClipboardContent;
import javafx.scene.input.MouseButton;
import javafx.scene.layout.*;
import javafx.stage.Modality;
import javafx.stage.Stage;

import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.HashMap;

/**
 * Janela dedicada de Checklist/Kanban para Ideia / Projeto Científico.
 *
 * Modos de visualização:
 *   • Lista  — flat list com filtros (Todos / Pendentes / Concluídos)
 *   • Kanban — board com 4 colunas: Backlog | Em Andamento | Em Revisão | Concluído
 */
public class ProjectChecklistWindow {

    // ── Colunas do Kanban ─────────────────────────────────────────────────────
    private static final String[][] KANBAN_COLS = {
        {"backlog",      "  Backlog",        "#546e7a"},
        {"em_andamento", "⚡  Em Andamento",   "#1565c0"},
        {"em_revisao",   "  Em Revisão",     "#7b1fa2"},
        {"concluido",    "✅  Concluído",       "#2e7d32"},
    };

    // ── Prevenção de janela duplicada ─────────────────────────────────────────
    private static final Map<Long, Stage> openWindows = new HashMap<>();

    private final ProjectIdea idea;
    private final IdeaChecklistRepository repo;
    private final Runnable onChanged;

    // ── Estado em memória ─────────────────────────────────────────────────────
    private final List<MutableItem> items = new ArrayList<>();

    // ── Modo de visualização ──────────────────────────────────────────────────
    private boolean isKanban = false;

    // ── Filtro de exibição (lista) ────────────────────────────────────────────
    private enum Filter { ALL, PENDING, DONE }
    private Filter currentFilter = Filter.ALL;

    // ── Componentes da UI ─────────────────────────────────────────────────────
    private VBox itemsBox;
    private StackPane contentArea;
    private Label kpiTotal, kpiDone, kpiPending, kpiPercent;
    private ProgressBar progressBar;
    private Label progressLabel;

    // ── Context menu único reutilizável para itens ────────────────────────────
    private final ContextMenu itemContextMenu = new ContextMenu();

    // ── Modelo mutável de item ────────────────────────────────────────────────
    private static class MutableItem {
        long    id;
        String  text;
        boolean done;
        int     position;
        String  kanbanColumn;

        MutableItem(IdeaChecklistItem src) {
            this.id           = src.id();
            this.text         = src.text();
            this.done         = src.done();
            this.position     = src.position();
            this.kanbanColumn = src.kanbanColumn() != null ? src.kanbanColumn() : "backlog";
        }
    }

    // ── Construtor ────────────────────────────────────────────────────────────

    public ProjectChecklistWindow(ProjectIdea idea, IdeaChecklistRepository repo, Runnable onChanged) {
        this.idea      = idea;
        this.repo      = repo;
        this.onChanged = onChanged;
    }

    // ── Ponto de entrada ──────────────────────────────────────────────────────

    public void show() {
        if (openWindows.containsKey(idea.id())) {
            openWindows.get(idea.id()).toFront();
            openWindows.get(idea.id()).requestFocus();
            return;
        }

        loadItems();

        Stage stage = new Stage();
        stage.initModality(Modality.NONE);
        stage.setTitle("Checklist — " + idea.title());
        stage.setMinWidth(640);
        stage.setMinHeight(540);
        openWindows.put(idea.id(), stage);
        stage.setOnHidden(e -> openWindows.remove(idea.id()));

        VBox root = new VBox(0);
        root.getStyleClass().add("app-root");

        contentArea = new StackPane();
        VBox.setVgrow(contentArea, Priority.ALWAYS);

        root.getChildren().addAll(
                buildHeader(),
                buildKpiBar(),
                buildProgressSection(),
                buildViewToolbar(),
                contentArea,
                buildFooter(stage)
        );

        refreshContentArea();

        Scene scene = new Scene(root, 880, 660);
        ThemeManager.getInstance().applyTo(scene);
        stage.setScene(scene);
        stage.show();
    }

    // ── Carregamento ──────────────────────────────────────────────────────────

    private void loadItems() {
        items.clear();
        repo.findByIdeaId(idea.id()).forEach(i -> items.add(new MutableItem(i)));
    }

    // ── Cabeçalho ─────────────────────────────────────────────────────────────

    private HBox buildHeader() {
        Label icon = new Label("☑");
        icon.setStyle("-fx-font-size: 28px; -fx-text-fill: #00b4d8;");

        Label title = new Label("Checklist do Projeto");
        title.getStyleClass().add("page-title");

        Label subtitle = new Label(idea.title()
                + "  ·  " + idea.typeLabel()
                + "  ·  " + idea.priorityLabel());
        subtitle.getStyleClass().add("page-subtitle");

        VBox texts = new VBox(2, title, subtitle);
        Region spacer = new Region();
        HBox.setHgrow(spacer, Priority.ALWAYS);

        Label statusBadge = new Label(idea.statusLabel());
        statusBadge.setStyle(
                "-fx-background-color: #1565c0; -fx-text-fill: white;"
                + " -fx-font-size: 11px; -fx-font-weight: 700;"
                + " -fx-padding: 4 10 4 10; -fx-background-radius: 12;");

        HBox hdr = new HBox(14, icon, texts, spacer, statusBadge);
        hdr.getStyleClass().add("header-bar");
        hdr.setPadding(new Insets(14, 20, 14, 20));
        hdr.setAlignment(Pos.CENTER_LEFT);
        return hdr;
    }

    // ── KPI bar ───────────────────────────────────────────────────────────────

    private HBox buildKpiBar() {
        kpiTotal   = kpiValue("0");
        kpiDone    = kpiValue("0");
        kpiPending = kpiValue("0");
        kpiPercent = kpiValue("0%");

        HBox bar = new HBox(10,
                kpiCard("TOTAL DE ITENS",   kpiTotal,   "kpi-blue"),
                kpiCard("CONCLUÍDOS",       kpiDone,    "kpi-green"),
                kpiCard("PENDENTES",        kpiPending, "kpi-indigo"),
                kpiCard("PROGRESSO",        kpiPercent, "kpi-cyan"));
        bar.setPadding(new Insets(12, 14, 4, 14));
        for (javafx.scene.Node n : bar.getChildren()) HBox.setHgrow(n, Priority.ALWAYS);
        refreshKpiAndProgress();
        return bar;
    }

    private Label kpiValue(String v) {
        Label l = new Label(v); l.getStyleClass().add("kpi-value"); return l;
    }
    private VBox kpiCard(String title, Label value, String cls) {
        Label lbl = new Label(title); lbl.getStyleClass().add("kpi-title");
        VBox c = new VBox(4, lbl, value); c.getStyleClass().addAll("kpi-card", cls); return c;
    }

    // ── Barra de progresso ────────────────────────────────────────────────────

    private VBox buildProgressSection() {
        progressBar = new ProgressBar(0);
        progressBar.setMaxWidth(Double.MAX_VALUE);
        progressBar.setPrefHeight(14);

        progressLabel = new Label("0 de 0 itens concluídos");
        progressLabel.setStyle("-fx-font-size: 11.5px; -fx-text-fill: #5a7a9e;"
                + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");

        VBox section = new VBox(6, progressBar, progressLabel);
        section.setPadding(new Insets(8, 14, 8, 14));
        section.setStyle("-fx-background-color: white;"
                + " -fx-border-color: transparent transparent #dce8f5 transparent;"
                + " -fx-border-width: 0 0 1 0;");
        return section;
    }

    // ── Barra de ferramentas com toggle Lista/Kanban + filtros ─────────────────

    private HBox buildViewToolbar() {
        // Toggle: Lista / Kanban
        ToggleGroup viewGroup = new ToggleGroup();
        ToggleButton listBtn   = new ToggleButton("☰  Lista");
        ToggleButton kanbanBtn = new ToggleButton("⬛  Kanban");
        listBtn.setToggleGroup(viewGroup);   listBtn.setSelected(true);
        kanbanBtn.setToggleGroup(viewGroup);
        listBtn.getStyleClass().add("view-toggle-btn");
        kanbanBtn.getStyleClass().add("view-toggle-btn");
        HBox viewToggle = new HBox(2, listBtn, kanbanBtn);
        viewToggle.getStyleClass().add("view-toggle-bar");

        listBtn.setOnAction(e -> {
            if (!listBtn.isSelected()) { listBtn.setSelected(true); return; }
            isKanban = false; refreshContentArea();
        });
        kanbanBtn.setOnAction(e -> {
            if (!kanbanBtn.isSelected()) { kanbanBtn.setSelected(true); return; }
            isKanban = true; refreshContentArea();
        });

        // Separador
        Separator sep = new Separator(javafx.geometry.Orientation.VERTICAL);
        sep.setPadding(new Insets(0, 4, 0, 4));

        // Filtros de lista
        ToggleGroup filterGroup = new ToggleGroup();
        ToggleButton allBtn   = filterToggle("Todos",      filterGroup, Filter.ALL);
        ToggleButton pendBtn  = filterToggle("Pendentes",  filterGroup, Filter.PENDING);
        ToggleButton doneBtn  = filterToggle("Concluídos", filterGroup, Filter.DONE);
        allBtn.setSelected(true);
        HBox filterBar = new HBox(2, allBtn, pendBtn, doneBtn);
        filterBar.getStyleClass().add("view-toggle-bar");

        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);

        Button checkAllBtn   = new Button("✔  Marcar Todos");
        Button uncheckAllBtn = new Button("☐  Desmarcar Todos");
        Button clearDoneBtn  = new Button("  Limpar Concluídos");
        checkAllBtn.getStyleClass().add("secondary-button");
        uncheckAllBtn.getStyleClass().add("secondary-button");
        clearDoneBtn.getStyleClass().add("danger-button");
        checkAllBtn.setStyle("-fx-font-size: 11px;");
        uncheckAllBtn.setStyle("-fx-font-size: 11px;");
        clearDoneBtn.setStyle("-fx-font-size: 11px;");
        checkAllBtn.setOnAction(e -> markAll(true));
        uncheckAllBtn.setOnAction(e -> markAll(false));
        clearDoneBtn.setOnAction(e -> clearDoneItems());

        Button addBtn = new Button("＋  Novo Item");
        addBtn.getStyleClass().add("primary-button");
        addBtn.setStyle("-fx-font-size: 11px;");
        addBtn.setOnAction(e -> showAddItemDialog());

        Button printBtn = new Button("  Imprimir");
        printBtn.getStyleClass().add("secondary-button");
        printBtn.setStyle("-fx-font-size: 11px;");
        printBtn.setOnAction(e -> printChecklist());

        HBox bar = new HBox(8, viewToggle, sep, filterBar, spacer,
                checkAllBtn, uncheckAllBtn, clearDoneBtn, printBtn, addBtn);
        bar.setPadding(new Insets(8, 14, 8, 14));
        bar.setAlignment(Pos.CENTER_LEFT);
        bar.setStyle("-fx-background-color: #f2f7fc;"
                + " -fx-border-color: transparent transparent #dce8f5 transparent;"
                + " -fx-border-width: 0 0 1 0;");
        return bar;
    }

    private ToggleButton filterToggle(String label, ToggleGroup tg, Filter filter) {
        ToggleButton btn = new ToggleButton(label);
        btn.setToggleGroup(tg);
        btn.getStyleClass().add("view-toggle-btn");
        btn.setOnAction(e -> {
            if (!btn.isSelected()) { btn.setSelected(true); return; }
            currentFilter = filter;
            if (!isKanban) refreshContentArea();
        });
        return btn;
    }

    // ── Impressão do checklist ────────────────────────────────────────────────

    private void printChecklist() {
        // ── Diálogo de filtros ────────────────────────────────────────────
        ComboBox<String> dlgItemsFilter = new ComboBox<>();
        dlgItemsFilter.getItems().addAll("Todos os itens", "Apenas Pendentes", "Apenas Concluídos");
        dlgItemsFilter.setValue(switch (currentFilter) {
            case PENDING -> "Apenas Pendentes";
            case DONE    -> "Apenas Concluídos";
            default      -> "Todos os itens";
        });
        dlgItemsFilter.getStyleClass().add("input-control");
        dlgItemsFilter.setMaxWidth(Double.MAX_VALUE);

        ComboBox<String> dlgColFilter = new ComboBox<>();
        dlgColFilter.getItems().add("Todas as colunas");
        for (String[] c : KANBAN_COLS) dlgColFilter.getItems().add(c[1].replace("  ", " ").trim());
        dlgColFilter.setValue("Todas as colunas");
        dlgColFilter.getStyleClass().add("input-control");
        dlgColFilter.setMaxWidth(Double.MAX_VALUE);

        javafx.scene.layout.GridPane grid = new javafx.scene.layout.GridPane();
        grid.setHgap(10); grid.setVgap(8); grid.setPadding(new Insets(10, 0, 0, 0));
        grid.add(new Label("Mostrar:"), 0, 0); grid.add(dlgItemsFilter, 1, 0);
        grid.add(new Label("Coluna:"),  0, 1); grid.add(dlgColFilter,   1, 1);
        javafx.scene.layout.GridPane.setHgrow(dlgItemsFilter, Priority.ALWAYS);
        javafx.scene.layout.GridPane.setHgrow(dlgColFilter,   Priority.ALWAYS);

        Dialog<ButtonType> printDlg = new Dialog<>();
        printDlg.setTitle("Opções de Impressão");
        printDlg.setHeaderText("Checklist — " + idea.title());
        printDlg.getDialogPane().setContent(grid);
        printDlg.getDialogPane().setMinWidth(380);
        printDlg.getDialogPane().getButtonTypes().addAll(ButtonType.OK, ButtonType.CANCEL);
        ((Button) printDlg.getDialogPane().lookupButton(ButtonType.OK)).setText(" Gerar Checklist");
        ((Button) printDlg.getDialogPane().lookupButton(ButtonType.CANCEL)).setText("Cancelar");

        var dlgResult = printDlg.showAndWait();
        if (dlgResult.isEmpty() || dlgResult.get() != ButtonType.OK) return;

        // ── Determinar coluna selecionada ─────────────────────────────────
        String colSel = dlgColFilter.getValue();
        String colKey = "Todas as colunas".equals(colSel) ? null :
                java.util.Arrays.stream(KANBAN_COLS)
                        .filter(c -> c[1].replace("  ", " ").trim().equals(colSel))
                        .map(c -> c[0])
                        .findFirst().orElse(null);

        // ── Filtrar itens conforme seleção ────────────────────────────────
        String itemsSel = dlgItemsFilter.getValue();
        List<com.pessoal.agenda.model.IdeaChecklistItem> checkItems = items.stream()
                .filter(mi -> switch (itemsSel) {
                    case "Apenas Pendentes"  -> !mi.done;
                    case "Apenas Concluídos" ->  mi.done;
                    default                  -> true;
                })
                .filter(mi -> colKey == null || colKey.equals(mi.kanbanColumn))
                .map(mi -> new com.pessoal.agenda.model.IdeaChecklistItem(
                        mi.id, idea.id(), mi.text, mi.done, mi.position, mi.kanbanColumn))
                .toList();

        String html = com.pessoal.agenda.ui.util.PrintReportService
                .generateProjectChecklistReport(idea, checkItems);
        PrintPreviewWindow.open(html, "Checklist — " + idea.title());
    }

    // ── Diálogo de adição de item ─────────────────────────────────────────────

    private void showAddItemDialog() {
        TextField field = new TextField();
        field.getStyleClass().add("input-control");
        field.setPromptText("Descreva o item...");
        field.setPrefWidth(380);

        ComboBox<String> colCombo = new ComboBox<>();
        colCombo.getStyleClass().add("input-control");
        for (String[] c : KANBAN_COLS) colCombo.getItems().add(c[1].replace("  ", " ").trim());
        colCombo.setValue(KANBAN_COLS[0][1].replace("  ", " ").trim());

        VBox content = new VBox(8,
                new Label("Texto do item:"), field,
                new Label("Coluna inicial:"), colCombo);
        content.setPadding(new Insets(10));

        Dialog<ButtonType> dlg = new Dialog<>();
        dlg.setTitle("Novo Item");
        dlg.setHeaderText("Adicionar item ao checklist");
        dlg.getDialogPane().setContent(content);
        dlg.getDialogPane().getButtonTypes().addAll(ButtonType.OK, ButtonType.CANCEL);
        Platform.runLater(field::requestFocus);

        dlg.showAndWait().ifPresent(btn -> {
            if (btn != ButtonType.OK) return;
            String text = field.getText().trim();
            if (text.isBlank()) return;
            int colIdx = colCombo.getSelectionModel().getSelectedIndex();
            String colKey = KANBAN_COLS[Math.max(0, colIdx)][0];
            IdeaChecklistItem saved = repo.addItem(idea.id(), text);
            // Atualiza a coluna se não for backlog
            if (!"backlog".equals(colKey)) repo.updateColumn(saved.id(), colKey);
            MutableItem mi = new MutableItem(saved);
            mi.kanbanColumn = colKey;
            mi.done = "concluido".equals(colKey);
            items.add(mi);
            refreshAll();
            if (onChanged != null) onChanged.run();
        });
    }

    // ── Área de conteúdo principal ────────────────────────────────────────────

    private void refreshContentArea() {
        if (contentArea == null) return;
        contentArea.getChildren().setAll(isKanban ? buildKanbanView() : buildListView());
    }

    // ──────────────────────────────────────────────────────────────────────────
    // VISTA LISTA
    // ──────────────────────────────────────────────────────────────────────────

    private javafx.scene.Node buildListView() {
        itemsBox = new VBox(0);
        itemsBox.setFillWidth(true);

        ScrollPane sp = new ScrollPane(itemsBox);
        sp.setFitToWidth(true);
        sp.setFitToHeight(false);
        sp.setHbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
        sp.setVbarPolicy(ScrollPane.ScrollBarPolicy.AS_NEEDED);
        sp.getStyleClass().add("edge-to-edge");
        sp.setStyle("-fx-background-color: #f7fbff;");

        refreshItemsUI();
        return sp;
    }

    private void refreshItemsUI() {
        if (itemsBox == null) return;
        itemsBox.getChildren().clear();

        List<MutableItem> visible = items.stream()
                .filter(it -> switch (currentFilter) {
                    case ALL     -> true;
                    case PENDING -> !it.done;
                    case DONE    -> it.done;
                }).toList();

        if (visible.isEmpty()) {
            Label empty = new Label(switch (currentFilter) {
                case PENDING -> "Nenhum item pendente.  Todos os itens foram concluídos!";
                case DONE    -> "Nenhum item concluído ainda.";
                default      -> "Nenhum item no checklist.\nUse o botão ＋ Novo Item para adicionar.";
            });
            empty.setStyle("-fx-text-fill: #9eafc0; -fx-font-size: 12px; -fx-padding: 30 20 30 20;");
            empty.setWrapText(true); empty.setMaxWidth(Double.MAX_VALUE);
            empty.setAlignment(Pos.CENTER);
            itemsBox.getChildren().add(empty);
            return;
        }
        for (int i = 0; i < visible.size(); i++) itemsBox.getChildren().add(buildItemRow(visible.get(i), i));
    }

    private VBox buildItemRow(MutableItem item, int index) {
        CheckBox cb = new CheckBox();
        cb.setSelected(item.done);
        cb.setStyle("-fx-cursor: hand;");

        int globalIdx = items.indexOf(item) + 1;
        Label numLbl = new Label(String.format("%02d", globalIdx));
        numLbl.setStyle("-fx-font-family:'JetBrains Mono','Consolas',monospace;"
                + " -fx-font-size:10px; -fx-text-fill:#9eafc0; -fx-min-width:24px;");

        Label textLbl = new Label(item.text);
        textLbl.setWrapText(true); textLbl.setMaxWidth(Double.MAX_VALUE);
        HBox.setHgrow(textLbl, Priority.ALWAYS);
        applyDoneStyle(textLbl, item.done);

        // Badge de coluna
        String colLabel = columnLabel(item.kanbanColumn);
        String colColor = columnColor(item.kanbanColumn);
        Label colBadge = new Label(colLabel);
        colBadge.setStyle("-fx-background-color:" + colColor + "22; -fx-text-fill:" + colColor + ";"
                + " -fx-font-size:9px; -fx-font-weight:700; -fx-padding:2 6 2 6; -fx-background-radius:8;");

        TextField editField = new TextField(item.text);
        editField.getStyleClass().add("input-control");
        editField.setStyle("-fx-font-size:12px;");
        editField.setVisible(false); editField.setManaged(false);
        HBox.setHgrow(editField, Priority.ALWAYS);

        Button editBtn = new Button("✏");
        editBtn.setTooltip(new Tooltip("Editar (duplo clique)"));
        editBtn.setStyle("-fx-background-color:transparent; -fx-text-fill:#5a7a9e;"
                + " -fx-font-size:12px; -fx-cursor:hand; -fx-padding:2 6 2 6; -fx-background-radius:4;");
        editBtn.setOnAction(e -> enterEditMode(textLbl, editField, item, editBtn));

        Button delBtn = new Button("✕");
        delBtn.setTooltip(new Tooltip("Excluir item"));
        delBtn.setStyle("-fx-background-color:transparent; -fx-text-fill:#9eafc0;"
                + " -fx-font-size:12px; -fx-cursor:hand; -fx-padding:2 6 2 6; -fx-background-radius:4;");
        delBtn.setOnMouseEntered(e -> delBtn.setStyle(
                "-fx-background-color:#fdecea; -fx-text-fill:#c62828;"
                + " -fx-font-size:12px; -fx-cursor:hand; -fx-padding:2 6 2 6; -fx-background-radius:4;"));
        delBtn.setOnMouseExited(e -> delBtn.setStyle(
                "-fx-background-color:transparent; -fx-text-fill:#9eafc0;"
                + " -fx-font-size:12px; -fx-cursor:hand; -fx-padding:2 6 2 6; -fx-background-radius:4;"));
        delBtn.setOnAction(e -> deleteItem(item));

        cb.selectedProperty().addListener((obs, o, n) -> {
            item.done = n;
            item.kanbanColumn = n ? "concluido" : (item.kanbanColumn.equals("concluido") ? "backlog" : item.kanbanColumn);
            repo.updateDone(item.id, n);
            applyDoneStyle(textLbl, n);
            colBadge.setText(columnLabel(item.kanbanColumn));
            colBadge.setStyle("-fx-background-color:" + columnColor(item.kanbanColumn) + "22;"
                    + " -fx-text-fill:" + columnColor(item.kanbanColumn) + ";"
                    + " -fx-font-size:9px; -fx-font-weight:700;"
                    + " -fx-padding:2 6 2 6; -fx-background-radius:8;");
            refreshKpiAndProgress();
            if (onChanged != null) onChanged.run();
        });

        HBox contentRow = new HBox(8, numLbl, textLbl, editField, colBadge);
        contentRow.setAlignment(Pos.CENTER_LEFT);
        HBox.setHgrow(contentRow, Priority.ALWAYS);
        contentRow.setOnMouseClicked(e -> {
            if (e.getClickCount() == 2) enterEditMode(textLbl, editField, item, editBtn);
        });

        HBox row = new HBox(10, cb, contentRow, editBtn, delBtn);
        row.setAlignment(Pos.CENTER_LEFT);
        row.setPadding(new Insets(9, 12, 9, 14));

        String baseColor = index % 2 == 0 ? "#ffffff" : "#f7fbff";
        row.setStyle("-fx-background-color:" + baseColor
                + "; -fx-border-color:transparent transparent #e8f0fa transparent; -fx-border-width:0 0 1 0;");
        row.setOnMouseEntered(e -> row.setStyle("-fx-background-color:#eef6ff;"
                + " -fx-border-color:transparent transparent #e8f0fa transparent; -fx-border-width:0 0 1 0;"));
        row.setOnMouseExited(e  -> row.setStyle("-fx-background-color:" + baseColor
                + "; -fx-border-color:transparent transparent #e8f0fa transparent; -fx-border-width:0 0 1 0;"));

        Region stripe = new Region();
        stripe.setMinWidth(4); stripe.setMaxWidth(4);
        stripe.setStyle("-fx-background-color:" + columnColor(item.kanbanColumn)
                + "; -fx-background-radius:2 0 0 2;");

        HBox outerRow = new HBox(0, stripe, row);
        HBox.setHgrow(row, Priority.ALWAYS);
        outerRow.setAlignment(Pos.CENTER_LEFT);
        outerRow.setOnMouseClicked(e -> {
            if (e.getButton() == MouseButton.SECONDARY) {
                showItemContextMenu(item, textLbl, editField, editBtn, outerRow, e.getScreenX(), e.getScreenY());
                e.consume();
            } else if (e.getButton() == MouseButton.PRIMARY) {
                itemContextMenu.hide();
            }
        });

        return new VBox(outerRow);
    }

    // ──────────────────────────────────────────────────────────────────────────
    // VISTA KANBAN
    // ──────────────────────────────────────────────────────────────────────────

    private javafx.scene.Node buildKanbanView() {
        HBox board = new HBox(10);
        board.setPadding(new Insets(12, 14, 14, 14));
        board.setFillHeight(true);

        for (String[] colDef : KANBAN_COLS) {
            List<MutableItem> colItems = items.stream()
                    .filter(it -> colDef[0].equals(it.kanbanColumn))
                    .toList();
            board.getChildren().add(buildKanbanColumn(colDef, colItems));
        }

        ScrollPane sp = new ScrollPane(board);
        sp.setFitToHeight(true);
        sp.setFitToWidth(false);
        sp.setHbarPolicy(ScrollPane.ScrollBarPolicy.AS_NEEDED);
        sp.setVbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
        sp.getStyleClass().add("edge-to-edge");
        return sp;
    }

    private VBox buildKanbanColumn(String[] colDef, List<MutableItem> colItems) {
        String key = colDef[0], label = colDef[1].replace("  ", " ").trim(), color = colDef[2];

        Label headerLbl = new Label(label + "  (" + colItems.size() + ")");
        headerLbl.setStyle("-fx-font-size:12px; -fx-font-weight:700; -fx-text-fill:white;"
                + " -fx-padding:6 10 6 10; -fx-background-radius:6 6 0 0;"
                + " -fx-background-color:" + color + ";");
        headerLbl.setMaxWidth(Double.MAX_VALUE);

        // Botão + rápido
        Button addColBtn = new Button("+");
        addColBtn.setStyle("-fx-background-color:rgba(255,255,255,0.3); -fx-text-fill:white;"
                + " -fx-background-radius:4; -fx-font-weight:bold; -fx-font-size:14; -fx-cursor:hand;"
                + " -fx-padding:1 7 1 7;");
        addColBtn.setTooltip(new Tooltip("Adicionar item nesta coluna"));
        addColBtn.setOnAction(e -> showAddItemDialogForColumn(key));

        HBox colHeader = new HBox(headerLbl, addColBtn);
        colHeader.setAlignment(Pos.CENTER_LEFT);
        colHeader.setStyle("-fx-background-color:" + color + "; -fx-background-radius:6 6 0 0;");
        HBox.setHgrow(headerLbl, Priority.ALWAYS);

        VBox cards = new VBox(6);
        cards.setPadding(new Insets(8));
        if (colItems.isEmpty()) {
            Label empty = new Label("Sem itens");
            empty.setStyle("-fx-text-fill:#aabbcc; -fx-font-size:11px; -fx-padding:12;");
            cards.getChildren().add(empty);
        } else {
            for (MutableItem it : colItems) cards.getChildren().add(buildKanbanCard(it, color));
        }

        ScrollPane cardScroll = new ScrollPane(cards);
        cardScroll.setFitToWidth(true);
        cardScroll.setHbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
        cardScroll.setStyle("-fx-background-color:#f7fbff; -fx-border-color:transparent;");
        VBox.setVgrow(cardScroll, Priority.ALWAYS);

        VBox col = new VBox(0, colHeader, cardScroll);
        col.setPrefWidth(210); col.setMinWidth(190); col.setMaxWidth(240);
        col.setStyle("-fx-background-color:#f7fbff;"
                + " -fx-border-color:#b8cfe8; -fx-border-radius:6; -fx-background-radius:6;"
                + " -fx-effect:dropshadow(gaussian,rgba(3,24,62,0.07),8,0.2,0,2);");
        VBox.setVgrow(col, Priority.ALWAYS);
        return col;
    }

    private VBox buildKanbanCard(MutableItem item, String accentColor) {
        Label numLbl = new Label(String.format("#%02d", items.indexOf(item) + 1));
        numLbl.setStyle("-fx-font-family:'JetBrains Mono','Consolas',monospace;"
                + " -fx-font-size:9px; -fx-text-fill:#9eafc0;");

        Label textLbl = new Label(item.text);
        textLbl.setWrapText(true); textLbl.setMaxWidth(Double.MAX_VALUE);
        textLbl.setStyle((item.done
                ? "-fx-text-fill:#9eafc0; -fx-strikethrough:true;"
                : "-fx-text-fill:#0d1b2a;") + " -fx-font-size:12px; -fx-wrap-text:true;");

        HBox topRow = new HBox(4, numLbl);
        topRow.setAlignment(Pos.CENTER_LEFT);
        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);

        // Ações rápidas no card
        Button cbBtn = new Button(item.done ? "☑" : "☐");
        cbBtn.setStyle("-fx-background-color:transparent; -fx-cursor:hand;"
                + " -fx-font-size:14px; -fx-padding:0 2 0 2;");
        cbBtn.setTooltip(new Tooltip(item.done ? "Marcar como pendente" : "Marcar como concluído"));
        cbBtn.setOnAction(e -> {
            item.done = !item.done;
            item.kanbanColumn = item.done ? "concluido" : "backlog";
            repo.updateDone(item.id, item.done);
            refreshAll();
            if (onChanged != null) onChanged.run();
        });

        topRow.getChildren().addAll(spacer, cbBtn);

        VBox card = new VBox(4, topRow, textLbl);
        card.setStyle("-fx-background-color:white; -fx-background-radius:5;"
                + " -fx-border-color:" + accentColor + "; -fx-border-width:0 0 0 3;"
                + " -fx-border-radius:5; -fx-padding:8 10 8 10; -fx-cursor:hand;"
                + " -fx-effect:dropshadow(gaussian,rgba(0,0,0,0.06),4,0.2,0,1);");

        // Hover
        card.setOnMouseEntered(e -> card.setStyle(
                "-fx-background-color:#f0f7ff; -fx-background-radius:5;"
                + " -fx-border-color:" + accentColor + "; -fx-border-width:0 0 0 3;"
                + " -fx-border-radius:5; -fx-padding:8 10 8 10; -fx-cursor:hand;"
                + " -fx-effect:dropshadow(gaussian,rgba(0,0,0,0.12),6,0.3,0,2);"));
        card.setOnMouseExited(e -> card.setStyle(
                "-fx-background-color:white; -fx-background-radius:5;"
                + " -fx-border-color:" + accentColor + "; -fx-border-width:0 0 0 3;"
                + " -fx-border-radius:5; -fx-padding:8 10 8 10; -fx-cursor:hand;"
                + " -fx-effect:dropshadow(gaussian,rgba(0,0,0,0.06),4,0.2,0,1);"));

        // Tooltip com texto completo
        if (item.text.length() > 60) {
            Tooltip tp = new Tooltip(item.text);
            tp.setWrapText(true); tp.setMaxWidth(280);
            Tooltip.install(card, tp);
        }

        // Clique direito → context menu
        card.setOnMouseClicked(e -> {
            if (e.getButton() == MouseButton.SECONDARY) {
                showItemContextMenu(item, textLbl, null, null, card, e.getScreenX(), e.getScreenY());
                e.consume();
            } else if (e.getButton() == MouseButton.PRIMARY) {
                itemContextMenu.hide();
            }
        });

        return card;
    }

    private void showAddItemDialogForColumn(String colKey) {
        TextInputDialog dlg = new TextInputDialog();
        dlg.setTitle("Novo Item");
        dlg.setHeaderText("Adicionar item na coluna \u201c" + columnLabel(colKey) + "\u201d");
        dlg.setContentText("Texto:");
        dlg.showAndWait().ifPresent(text -> {
            if (text.isBlank()) return;
            IdeaChecklistItem saved = repo.addItem(idea.id(), text);
            if (!"backlog".equals(colKey)) repo.updateColumn(saved.id(), colKey);
            MutableItem mi = new MutableItem(saved);
            mi.kanbanColumn = colKey;
            mi.done = "concluido".equals(colKey);
            items.add(mi);
            refreshAll();
            if (onChanged != null) onChanged.run();
        });
    }

    // ── Modo de edição inline ─────────────────────────────────────────────────

    private void enterEditMode(Label textLbl, TextField editField, MutableItem item, Button editBtn) {
        if (editField == null) return; // kanban card — usa diálogo
        textLbl.setVisible(false); textLbl.setManaged(false);
        editField.setText(item.text);
        editField.setVisible(true); editField.setManaged(true);
        editField.requestFocus(); editField.selectAll();
        if (editBtn != null) editBtn.setText("");

        Runnable save = () -> {
            String newText = editField.getText().trim();
            if (!newText.isBlank() && !newText.equals(item.text)) {
                item.text = newText; repo.updateText(item.id, newText);
                if (onChanged != null) onChanged.run();
            }
            textLbl.setText(item.text);
            textLbl.setVisible(true); textLbl.setManaged(true);
            editField.setVisible(false); editField.setManaged(false);
            if (editBtn != null) editBtn.setText("✏");
        };
        Runnable cancel = () -> {
            textLbl.setVisible(true); textLbl.setManaged(true);
            editField.setVisible(false); editField.setManaged(false);
            if (editBtn != null) editBtn.setText("✏");
        };
        editField.setOnAction(e -> save.run());
        editField.setOnKeyPressed(e -> { if (e.getCode() == javafx.scene.input.KeyCode.ESCAPE) cancel.run(); });
        if (editBtn != null) editBtn.setOnAction(e -> {
            if ("".equals(editBtn.getText())) save.run();
            else enterEditMode(textLbl, editField, item, editBtn);
        });
    }

    // ── Context menu ──────────────────────────────────────────────────────────

    private void showItemContextMenu(MutableItem item, Label textLbl,
                                     TextField editField, Button editBtn,
                                     javafx.scene.Node anchor, double sx, double sy) {
        itemContextMenu.hide();
        itemContextMenu.getItems().clear();
        itemContextMenu.setAutoHide(true);

        MenuItem copyItem = new MenuItem("  Copiar Texto");
        copyItem.setOnAction(e -> copyToClipboard(item.text));

        MenuItem editItem = new MenuItem("✏  Editar");
        if (editField != null) {
            editItem.setOnAction(e -> enterEditMode(textLbl, editField, item, editBtn));
        } else {
            // No Kanban — usa TextInputDialog
            editItem.setOnAction(e -> {
                TextInputDialog dlg = new TextInputDialog(item.text);
                dlg.setTitle("Editar Item"); dlg.setHeaderText(null);
                dlg.setContentText("Texto:");
                dlg.showAndWait().ifPresent(t -> {
                    if (!t.isBlank() && !t.equals(item.text)) {
                        item.text = t; repo.updateText(item.id, t);
                        refreshAll();
                        if (onChanged != null) onChanged.run();
                    }
                });
            });
        }

        MenuItem toggleItem = item.done
                ? new MenuItem("☐  Marcar como Pendente")
                : new MenuItem("✔  Marcar como Concluído");
        toggleItem.setOnAction(e -> {
            item.done = !item.done;
            item.kanbanColumn = item.done ? "concluido"
                    : (item.kanbanColumn.equals("concluido") ? "backlog" : item.kanbanColumn);
            repo.updateDone(item.id, item.done);
            refreshAll();
            if (onChanged != null) onChanged.run();
        });

        // Submenu "Mover para..."
        Menu moveMenu = new Menu("  Mover para...");
        for (String[] c : KANBAN_COLS) {
            String cKey = c[0], cLabel = c[1].replace("  ", " ").trim();
            MenuItem mi = new MenuItem(cLabel);
            if (cKey.equals(item.kanbanColumn)) mi.setStyle("-fx-font-weight:bold; -fx-text-fill:#1565c0;");
            mi.setOnAction(e -> moveItemToColumn(item, cKey));
            moveMenu.getItems().add(mi);
        }

        SeparatorMenuItem sep = new SeparatorMenuItem();

        MenuItem deleteItem = new MenuItem("  Excluir Item");
        deleteItem.setStyle("-fx-text-fill:#c62828;");
        deleteItem.setOnAction(e -> deleteItem(item));

        itemContextMenu.getItems().addAll(copyItem, editItem, toggleItem, moveMenu, sep, deleteItem);
        itemContextMenu.show(anchor, sx, sy);
    }

    private void moveItemToColumn(MutableItem item, String colKey) {
        item.kanbanColumn = colKey;
        item.done = "concluido".equals(colKey);
        repo.updateColumn(item.id, colKey);
        refreshAll();
        if (onChanged != null) onChanged.run();
    }

    private void deleteItem(MutableItem item) {
        repo.deleteItem(item.id);
        items.remove(item);
        refreshAll();
        if (onChanged != null) onChanged.run();
    }

    // ── Ações em lote ─────────────────────────────────────────────────────────

    private void markAll(boolean done) {
        for (MutableItem it : items) {
            if (it.done != done) {
                it.done = done;
                it.kanbanColumn = done ? "concluido"
                        : (it.kanbanColumn.equals("concluido") ? "backlog" : it.kanbanColumn);
                repo.updateDone(it.id, done);
            }
        }
        refreshAll();
        if (onChanged != null) onChanged.run();
    }

    private void clearDoneItems() {
        long count = items.stream().filter(it -> it.done).count();
        if (count == 0) { new Alert(Alert.AlertType.INFORMATION, "Sem itens concluídos para remover.", ButtonType.OK).showAndWait(); return; }
        Alert confirm = new Alert(Alert.AlertType.CONFIRMATION);
        confirm.setTitle("Limpar Concluídos");
        confirm.setHeaderText("Remover itens concluídos?");
        confirm.setContentText(count + " item(ns) serão excluídos permanentemente.");
        confirm.showAndWait().ifPresent(btn -> {
            if (btn == ButtonType.OK) {
                List<MutableItem> done = items.stream().filter(it -> it.done).toList();
                done.forEach(it -> repo.deleteItem(it.id));
                items.removeAll(done);
                refreshAll();
                if (onChanged != null) onChanged.run();
            }
        });
    }

    // ── Refresh ───────────────────────────────────────────────────────────────

    private void refreshAll() {
        refreshKpiAndProgress();
        refreshContentArea();
    }

    private void refreshKpiAndProgress() {
        int total   = items.size();
        int done    = (int) items.stream().filter(it -> it.done).count();
        int pending = total - done;
        double pct  = total == 0 ? 0.0 : (double) done / total;

        if (kpiTotal   != null) kpiTotal.setText(String.valueOf(total));
        if (kpiDone    != null) kpiDone.setText(String.valueOf(done));
        if (kpiPending != null) kpiPending.setText(String.valueOf(pending));
        if (kpiPercent != null) kpiPercent.setText(Math.round(pct * 100) + "%");

        if (progressBar != null) {
            progressBar.setProgress(pct);
            String accent = pct == 1.0 ? "#1b5e20" : pct >= 0.7 ? "#2e7d32" : pct >= 0.4 ? "#f57f17" : "#c62828";
            progressBar.setStyle("-fx-accent:" + accent
                    + "; -fx-background-color:#d6e4f5; -fx-background-radius:7; -fx-border-radius:7;");
        }
        if (progressLabel != null) progressLabel.setText(
                done + " de " + total + " itens concluídos"
                + (total > 0 ? "  (" + Math.round(pct * 100) + "%)" : ""));
    }

    // ── Rodapé ────────────────────────────────────────────────────────────────

    private HBox buildFooter(Stage stage) {
        Label hint = new Label("  Duplo clique para editar  ·  Botão direito para mais opções  ·  ⬛ Kanban mostra colunas de progresso");
        hint.setStyle("-fx-font-size:11px; -fx-text-fill:#7a9abc;"
                + " -fx-font-family:'JetBrains Mono','Consolas',monospace;");
        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);

        Button printBtn = new Button("  Imprimir Checklist");
        printBtn.getStyleClass().add("secondary-button");
        printBtn.setOnAction(e -> printChecklist());

        Button closeBtn = new Button("✕  Fechar");
        closeBtn.getStyleClass().add("secondary-button");
        closeBtn.setOnAction(e -> stage.close());
        HBox footer = new HBox(12, hint, spacer, printBtn, closeBtn);
        footer.setPadding(new Insets(10, 18, 10, 18)); footer.setAlignment(Pos.CENTER_LEFT);
        footer.setStyle("-fx-background-color:#edf1f8; -fx-border-color:#b8cfe8; -fx-border-width:1 0 0 0;");
        return footer;
    }


    // ── Helpers de Kanban ─────────────────────────────────────────────────────

    private String columnLabel(String key) {
        for (String[] c : KANBAN_COLS) if (c[0].equals(key)) return c[1].replace("  ", " ").trim();
        return key;
    }
    private String columnColor(String key) {
        for (String[] c : KANBAN_COLS) if (c[0].equals(key)) return c[2];
        return "#546e7a";
    }

    // ── Helpers visuais ───────────────────────────────────────────────────────

    private void applyDoneStyle(Label lbl, boolean done) {
        lbl.setStyle(done
                ? "-fx-text-fill:#9eafc0; -fx-strikethrough:true;  -fx-font-size:12px;"
                : "-fx-text-fill:#0d1b2a; -fx-strikethrough:false; -fx-font-size:12px;");
    }

    private void copyToClipboard(String text) {
        ClipboardContent c = new ClipboardContent(); c.putString(text);
        Clipboard.getSystemClipboard().setContent(c);
    }

    // ── Fábrica estática ──────────────────────────────────────────────────────

    public static void open(ProjectIdea idea, Runnable onChanged) {
        IdeaChecklistRepository repo = AppContextHolder.get().ideaChecklistRepository();
        new ProjectChecklistWindow(idea, repo, onChanged).show();
    }
}

package com.pessoal.agenda.ui.view;

import com.pessoal.agenda.app.AppContextHolder;
import com.pessoal.agenda.model.Category;
import com.pessoal.agenda.model.CategoryDomain;
import com.pessoal.agenda.model.IdeaChecklistItem;
import com.pessoal.agenda.model.ProjectIdea;
import com.pessoal.agenda.repository.IdeaChecklistRepository;
import com.pessoal.agenda.repository.ProjectIdeaRepository;
import javafx.application.Platform;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.*;
import javafx.stage.Modality;
import javafx.stage.Stage;

import java.util.ArrayList;
import java.util.List;

/**
 * Janela de detalhe e edição de uma Ideia / Projeto Científico.
 *
 * A seção "Próximas Ações" suporta dois modos intercambiáveis:
 *   • Texto livre  — área de texto simples, sempre disponível
 *   • Checklist    — lista de itens com checkbox, progresso e persistência imediata
 */
public class ProjectIdeaDetailWindow {

    private static final java.util.Map<Long, Stage> openWindows = new java.util.HashMap<>();

    private final ProjectIdea idea;
    private final ProjectIdeaRepository repo;
    private final Runnable onSaved;
    private IdeaChecklistRepository checklistRepo;

    // ── campos de formulário ──────────────────────────────────────────────────
    private TextField titleField;
    private ComboBox<String> statusCombo;
    private ComboBox<String> categoryCombo;
    private ComboBox<String> priorityCombo;
    private ComboBox<String> typeCombo;
    private ComboBox<String> impactCombo;
    private Spinner<Integer> feasibilitySpinner;
    private Spinner<Integer> hoursSpinner;
    private DatePicker startDatePicker;
    private DatePicker targetDatePicker;
    private TextArea descriptionArea;
    private TextArea methodologyArea;
    private TextArea nextActionsArea;
    private TextField keywordsField;
    private TextArea referencesArea;

    // ── estado do checklist ───────────────────────────────────────────────────
    private String nextActionsMode = "text";
    private final List<ChecklistItemState> checklistItems = new ArrayList<>();
    private VBox checklistItemsBox;
    private Label checklistProgressLabel;
    private VBox checklistPane;

    /** Estado mutável de um item de checklist na UI. */
    private static class ChecklistItemState {
        long   dbId;   // 0 = ainda não persistido
        String text;
        boolean done;
        ChecklistItemState(long dbId, String text, boolean done) {
            this.dbId = dbId; this.text = text; this.done = done;
        }
    }

    public ProjectIdeaDetailWindow(ProjectIdea idea, ProjectIdeaRepository repo, Runnable onSaved) {
        this.idea    = idea;
        this.repo    = repo;
        this.onSaved = onSaved;
    }

    public void show() {
        // Previne abertura duplicada da mesma ideia
        if (openWindows.containsKey(idea.id())) {
            Stage existing = openWindows.get(idea.id());
            existing.toFront(); existing.requestFocus();
            return;
        }

        checklistRepo = AppContextHolder.get().ideaChecklistRepository();

        if (idea.id() > 0) {
            nextActionsMode = repo.getNextActionsMode(idea.id());
            if ("checklist".equals(nextActionsMode)) {
                for (IdeaChecklistItem it : checklistRepo.findByIdeaId(idea.id())) {
                    checklistItems.add(new ChecklistItemState(it.id(), it.text(), it.done()));
                }
            }
        }

        Stage stage = new Stage();
        stage.initModality(Modality.NONE);
        stage.setTitle("Ideia / Projeto — " + idea.title());
        stage.setMinWidth(780); stage.setMinHeight(680);
        openWindows.put(idea.id(), stage);
        stage.setOnHidden(e -> openWindows.remove(idea.id()));

        // ── Layout principal ───────────────────────────────────────────────────
        VBox root = new VBox(0);
        root.getStylesheets().add(
                getClass().getResource("/com/pessoal/agenda/app.css").toExternalForm());
        root.getStyleClass().add("app-root");
        root.getChildren().add(buildHeader());

        ScrollPane scroll = new ScrollPane(buildForm());
        scroll.setFitToWidth(true); scroll.setFitToHeight(true);
        VBox.setVgrow(scroll, Priority.ALWAYS);
        root.getChildren().add(scroll);
        root.getChildren().add(buildFooter(stage));

        stage.setScene(new Scene(root, 820, 740));
        stage.show();
    }

    // ── Cabeçalho da janela ──────────────────────────────────────────────────

    private HBox buildHeader() {
        Label title = new Label(idea.id() == 0 ? "Nova Ideia / Projeto" : "Ideia / Projeto");
        title.getStyleClass().add("page-title");
        Label sub = new Label(idea.typeLabel() + "  ·  " + idea.priorityLabel()
                + "  ·  " + idea.impactLabel());
        sub.getStyleClass().add("page-subtitle");
        VBox titles = new VBox(2, title, sub);
        HBox hdr = new HBox(titles);
        hdr.getStyleClass().add("header-bar");
        hdr.setPadding(new Insets(14, 20, 14, 20));
        hdr.setAlignment(Pos.CENTER_LEFT);
        return hdr;
    }

    // ── Formulário completo ──────────────────────────────────────────────────

    private VBox buildForm() {
        VBox form = new VBox(14);
        form.setPadding(new Insets(18));

        // ── Linha 1: Título ────────────────────────────────────────────────
        titleField = new TextField(nvl(idea.title(), ""));
        titleField.getStyleClass().add("input-control");
        titleField.setPromptText("Título da ideia ou projeto");
        titleField.setStyle("-fx-font-size: 14px; -fx-font-weight: bold;");
        form.getChildren().add(fieldRow("Título *", titleField));

        // ── Linha 2: Status / Prioridade / Tipo / Impacto ─────────────────
        statusCombo   = buildCombo(
                new String[]{"nova","em_validacao","prototipagem","em_execucao","pausada","concluida","abandonada"},
                new String[]{"Nova","Em Validação","Prototipagem","Em Execução","Pausada","Concluída","Abandonada"},
                nvl(idea.status(), "nova"));
        priorityCombo = buildCombo(
                new String[]{"CRITICA","ALTA","NORMAL","BAIXA"},
                new String[]{" Crítica"," Alta"," Normal"," Baixa"},
                nvl(idea.priority(), "NORMAL"));
        typeCombo     = buildCombo(
                new String[]{"GERAL","PESQUISA","ENGENHARIA","HIPOTESE","EXPERIMENTO","SOFTWARE","METODOLOGIA","INOVACAO"},
                new String[]{" Geral"," Pesquisa","⚙ Engenharia"," Hipótese"," Experimento"," Software"," Metodologia"," Inovação"},
                nvl(idea.ideaType(), "GERAL"));
        impactCombo   = buildCombo(
                new String[]{"BAIXO","MEDIO","ALTO","REVOLUCIONARIO"},
                new String[]{"▽ Baixo","◈ Médio","▲ Alto","⚡ Revolucionário"},
                nvl(idea.impactLevel(), "MEDIO"));

        HBox metaRow = new HBox(10,
                labeledControl("Status",     statusCombo),
                labeledControl("Prioridade", priorityCombo),
                labeledControl("Tipo",       typeCombo),
                labeledControl("Impacto",    impactCombo));
        metaRow.setFillHeight(true);
        HBox.setHgrow(statusCombo, Priority.ALWAYS); HBox.setHgrow(priorityCombo, Priority.ALWAYS);
        HBox.setHgrow(typeCombo,   Priority.ALWAYS); HBox.setHgrow(impactCombo,   Priority.ALWAYS);
        form.getChildren().add(metaRow);

        // ── Linha 3: Categoria / Viabilidade / Horas estimadas ────────────
        categoryCombo = new ComboBox<>();
        categoryCombo.getStyleClass().add("input-control");
        categoryCombo.setEditable(true);
        // Popula com as categorias de Ideias cadastradas nas Configurações
        List<String> ideaCatNames = AppContextHolder.get()
                .categoryService()
                .list(CategoryDomain.IDEA)
                .stream()
                .map(Category::name)
                .toList();
        if (ideaCatNames.isEmpty()) {
            categoryCombo.getItems().add("Geral");
        } else {
            categoryCombo.getItems().addAll(ideaCatNames);
        }
        categoryCombo.setValue(nvl(idea.category(), categoryCombo.getItems().get(0)));

        feasibilitySpinner = new Spinner<>(1, 5, Math.max(1, Math.min(5, idea.feasibility())));
        feasibilitySpinner.setEditable(true);
        feasibilitySpinner.getStyleClass().add("input-control");
        feasibilitySpinner.setPrefWidth(80);

        hoursSpinner = new Spinner<>(0, 10000, idea.estimatedHours());
        hoursSpinner.setEditable(true);
        hoursSpinner.getStyleClass().add("input-control");
        hoursSpinner.setPrefWidth(90);

        startDatePicker  = new DatePicker(idea.startDate());
        startDatePicker.getStyleClass().add("input-control");
        startDatePicker.setPromptText("dd/MM/yyyy");

        targetDatePicker = new DatePicker(idea.targetDate());
        targetDatePicker.getStyleClass().add("input-control");
        targetDatePicker.setPromptText("dd/MM/yyyy");

        HBox row3 = new HBox(10,
                labeledControl("Categoria",          categoryCombo),
                labeledControl("Viabilidade (1-5)",  feasibilitySpinner),
                labeledControl("Horas estimadas",    hoursSpinner),
                labeledControl("Início planejado",   startDatePicker),
                labeledControl("Prazo-alvo",         targetDatePicker));
        HBox.setHgrow(categoryCombo, Priority.ALWAYS);
        form.getChildren().add(row3);

        // ── Seção: Descrição / Hipótese / Abstract ─────────────────────────
        descriptionArea = buildTextArea(nvl(idea.description(), ""), 6,
                "Descreva a ideia, hipótese científica, problema a resolver ou objetivo do projeto.\n"
              + "Pode incluir contexto, motivação e estado-da-arte resumido.");
        form.getChildren().add(sectionCard(" Descrição / Hipótese / Abstract", descriptionArea));

        // ── Seção: Metodologia ─────────────────────────────────────────────
        methodologyArea = buildTextArea(nvl(idea.methodology(), ""), 4,
                "Ex: Método Científico, Design Thinking, Agile, Revisão Bibliográfica...");
        form.getChildren().add(sectionCard(" Metodologia", methodologyArea));

        // ── Próximas Ações (texto OU checklist) ──────────────────────────────
        form.getChildren().add(buildNextActionsSection());

        // ── Linha: Palavras-chave ──────────────────────────────────────────
        keywordsField = new TextField(nvl(idea.keywords(), ""));
        keywordsField.getStyleClass().add("input-control");
        keywordsField.setPromptText("Ex: machine learning, proteínas, otimização, PCR...");
        form.getChildren().add(fieldRow(" Palavras-chave (separadas por vírgula)", keywordsField));

        // ── Seção: Referências ─────────────────────────────────────────────
        referencesArea = buildTextArea(nvl(idea.referencesText(), ""), 4,
                "Referências bibliográficas, DOIs, URLs, artigos, livros, datasets...\n"
              + "Ex: Smith et al. (2023). Nature, doi:10.1038/...");
        form.getChildren().add(sectionCard(" Referências / Fontes", referencesArea));

        return form;
    }

    // ── Seção Próximas Ações (texto OU checklist) ─────────────────────────────

    private VBox buildNextActionsSection() {
        ToggleGroup modeGroup     = new ToggleGroup();
        ToggleButton textBtn      = new ToggleButton(" Texto");
        ToggleButton checklistBtn = new ToggleButton("☑  Checklist");
        textBtn.setToggleGroup(modeGroup);
        checklistBtn.setToggleGroup(modeGroup);
        textBtn.getStyleClass().add("view-toggle-btn");
        checklistBtn.getStyleClass().add("view-toggle-btn");

        if ("checklist".equals(nextActionsMode)) checklistBtn.setSelected(true);
        else                                     textBtn.setSelected(true);

        checklistProgressLabel = new Label();
        checklistProgressLabel.setStyle(
                "-fx-font-size: 11px; -fx-font-weight: 700; -fx-text-fill: #2e7d32;"
                + " -fx-background-color: #e8f5e9; -fx-padding: 3 10 3 10;"
                + " -fx-background-radius: 12;");
        updateChecklistProgress();
        checklistProgressLabel.setVisible("checklist".equals(nextActionsMode));

        Label sectionTitle = new Label("✅ Próximas Ações");
        sectionTitle.setStyle("-fx-font-size: 12.5px; -fx-font-weight: 700; -fx-text-fill: #03183e;");
        Region hSpacer = new Region(); HBox.setHgrow(hSpacer, Priority.ALWAYS);

        HBox headerRow = new HBox(6, sectionTitle, hSpacer,
                checklistProgressLabel, new HBox(2, textBtn, checklistBtn));
        headerRow.setAlignment(Pos.CENTER_LEFT);
        headerRow.setStyle("-fx-padding: 0 0 8 0;"
                + " -fx-border-color: transparent transparent #d6e4f5 transparent;"
                + " -fx-border-width: 0 0 1 0;");

        // ── modo texto ────────────────────────────────────────────────────
        nextActionsArea = buildTextArea(nvl(idea.nextActions(), ""), 4,
                "Liste as próximas ações (uma por linha):\n- Configurar ambiente\n- Revisar documentação");
        nextActionsArea.setVisible("text".equals(nextActionsMode));
        nextActionsArea.setManaged("text".equals(nextActionsMode));

        // ── modo checklist ────────────────────────────────────────────────
        checklistItemsBox = new VBox(3);
        checklistItemsBox.setPadding(new Insets(6));
        refreshChecklistItemsUI();

        ScrollPane itemsScroll = new ScrollPane(checklistItemsBox);
        itemsScroll.setFitToWidth(true);
        itemsScroll.setPrefHeight(200); itemsScroll.setMaxHeight(350);
        itemsScroll.setStyle("-fx-background-color: transparent;"
                + " -fx-border-color: #dce8f5; -fx-border-radius: 5; -fx-background-radius: 5;");

        TextField newItemField = new TextField();
        newItemField.setPromptText("Descreva a próxima ação e pressione Enter...");
        newItemField.getStyleClass().add("input-control");
        HBox.setHgrow(newItemField, Priority.ALWAYS);

        Button addItemBtn = new Button("＋  Adicionar");
        addItemBtn.getStyleClass().add("primary-button");
        addItemBtn.setStyle("-fx-font-size: 11px;");

        Runnable doAdd = () -> {
            String t = newItemField.getText().trim();
            if (t.isBlank()) return;
            newItemField.clear();
            ChecklistItemState s = new ChecklistItemState(0, t, false);
            if (idea.id() > 0) {
                IdeaChecklistItem saved = checklistRepo.addItem(idea.id(), t);
                s.dbId = saved.id();
            }
            checklistItems.add(s);
            refreshChecklistItemsUI();
            updateChecklistProgress();
            Platform.runLater(() -> itemsScroll.setVvalue(1.0));
        };
        newItemField.setOnAction(e -> doAdd.run());
        addItemBtn.setOnAction(e -> doAdd.run());

        HBox addRow = new HBox(6, newItemField, addItemBtn);
        addRow.setAlignment(Pos.CENTER_LEFT);
        addRow.setStyle("-fx-padding: 8 0 0 0; -fx-border-color: #d6e4f5; -fx-border-width: 1 0 0 0;");

        checklistPane = new VBox(6, itemsScroll, addRow);
        checklistPane.setVisible("checklist".equals(nextActionsMode));
        checklistPane.setManaged("checklist".equals(nextActionsMode));

        // ── toggle ────────────────────────────────────────────────────────
        textBtn.setOnAction(e -> {
            if (!textBtn.isSelected()) { textBtn.setSelected(true); return; }
            nextActionsMode = "text";
            nextActionsArea.setVisible(true);  nextActionsArea.setManaged(true);
            checklistPane.setVisible(false);   checklistPane.setManaged(false);
            checklistProgressLabel.setVisible(false);
        });
        checklistBtn.setOnAction(e -> {
            if (!checklistBtn.isSelected()) { checklistBtn.setSelected(true); return; }
            nextActionsMode = "checklist";
            nextActionsArea.setVisible(false); nextActionsArea.setManaged(false);
            checklistPane.setVisible(true);    checklistPane.setManaged(true);
            checklistProgressLabel.setVisible(true);
            updateChecklistProgress();
        });

        VBox sectionContent = new VBox(8, nextActionsArea, checklistPane);
        VBox card = new VBox(8, headerRow, sectionContent);
        card.getStyleClass().add("section-card");
        card.setPadding(new Insets(12));
        return card;
    }

    // ── Checklist UI helpers ──────────────────────────────────────────────────

    private void refreshChecklistItemsUI() {
        if (checklistItemsBox == null) return;
        checklistItemsBox.getChildren().clear();
        List<ChecklistItemState> snapshot = new ArrayList<>(checklistItems);

        if (snapshot.isEmpty()) {
            Label empty = new Label("Nenhuma ação adicionada. Use o campo abaixo para adicionar.");
            empty.setStyle("-fx-text-fill: #9eafc0; -fx-font-size: 11px; -fx-padding: 10 8 10 8;");
            checklistItemsBox.getChildren().add(empty);
            return;
        }

        for (int i = 0; i < snapshot.size(); i++) {
            final ChecklistItemState item = snapshot.get(i);

            CheckBox cb = new CheckBox();
            cb.setSelected(item.done);

            Label textLbl = new Label(item.text);
            textLbl.setWrapText(true);
            textLbl.setMaxWidth(Double.MAX_VALUE);
            HBox.setHgrow(textLbl, Priority.ALWAYS);
            applyDoneStyle(textLbl, item.done);

            cb.selectedProperty().addListener((obs, o, n) -> {
                item.done = n;
                if (idea.id() > 0 && item.dbId > 0) checklistRepo.updateDone(item.dbId, n);
                applyDoneStyle(textLbl, n);
                updateChecklistProgress();
            });

            Button delBtn = new Button("✕");
            delBtn.setStyle("-fx-background-color: transparent; -fx-text-fill: #b71c1c;"
                    + " -fx-font-size: 11px; -fx-cursor: hand; -fx-padding: 2 6 2 6;"
                    + " -fx-background-radius: 4;");
            delBtn.setOnAction(e -> {
                if (idea.id() > 0 && item.dbId > 0) checklistRepo.deleteItem(item.dbId);
                checklistItems.remove(item);
                refreshChecklistItemsUI();
                updateChecklistProgress();
            });

            HBox row = new HBox(8, cb, textLbl, delBtn);
            row.setAlignment(Pos.CENTER_LEFT);
            row.setPadding(new Insets(5, 8, 5, 10));
            row.setStyle("-fx-background-color: " + (i % 2 == 0 ? "#f8fafc" : "white")
                    + "; -fx-background-radius: 4;");
            checklistItemsBox.getChildren().add(row);
        }
    }

    private void applyDoneStyle(Label lbl, boolean done) {
        lbl.setStyle(done
                ? "-fx-text-fill: #9eafc0; -fx-strikethrough: true;  -fx-font-size: 12px;"
                : "-fx-text-fill: #0d1b2a; -fx-strikethrough: false; -fx-font-size: 12px;");
    }

    private void updateChecklistProgress() {
        if (checklistProgressLabel == null) return;
        int total = checklistItems.size();
        int done  = (int) checklistItems.stream().filter(s -> s.done).count();
        checklistProgressLabel.setText(
                total == 0 ? "sem itens" : done + " / " + total + " concluídas");
    }

    // ── Rodapé com ações ─────────────────────────────────────────────────────

    private HBox buildFooter(Stage stage) {
        Button saveBtn = new Button("  Salvar");
        saveBtn.getStyleClass().add("primary-button");
        saveBtn.setPrefWidth(120);
        saveBtn.setOnAction(e -> {
            if (saveIdea()) { stage.close(); if (onSaved != null) onSaved.run(); }
        });

        Button deleteBtn = new Button("  Excluir");
        deleteBtn.getStyleClass().add("danger-button");
        deleteBtn.setPrefWidth(100);
        deleteBtn.setVisible(idea.id() > 0);
        deleteBtn.setOnAction(e -> {
            Alert confirm = new Alert(Alert.AlertType.CONFIRMATION,
                    "Excluir permanentemente esta ideia/projeto?", ButtonType.YES, ButtonType.NO);
            confirm.setHeaderText("Confirmar exclusão");
            confirm.showAndWait().ifPresent(b -> {
                if (b == ButtonType.YES) {
                    checklistRepo.deleteByIdeaId(idea.id());
                    repo.deleteById(idea.id());
                    stage.close();
                    if (onSaved != null) onSaved.run();
                }
            });
        });

        Button cancelBtn = new Button("✕  Fechar");
        cancelBtn.getStyleClass().add("secondary-button");
        cancelBtn.setOnAction(e -> stage.close());

        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);
        HBox footer = new HBox(10, deleteBtn, spacer, cancelBtn, saveBtn);
        footer.setPadding(new Insets(10, 18, 10, 18));
        footer.setAlignment(Pos.CENTER_LEFT);
        footer.setStyle("-fx-background-color: #edf1f8;"
                + " -fx-border-color: #b8cfe8; -fx-border-width: 1 0 0 0;");
        return footer;
    }

    // ── Lógica de salvar ──────────────────────────────────────────────────────

    private boolean saveIdea() {
        if (titleField.getText().isBlank()) {
            new Alert(Alert.AlertType.WARNING, "O título é obrigatório.", ButtonType.OK)
                    .showAndWait();
            return false;
        }
        String status   = resolveKey(statusCombo);
        String priority = resolveKey(priorityCombo);
        String type     = resolveKey(typeCombo);
        String impact   = resolveKey(impactCombo);

        ProjectIdea updated = new ProjectIdea(
                idea.id(), titleField.getText().trim(),
                descriptionArea.getText().trim(),
                status,
                categoryCombo.getValue() != null ? categoryCombo.getValue() : "Geral",
                priority, type, impact,
                feasibilitySpinner.getValue(),
                hoursSpinner.getValue(),
                startDatePicker.getValue(),
                targetDatePicker.getValue(),
                methodologyArea.getText().trim(),
                nextActionsArea.getText().trim(),   // texto livre (preservado mesmo no modo checklist)
                keywordsField.getText().trim(),
                referencesArea.getText().trim());

        long savedId;
        if (idea.id() == 0) {
            savedId = repo.saveFullIdea(updated);
            // Nova ideia: persistir itens de checklist que estão em memória
            if ("checklist".equals(nextActionsMode) && savedId > 0) {
                for (ChecklistItemState s : checklistItems) {
                    IdeaChecklistItem persisted = checklistRepo.addItem(savedId, s.text);
                    s.dbId = persisted.id();
                    if (s.done) checklistRepo.updateDone(persisted.id(), true);
                }
            }
        } else {
            repo.update(updated);
            savedId = idea.id();
        }

        if (savedId > 0) repo.setNextActionsMode(savedId, nextActionsMode);
        return true;
    }

    // ── Builder helpers ───────────────────────────────────────────────────────

    private ComboBox<String> buildCombo(String[] keys, String[] labels, String selectedKey) {
        ComboBox<String> cb = new ComboBox<>();
        cb.getStyleClass().add("input-control");
        for (String l : labels) cb.getItems().add(l);
        // Encontra o index pelo key
        for (int i = 0; i < keys.length; i++) {
            if (keys[i].equalsIgnoreCase(selectedKey)) { cb.getSelectionModel().select(i); break; }
        }
        if (cb.getSelectionModel().isEmpty()) cb.getSelectionModel().select(0);
        // Armazena os keys como UserData
        cb.setUserData(keys);
        return cb;
    }

    private String resolveKey(ComboBox<String> cb) {
        String[] keys = (String[]) cb.getUserData();
        int idx = cb.getSelectionModel().getSelectedIndex();
        return (keys != null && idx >= 0 && idx < keys.length) ? keys[idx] : "NORMAL";
    }

    private VBox labeledControl(String label, javafx.scene.Node control) {
        Label lbl = new Label(label);
        lbl.getStyleClass().add("form-label");
        lbl.setStyle("-fx-font-size: 11px; -fx-text-fill: #5a7a9e; -fx-font-weight: 600;");
        VBox box = new VBox(3, lbl, control);
        HBox.setHgrow(box, Priority.ALWAYS);
        return box;
    }

    private HBox fieldRow(String label, javafx.scene.Node control) {
        Label lbl = new Label(label);
        lbl.setStyle("-fx-font-size: 11.5px; -fx-text-fill: #5a7a9e;"
                + " -fx-font-weight: 600; -fx-min-width: 120px;");
        HBox row = new HBox(10, lbl, control);
        row.setAlignment(Pos.CENTER_LEFT);
        HBox.setHgrow(control, Priority.ALWAYS);
        return row;
    }

    private VBox sectionCard(String title, javafx.scene.Node content) {
        Label hdr = new Label(title);
        hdr.getStyleClass().add("section-title");
        hdr.setStyle("-fx-font-size: 12.5px; -fx-font-weight: 700; -fx-text-fill: #03183e;"
                + " -fx-padding: 0 0 6 0;"
                + " -fx-border-color: transparent transparent #d6e4f5 transparent;"
                + " -fx-border-width: 0 0 1 0;");
        VBox card = new VBox(8, hdr, content);
        card.getStyleClass().add("section-card");
        card.setPadding(new Insets(12));
        return card;
    }

    private TextArea buildTextArea(String text, int rows, String prompt) {
        TextArea ta = new TextArea(text);
        ta.getStyleClass().add("input-control");
        ta.setPrefRowCount(rows);
        ta.setPromptText(prompt);
        ta.setWrapText(true);
        return ta;
    }

    private static String nvl(String s, String def) { return s != null ? s : def; }

    // ── Fábrica estática ──────────────────────────────────────────────────────

    /** Abre janela de nova ideia (id=0). */
    public static void showNew(ProjectIdeaRepository repo, String defaultCategory, Runnable onSaved) {
        ProjectIdea blank = new ProjectIdea(0, "", "", "nova", defaultCategory);
        new ProjectIdeaDetailWindow(blank, repo, onSaved).show();
    }
}

package com.pessoal.agenda.ui.view;

import com.pessoal.agenda.app.AppContextHolder;
import com.pessoal.agenda.model.Category;
import com.pessoal.agenda.model.CategoryDomain;
import com.pessoal.agenda.model.IdeaChecklistItem;
import com.pessoal.agenda.model.ProjectIdea;
import com.pessoal.agenda.repository.IdeaChecklistRepository;
import com.pessoal.agenda.repository.ProjectIdeaRepository;
import javafx.application.Platform;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.*;
import javafx.stage.Modality;
import javafx.stage.Stage;

import java.util.ArrayList;
import java.util.List;

/**
 * Janela de detalhe e edição de uma Ideia / Projeto Científico.
 *
 * A seção "Próximas Ações" suporta dois modos intercambiáveis:
 *   • Texto livre  — área de texto simples, sempre disponível
 *   • Checklist    — lista de itens com checkbox, progresso e persistência imediata
 */
public class ProjectIdeaDetailWindow {

    private static final java.util.Map<Long, Stage> openWindows = new java.util.HashMap<>();

    private final ProjectIdea idea;
    private final ProjectIdeaRepository repo;
    private final Runnable onSaved;
    private IdeaChecklistRepository checklistRepo;

    // ── campos de formulário ──────────────────────────────────────────────────
    private TextField titleField;
    private ComboBox<String> statusCombo;
    private ComboBox<String> categoryCombo;
    private ComboBox<String> priorityCombo;
    private ComboBox<String> typeCombo;
    private ComboBox<String> impactCombo;
    private Spinner<Integer> feasibilitySpinner;
    private Spinner<Integer> hoursSpinner;
    private DatePicker startDatePicker;
    private DatePicker targetDatePicker;
    private TextArea descriptionArea;
    private TextArea methodologyArea;
    private TextArea nextActionsArea;
    private TextField keywordsField;
    private TextArea referencesArea;

    // ── estado do checklist ───────────────────────────────────────────────────
    private String nextActionsMode = "text";
    private final List<ChecklistItemState> checklistItems = new ArrayList<>();
    private VBox checklistItemsBox;
    private Label checklistProgressLabel;
    private VBox checklistPane;

    /** Estado mutável de um item de checklist na UI. */
    private static class ChecklistItemState {
        long   dbId;   // 0 = ainda não persistido
        String text;
        boolean done;
        ChecklistItemState(long dbId, String text, boolean done) {
            this.dbId = dbId; this.text = text; this.done = done;
        }
    }

    public ProjectIdeaDetailWindow(ProjectIdea idea, ProjectIdeaRepository repo, Runnable onSaved) {
        this.idea    = idea;
        this.repo    = repo;
        this.onSaved = onSaved;
    }

    public void show() {
        // Previne abertura duplicada da mesma ideia
        if (openWindows.containsKey(idea.id())) {
            Stage existing = openWindows.get(idea.id());
            existing.toFront(); existing.requestFocus();
            return;
        }

        checklistRepo = AppContextHolder.get().ideaChecklistRepository();

        if (idea.id() > 0) {
            nextActionsMode = repo.getNextActionsMode(idea.id());
            if ("checklist".equals(nextActionsMode)) {
                for (IdeaChecklistItem it : checklistRepo.findByIdeaId(idea.id())) {
                    checklistItems.add(new ChecklistItemState(it.id(), it.text(), it.done()));
                }
            }
        }

        Stage stage = new Stage();
        stage.initModality(Modality.NONE);
        stage.setTitle("Ideia / Projeto — " + idea.title());
        stage.setMinWidth(780); stage.setMinHeight(680);
        openWindows.put(idea.id(), stage);
        stage.setOnHidden(e -> openWindows.remove(idea.id()));

        // ── Layout principal ───────────────────────────────────────────────────
        VBox root = new VBox(0);
        root.getStyleClass().add("app-root");
        root.getChildren().add(buildHeader());

        ScrollPane scroll = new ScrollPane(buildForm());
        scroll.setFitToWidth(true); scroll.setFitToHeight(true);
        VBox.setVgrow(scroll, Priority.ALWAYS);
        root.getChildren().add(scroll);
        root.getChildren().add(buildFooter(stage));

        Scene scene = new Scene(root, 820, 740);
        ThemeManager.getInstance().applyTo(scene);
        stage.setScene(scene);
        stage.show();
    }

    // ── Cabeçalho da janela ──────────────────────────────────────────────────

    private HBox buildHeader() {
        Label title = new Label(idea.id() == 0 ? "Nova Ideia / Projeto" : "Ideia / Projeto");
        title.getStyleClass().add("page-title");
        Label sub = new Label(idea.typeLabel() + "  ·  " + idea.priorityLabel()
                + "  ·  " + idea.impactLabel());
        sub.getStyleClass().add("page-subtitle");
        VBox titles = new VBox(2, title, sub);
        HBox hdr = new HBox(titles);
        hdr.getStyleClass().add("header-bar");
        hdr.setPadding(new Insets(14, 20, 14, 20));
        hdr.setAlignment(Pos.CENTER_LEFT);
        return hdr;
    }

    // ── Formulário completo ──────────────────────────────────────────────────

    private VBox buildForm() {
        VBox form = new VBox(14);
        form.setPadding(new Insets(18));

        // ── Linha 1: Título ────────────────────────────────────────────────
        titleField = new TextField(nvl(idea.title(), ""));
        titleField.getStyleClass().add("input-control");
        titleField.setPromptText("Título da ideia ou projeto");
        titleField.setStyle("-fx-font-size: 14px; -fx-font-weight: bold;");
        form.getChildren().add(fieldRow("Título *", titleField));

        // ── Linha 2: Status / Prioridade / Tipo / Impacto ─────────────────
        statusCombo   = buildCombo(
                new String[]{"nova","em_validacao","prototipagem","em_execucao","pausada","concluida","abandonada"},
                new String[]{"Nova","Em Validação","Prototipagem","Em Execução","Pausada","Concluída","Abandonada"},
                nvl(idea.status(), "nova"));
        priorityCombo = buildCombo(
                new String[]{"CRITICA","ALTA","NORMAL","BAIXA"},
                new String[]{" Crítica"," Alta"," Normal"," Baixa"},
                nvl(idea.priority(), "NORMAL"));
        typeCombo     = buildCombo(
                new String[]{"GERAL","PESQUISA","ENGENHARIA","HIPOTESE","EXPERIMENTO","SOFTWARE","METODOLOGIA","INOVACAO"},
                new String[]{" Geral"," Pesquisa","⚙ Engenharia"," Hipótese"," Experimento"," Software"," Metodologia"," Inovação"},
                nvl(idea.ideaType(), "GERAL"));
        impactCombo   = buildCombo(
                new String[]{"BAIXO","MEDIO","ALTO","REVOLUCIONARIO"},
                new String[]{"▽ Baixo","◈ Médio","▲ Alto","⚡ Revolucionário"},
                nvl(idea.impactLevel(), "MEDIO"));

        HBox metaRow = new HBox(10,
                labeledControl("Status",     statusCombo),
                labeledControl("Prioridade", priorityCombo),
                labeledControl("Tipo",       typeCombo),
                labeledControl("Impacto",    impactCombo));
        metaRow.setFillHeight(true);
        HBox.setHgrow(statusCombo, Priority.ALWAYS); HBox.setHgrow(priorityCombo, Priority.ALWAYS);
        HBox.setHgrow(typeCombo,   Priority.ALWAYS); HBox.setHgrow(impactCombo,   Priority.ALWAYS);
        form.getChildren().add(metaRow);

        // ── Linha 3: Categoria / Viabilidade / Horas estimadas ────────────
        categoryCombo = new ComboBox<>();
        categoryCombo.getStyleClass().add("input-control");
        categoryCombo.setEditable(true);
        // Popula com as categorias de Ideias cadastradas nas Configurações
        List<String> ideaCatNames = AppContextHolder.get()
                .categoryService()
                .list(CategoryDomain.IDEA)
                .stream()
                .map(Category::name)
                .toList();
        if (ideaCatNames.isEmpty()) {
            categoryCombo.getItems().add("Geral");
        } else {
            categoryCombo.getItems().addAll(ideaCatNames);
        }
        categoryCombo.setValue(nvl(idea.category(), categoryCombo.getItems().get(0)));

        feasibilitySpinner = new Spinner<>(1, 5, Math.max(1, Math.min(5, idea.feasibility())));
        feasibilitySpinner.setEditable(true);
        feasibilitySpinner.getStyleClass().add("input-control");
        feasibilitySpinner.setPrefWidth(80);

        hoursSpinner = new Spinner<>(0, 10000, idea.estimatedHours());
        hoursSpinner.setEditable(true);
        hoursSpinner.getStyleClass().add("input-control");
        hoursSpinner.setPrefWidth(90);

        startDatePicker  = new DatePicker(idea.startDate());
        startDatePicker.getStyleClass().add("input-control");
        startDatePicker.setPromptText("dd/MM/yyyy");

        targetDatePicker = new DatePicker(idea.targetDate());
        targetDatePicker.getStyleClass().add("input-control");
        targetDatePicker.setPromptText("dd/MM/yyyy");

        HBox row3 = new HBox(10,
                labeledControl("Categoria",          categoryCombo),
                labeledControl("Viabilidade (1-5)",  feasibilitySpinner),
                labeledControl("Horas estimadas",    hoursSpinner),
                labeledControl("Início planejado",   startDatePicker),
                labeledControl("Prazo-alvo",         targetDatePicker));
        HBox.setHgrow(categoryCombo, Priority.ALWAYS);
        form.getChildren().add(row3);

        // ── Seção: Descrição / Hipótese / Abstract ─────────────────────────
        descriptionArea = buildTextArea(nvl(idea.description(), ""), 6,
                "Descreva a ideia, hipótese científica, problema a resolver ou objetivo do projeto.\n"
              + "Pode incluir contexto, motivação e estado-da-arte resumido.");
        form.getChildren().add(sectionCard(" Descrição / Hipótese / Abstract", descriptionArea));

        // ── Seção: Metodologia ─────────────────────────────────────────────
        methodologyArea = buildTextArea(nvl(idea.methodology(), ""), 4,
                "Ex: Método Científico, Design Thinking, Agile, Revisão Bibliográfica...");
        form.getChildren().add(sectionCard(" Metodologia", methodologyArea));

        // ── Próximas Ações (texto OU checklist) ──────────────────────────────
        form.getChildren().add(buildNextActionsSection());

        // ── Linha: Palavras-chave ──────────────────────────────────────────
        keywordsField = new TextField(nvl(idea.keywords(), ""));
        keywordsField.getStyleClass().add("input-control");
        keywordsField.setPromptText("Ex: machine learning, proteínas, otimização, PCR...");
        form.getChildren().add(fieldRow(" Palavras-chave (separadas por vírgula)", keywordsField));

        // ── Seção: Referências ─────────────────────────────────────────────
        referencesArea = buildTextArea(nvl(idea.referencesText(), ""), 4,
                "Referências bibliográficas, DOIs, URLs, artigos, livros, datasets...\n"
              + "Ex: Smith et al. (2023). Nature, doi:10.1038/...");
        form.getChildren().add(sectionCard(" Referências / Fontes", referencesArea));

        return form;
    }

    // ── Seção Próximas Ações (texto OU checklist) ─────────────────────────────

    private VBox buildNextActionsSection() {
        ToggleGroup modeGroup     = new ToggleGroup();
        ToggleButton textBtn      = new ToggleButton(" Texto");
        ToggleButton checklistBtn = new ToggleButton("☑  Checklist");
        textBtn.setToggleGroup(modeGroup);
        checklistBtn.setToggleGroup(modeGroup);
        textBtn.getStyleClass().add("view-toggle-btn");
        checklistBtn.getStyleClass().add("view-toggle-btn");

        if ("checklist".equals(nextActionsMode)) checklistBtn.setSelected(true);
        else                                     textBtn.setSelected(true);

        checklistProgressLabel = new Label();
        checklistProgressLabel.setStyle(
                "-fx-font-size: 11px; -fx-font-weight: 700; -fx-text-fill: #2e7d32;"
                + " -fx-background-color: #e8f5e9; -fx-padding: 3 10 3 10;"
                + " -fx-background-radius: 12;");
        updateChecklistProgress();
        checklistProgressLabel.setVisible("checklist".equals(nextActionsMode));

        Label sectionTitle = new Label("✅ Próximas Ações");
        sectionTitle.setStyle("-fx-font-size: 12.5px; -fx-font-weight: 700; -fx-text-fill: #03183e;");
        Region hSpacer = new Region(); HBox.setHgrow(hSpacer, Priority.ALWAYS);

        HBox headerRow = new HBox(6, sectionTitle, hSpacer,
                checklistProgressLabel, new HBox(2, textBtn, checklistBtn));
        headerRow.setAlignment(Pos.CENTER_LEFT);
        headerRow.setStyle("-fx-padding: 0 0 8 0;"
                + " -fx-border-color: transparent transparent #d6e4f5 transparent;"
                + " -fx-border-width: 0 0 1 0;");

        // ── modo texto ────────────────────────────────────────────────────
        nextActionsArea = buildTextArea(nvl(idea.nextActions(), ""), 4,
                "Liste as próximas ações (uma por linha):\n- Configurar ambiente\n- Revisar documentação");
        nextActionsArea.setVisible("text".equals(nextActionsMode));
        nextActionsArea.setManaged("text".equals(nextActionsMode));

        // ── modo checklist ────────────────────────────────────────────────
        checklistItemsBox = new VBox(3);
        checklistItemsBox.setPadding(new Insets(6));
        refreshChecklistItemsUI();

        ScrollPane itemsScroll = new ScrollPane(checklistItemsBox);
        itemsScroll.setFitToWidth(true);
        itemsScroll.setPrefHeight(200); itemsScroll.setMaxHeight(350);
        itemsScroll.setStyle("-fx-background-color: transparent;"
                + " -fx-border-color: #dce8f5; -fx-border-radius: 5; -fx-background-radius: 5;");

        TextField newItemField = new TextField();
        newItemField.setPromptText("Descreva a próxima ação e pressione Enter...");
        newItemField.getStyleClass().add("input-control");
        HBox.setHgrow(newItemField, Priority.ALWAYS);

        Button addItemBtn = new Button("＋  Adicionar");
        addItemBtn.getStyleClass().add("primary-button");
        addItemBtn.setStyle("-fx-font-size: 11px;");

        Runnable doAdd = () -> {
            String t = newItemField.getText().trim();
            if (t.isBlank()) return;
            newItemField.clear();
            ChecklistItemState s = new ChecklistItemState(0, t, false);
            if (idea.id() > 0) {
                IdeaChecklistItem saved = checklistRepo.addItem(idea.id(), t);
                s.dbId = saved.id();
            }
            checklistItems.add(s);
            refreshChecklistItemsUI();
            updateChecklistProgress();
            Platform.runLater(() -> itemsScroll.setVvalue(1.0));
        };
        newItemField.setOnAction(e -> doAdd.run());
        addItemBtn.setOnAction(e -> doAdd.run());

        HBox addRow = new HBox(6, newItemField, addItemBtn);
        addRow.setAlignment(Pos.CENTER_LEFT);
        addRow.setStyle("-fx-padding: 8 0 0 0; -fx-border-color: #d6e4f5; -fx-border-width: 1 0 0 0;");

        checklistPane = new VBox(6, itemsScroll, addRow);
        checklistPane.setVisible("checklist".equals(nextActionsMode));
        checklistPane.setManaged("checklist".equals(nextActionsMode));

        // ── toggle ────────────────────────────────────────────────────────
        textBtn.setOnAction(e -> {
            if (!textBtn.isSelected()) { textBtn.setSelected(true); return; }
            nextActionsMode = "text";
            nextActionsArea.setVisible(true);  nextActionsArea.setManaged(true);
            checklistPane.setVisible(false);   checklistPane.setManaged(false);
            checklistProgressLabel.setVisible(false);
        });
        checklistBtn.setOnAction(e -> {
            if (!checklistBtn.isSelected()) { checklistBtn.setSelected(true); return; }
            nextActionsMode = "checklist";
            nextActionsArea.setVisible(false); nextActionsArea.setManaged(false);
            checklistPane.setVisible(true);    checklistPane.setManaged(true);
            checklistProgressLabel.setVisible(true);
            updateChecklistProgress();
        });

        VBox sectionContent = new VBox(8, nextActionsArea, checklistPane);
        VBox card = new VBox(8, headerRow, sectionContent);
        card.getStyleClass().add("section-card");
        card.setPadding(new Insets(12));
        return card;
    }

    // ── Checklist UI helpers ──────────────────────────────────────────────────

    private void refreshChecklistItemsUI() {
        if (checklistItemsBox == null) return;
        checklistItemsBox.getChildren().clear();
        List<ChecklistItemState> snapshot = new ArrayList<>(checklistItems);

        if (snapshot.isEmpty()) {
            Label empty = new Label("Nenhuma ação adicionada. Use o campo abaixo para adicionar.");
            empty.setStyle("-fx-text-fill: #9eafc0; -fx-font-size: 11px; -fx-padding: 10 8 10 8;");
            checklistItemsBox.getChildren().add(empty);
            return;
        }

        for (int i = 0; i < snapshot.size(); i++) {
            final ChecklistItemState item = snapshot.get(i);

            CheckBox cb = new CheckBox();
            cb.setSelected(item.done);

            Label textLbl = new Label(item.text);
            textLbl.setWrapText(true);
            textLbl.setMaxWidth(Double.MAX_VALUE);
            HBox.setHgrow(textLbl, Priority.ALWAYS);
            applyDoneStyle(textLbl, item.done);

            cb.selectedProperty().addListener((obs, o, n) -> {
                item.done = n;
                if (idea.id() > 0 && item.dbId > 0) checklistRepo.updateDone(item.dbId, n);
                applyDoneStyle(textLbl, n);
                updateChecklistProgress();
            });

            Button delBtn = new Button("✕");
            delBtn.setStyle("-fx-background-color: transparent; -fx-text-fill: #b71c1c;"
                    + " -fx-font-size: 11px; -fx-cursor: hand; -fx-padding: 2 6 2 6;"
                    + " -fx-background-radius: 4;");
            delBtn.setOnAction(e -> {
                if (idea.id() > 0 && item.dbId > 0) checklistRepo.deleteItem(item.dbId);
                checklistItems.remove(item);
                refreshChecklistItemsUI();
                updateChecklistProgress();
            });

            HBox row = new HBox(8, cb, textLbl, delBtn);
            row.setAlignment(Pos.CENTER_LEFT);
            row.setPadding(new Insets(5, 8, 5, 10));
            row.setStyle("-fx-background-color: " + (i % 2 == 0 ? "#f8fafc" : "white")
                    + "; -fx-background-radius: 4;");
            checklistItemsBox.getChildren().add(row);
        }
    }

    private void applyDoneStyle(Label lbl, boolean done) {
        lbl.setStyle(done
                ? "-fx-text-fill: #9eafc0; -fx-strikethrough: true;  -fx-font-size: 12px;"
                : "-fx-text-fill: #0d1b2a; -fx-strikethrough: false; -fx-font-size: 12px;");
    }

    private void updateChecklistProgress() {
        if (checklistProgressLabel == null) return;
        int total = checklistItems.size();
        int done  = (int) checklistItems.stream().filter(s -> s.done).count();
        checklistProgressLabel.setText(
                total == 0 ? "sem itens" : done + " / " + total + " concluídas");
    }

    // ── Rodapé com ações ─────────────────────────────────────────────────────

    private HBox buildFooter(Stage stage) {
        Button saveBtn = new Button("  Salvar");
        saveBtn.getStyleClass().add("primary-button");
        saveBtn.setPrefWidth(120);
        saveBtn.setOnAction(e -> {
            if (saveIdea()) { stage.close(); if (onSaved != null) onSaved.run(); }
        });

        Button deleteBtn = new Button("  Excluir");
        deleteBtn.getStyleClass().add("danger-button");
        deleteBtn.setPrefWidth(100);
        deleteBtn.setVisible(idea.id() > 0);
        deleteBtn.setOnAction(e -> {
            Alert confirm = new Alert(Alert.AlertType.CONFIRMATION,
                    "Excluir permanentemente esta ideia/projeto?", ButtonType.YES, ButtonType.NO);
            confirm.setHeaderText("Confirmar exclusão");
            confirm.showAndWait().ifPresent(b -> {
                if (b == ButtonType.YES) {
                    checklistRepo.deleteByIdeaId(idea.id());
                    repo.deleteById(idea.id());
                    stage.close();
                    if (onSaved != null) onSaved.run();
                }
            });
        });

        Button cancelBtn = new Button("✕  Fechar");
        cancelBtn.getStyleClass().add("secondary-button");
        cancelBtn.setOnAction(e -> stage.close());

        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);
        HBox footer = new HBox(10, deleteBtn, spacer, cancelBtn, saveBtn);
        footer.setPadding(new Insets(10, 18, 10, 18));
        footer.setAlignment(Pos.CENTER_LEFT);
        footer.setStyle("-fx-background-color: #edf1f8;"
                + " -fx-border-color: #b8cfe8; -fx-border-width: 1 0 0 0;");
        return footer;
    }

    // ── Lógica de salvar ──────────────────────────────────────────────────────

    private boolean saveIdea() {
        if (titleField.getText().isBlank()) {
            new Alert(Alert.AlertType.WARNING, "O título é obrigatório.", ButtonType.OK)
                    .showAndWait();
            return false;
        }
        String status   = resolveKey(statusCombo);
        String priority = resolveKey(priorityCombo);
        String type     = resolveKey(typeCombo);
        String impact   = resolveKey(impactCombo);

        ProjectIdea updated = new ProjectIdea(
                idea.id(), titleField.getText().trim(),
                descriptionArea.getText().trim(),
                status,
                categoryCombo.getValue() != null ? categoryCombo.getValue() : "Geral",
                priority, type, impact,
                feasibilitySpinner.getValue(),
                hoursSpinner.getValue(),
                startDatePicker.getValue(),
                targetDatePicker.getValue(),
                methodologyArea.getText().trim(),
                nextActionsArea.getText().trim(),   // texto livre (preservado mesmo no modo checklist)
                keywordsField.getText().trim(),
                referencesArea.getText().trim());

        long savedId;
        if (idea.id() == 0) {
            savedId = repo.saveFullIdea(updated);
            // Nova ideia: persistir itens de checklist que estão em memória
            if ("checklist".equals(nextActionsMode) && savedId > 0) {
                for (ChecklistItemState s : checklistItems) {
                    IdeaChecklistItem persisted = checklistRepo.addItem(savedId, s.text);
                    s.dbId = persisted.id();
                    if (s.done) checklistRepo.updateDone(persisted.id(), true);
                }
            }
        } else {
            repo.update(updated);
            savedId = idea.id();
        }

        if (savedId > 0) repo.setNextActionsMode(savedId, nextActionsMode);
        return true;
    }

    // ── Builder helpers ───────────────────────────────────────────────────────

    private ComboBox<String> buildCombo(String[] keys, String[] labels, String selectedKey) {
        ComboBox<String> cb = new ComboBox<>();
        cb.getStyleClass().add("input-control");
        for (String l : labels) cb.getItems().add(l);
        // Encontra o index pelo key
        for (int i = 0; i < keys.length; i++) {
            if (keys[i].equalsIgnoreCase(selectedKey)) { cb.getSelectionModel().select(i); break; }
        }
        if (cb.getSelectionModel().isEmpty()) cb.getSelectionModel().select(0);
        // Armazena os keys como UserData
        cb.setUserData(keys);
        return cb;
    }

    private String resolveKey(ComboBox<String> cb) {
        String[] keys = (String[]) cb.getUserData();
        int idx = cb.getSelectionModel().getSelectedIndex();
        return (keys != null && idx >= 0 && idx < keys.length) ? keys[idx] : "NORMAL";
    }

    private VBox labeledControl(String label, javafx.scene.Node control) {
        Label lbl = new Label(label);
        lbl.getStyleClass().add("form-label");
        lbl.setStyle("-fx-font-size: 11px; -fx-text-fill: #5a7a9e; -fx-font-weight: 600;");
        VBox box = new VBox(3, lbl, control);
        HBox.setHgrow(box, Priority.ALWAYS);
        return box;
    }

    private HBox fieldRow(String label, javafx.scene.Node control) {
        Label lbl = new Label(label);
        lbl.setStyle("-fx-font-size: 11.5px; -fx-text-fill: #5a7a9e;"
                + " -fx-font-weight: 600; -fx-min-width: 120px;");
        HBox row = new HBox(10, lbl, control);
        row.setAlignment(Pos.CENTER_LEFT);
        HBox.setHgrow(control, Priority.ALWAYS);
        return row;
    }

    private VBox sectionCard(String title, javafx.scene.Node content) {
        Label hdr = new Label(title);
        hdr.getStyleClass().add("section-title");
        hdr.setStyle("-fx-font-size: 12.5px; -fx-font-weight: 700; -fx-text-fill: #03183e;"
                + " -fx-padding: 0 0 6 0;"
                + " -fx-border-color: transparent transparent #d6e4f5 transparent;"
                + " -fx-border-width: 0 0 1 0;");
        VBox card = new VBox(8, hdr, content);
        card.getStyleClass().add("section-card");
        card.setPadding(new Insets(12));
        return card;
    }

    private TextArea buildTextArea(String text, int rows, String prompt) {
        TextArea ta = new TextArea(text);
        ta.getStyleClass().add("input-control");
        ta.setPrefRowCount(rows);
        ta.setPromptText(prompt);
        ta.setWrapText(true);
        return ta;
    }

    private static String nvl(String s, String def) { return s != null ? s : def; }

    // ── Fábrica estática ──────────────────────────────────────────────────────

    /** Abre janela de nova ideia (id=0). */
    public static void showNew(ProjectIdeaRepository repo, String defaultCategory, Runnable onSaved) {
        ProjectIdea blank = new ProjectIdea(0, "", "", "nova", defaultCategory);
        new ProjectIdeaDetailWindow(blank, repo, onSaved).show();
    }
}

package com.pessoal.agenda.ui.view;

import com.pessoal.agenda.model.*;
import com.pessoal.agenda.repository.ProtocolRepository;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.*;
import javafx.scene.paint.Color;
import javafx.stage.Modality;
import javafx.stage.Stage;

import java.time.format.DateTimeFormatter;
import java.util.List;
import java.util.Optional;

/**
 * Janela de execução de um Protocolo Operacional.
 *
 * Layout:
 *   TOP    — header-bar: nome, tipo, categoria, validade, progresso
 *   CENTER — SplitPane(execução atual com checkboxes | histórico de execuções)
 */
public class ProtocolExecutionWindow {

    private static final DateTimeFormatter DT_FMT =
            DateTimeFormatter.ofPattern("dd/MM/yyyy HH:mm");
    private static final DateTimeFormatter DATE_FMT =
            DateTimeFormatter.ofPattern("dd/MM/yyyy");

    /** Janelas abertas por ID de protocolo. */
    private static final java.util.Map<Long, Stage> openWindows =
            new java.util.HashMap<>();

    private final Protocol           protocol;
    private final ProtocolRepository repo;
    private final Runnable           onCloseCallback;

    private Stage stage;

    // ── Execução atual ──────────────────────────────────────────────────────
    private ProtocolExecution currentExecution;
    private Label             execHeaderLabel;
    private Label             execProgressLabel;
    private ProgressBar       execProgressBar;
    private VBox              stepsContainer;
    private TextArea          execNotesArea;
    private Label             noExecLabel;
    private VBox              activeExecPanel;
    private Button            startBtn;
    private Button            completeBtn;
    private Button            restartBtn;
    private Button            cancelExecBtn;

    // ── Histórico ──────────────────────────────────────────────────────────
    private final ObservableList<ProtocolExecution> historyItems =
            FXCollections.observableArrayList();
    private ListView<ProtocolExecution> historyList;
    private VBox                        historyDetailBox;

    public ProtocolExecutionWindow(Protocol protocol,
                                   ProtocolRepository repo,
                                   Runnable onCloseCallback) {
        this.protocol        = protocol;
        this.repo            = repo;
        this.onCloseCallback = onCloseCallback;
    }

    public void show() {
        Stage existing = openWindows.get(protocol.id());
        if (existing != null && existing.isShowing()) {
            existing.toFront(); existing.requestFocus(); return;
        }

        stage = new Stage();
        stage.initModality(Modality.APPLICATION_MODAL);
        stage.setTitle(protocol.executionType().icon() + "  " + protocol.name());
        stage.setMinWidth(920);
        stage.setMinHeight(580);

        VBox root = new VBox(0);
        root.getStyleClass().add("app-root");
        root.getChildren().addAll(buildHeader(), buildCenter());

        Scene scene = new Scene(root, 1020, 650);
        try {
            scene.getStylesheets().add(
                getClass().getResource("/com/pessoal/agenda/app.css").toExternalForm());
        } catch (Exception ignored) {}

        stage.setScene(scene);
        stage.setOnHidden(e -> {
            openWindows.remove(protocol.id());
            if (onCloseCallback != null) onCloseCallback.run();
        });

        openWindows.put(protocol.id(), stage);
        loadCurrentExecution();
        loadHistory();
        stage.show();
    }

    // ── Header (header-bar) ─────────────────────────────────────────────────

    private HBox buildHeader() {
        // Badge de tipo
        Label typeBadge = new Label("  " + protocol.executionType().icon()
                + "  " + protocol.executionType().label() + "  ");
        typeBadge.getStyleClass().addAll("study-badge", "badge-type");
        typeBadge.setStyle(typeBadge.getStyle()
                + "-fx-font-size: 11px; -fx-text-fill: #7ec8e3;"
                + " -fx-background-color: rgba(0,180,216,0.15);"
                + " -fx-border-color: rgba(0,180,216,0.4); -fx-border-radius: 10;");

        // Nome do protocolo
        Label nameLbl = new Label(protocol.name());
        nameLbl.getStyleClass().add("page-title");
        nameLbl.setWrapText(true);

        // Categoria
        Label catBadge = new Label("  " + (protocol.category() != null ? protocol.category() : "Geral") + "  ");
        catBadge.setStyle("-fx-font-size: 10.5px; -fx-text-fill: #a8d4e6;"
                + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");

        // Barra de progresso
        execProgressBar = new ProgressBar(0);
        execProgressBar.setPrefWidth(220);
        execProgressBar.setPrefHeight(10);
        execProgressBar.getStyleClass().add("study-progress-bar");

        execProgressLabel = new Label("—");
        execProgressLabel.setStyle("-fx-font-size: 11.5px; -fx-font-weight: 700;"
                + " -fx-text-fill: #7ec8e3;"
                + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");

        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);
        HBox topRow = new HBox(10, typeBadge, nameLbl, catBadge, spacer,
                execProgressBar, execProgressLabel);
        topRow.setAlignment(Pos.CENTER_LEFT);

        // Descrição / hint de tipo
        Label descLbl = new Label(
            protocol.description() != null && !protocol.description().isBlank()
                ? protocol.description() : protocol.executionType().description());
        descLbl.setStyle("-fx-text-fill: #a8d4e6; -fx-font-size: 11.5px;"
                + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");
        descLbl.setWrapText(true);

        // Badge de validade
        Label validityLbl = new Label();
        validityLbl.setWrapText(false);
        if (protocol.hasValidity()) {
            java.time.LocalDate nextDue = repo.nextDueDate(protocol.id(), protocol.validityDays());
            if (nextDue != null) {
                long days = java.time.temporal.ChronoUnit.DAYS.between(
                        java.time.LocalDate.now(), nextDue);
                if (days < 0) {
                    validityLbl.setText("⚠  Validade VENCIDA há " + (-days) + " dias"
                            + "  (ciclo: " + protocol.validityDays() + "d)");
                    validityLbl.setStyle("-fx-text-fill: #ff6b6b; -fx-font-weight: 700;"
                            + " -fx-font-size: 11px;"
                            + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");
                } else {
                    validityLbl.setText("  Válido por mais " + days + " dias"
                            + "  (expira: " + nextDue.format(DATE_FMT) + ")");
                    validityLbl.setStyle("-fx-text-fill: " + (days <= 7 ? "#ffa94d" : "#69db7c") + ";"
                            + " -fx-font-size: 11px;"
                            + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");
                }
            } else {
                validityLbl.setText("  Validade: " + protocol.validityDays() + " dias após conclusão");
                validityLbl.setStyle("-fx-text-fill: #a8d4e6; -fx-font-size: 11px;"
                        + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");
            }
        }

        VBox headerContent = new VBox(5, topRow, descLbl);
        if (protocol.hasValidity()) headerContent.getChildren().add(validityLbl);
        headerContent.setMaxWidth(Double.MAX_VALUE);
        HBox.setHgrow(headerContent, Priority.ALWAYS);

        HBox header = new HBox(headerContent);
        header.setPadding(new Insets(14, 18, 12, 18));
        header.getStyleClass().add("header-bar");
        return header;
    }

    // ── Center ──────────────────────────────────────────────────────────────

    private SplitPane buildCenter() {
        SplitPane sp = new SplitPane(buildExecutionPanel(), buildHistoryPanel());
        sp.setDividerPositions(0.60);
        VBox.setVgrow(sp, Priority.ALWAYS);
        return sp;
    }

    // ── Painel de Execução Atual ─────────────────────────────────────────────

    private VBox buildExecutionPanel() {
        execHeaderLabel = new Label("Nenhuma execução ativa");
        execHeaderLabel.setStyle("-fx-font-size: 13px; -fx-font-weight: 700;"
                + " -fx-text-fill: #03183e;"
                + " -fx-border-color: transparent transparent #d6e4f5 transparent;"
                + " -fx-border-width: 0 0 1 0; -fx-padding: 0 0 6 0;");
        execHeaderLabel.setMaxWidth(Double.MAX_VALUE);

        // Painel "sem execução"
        noExecLabel = new Label("Nenhuma execução em andamento.\nClique em 'Iniciar Execução' para começar.");
        noExecLabel.getStyleClass().add("study-dates-label");
        noExecLabel.setWrapText(true);
        noExecLabel.setTextAlignment(javafx.scene.text.TextAlignment.CENTER);

        startBtn = new Button("▶  Iniciar Execução");
        startBtn.getStyleClass().add("primary-button");
        startBtn.setOnAction(e -> startNewExecution());

        VBox noExecBox = new VBox(16, noExecLabel, startBtn);
        noExecBox.setAlignment(Pos.CENTER);
        noExecBox.setPadding(new Insets(40));

        // Passos da execução ativa
        stepsContainer = new VBox(5);
        stepsContainer.setPadding(new Insets(4, 0, 4, 0));

        ScrollPane stepsScroll = new ScrollPane(stepsContainer);
        stepsScroll.setFitToWidth(true);
        stepsScroll.getStyleClass().add("edge-to-edge");
        VBox.setVgrow(stepsScroll, Priority.ALWAYS);

        // Notas
        Label notesLbl = new Label("Observações da execução:");
        notesLbl.setStyle("-fx-font-size: 11px; -fx-text-fill: #5a7a9e; -fx-font-weight: 600;");
        execNotesArea = new TextArea();
        execNotesArea.getStyleClass().add("input-control");
        execNotesArea.setPromptText("Observações desta execução (opcional)...");
        execNotesArea.setPrefRowCount(2);
        execNotesArea.setWrapText(true);

        // Botões de conclusão
        completeBtn = new Button("✓  Concluir Execução");
        completeBtn.getStyleClass().add("primary-button");
        completeBtn.setOnAction(e -> completeExecution(false));

        restartBtn = new Button("↺  Concluir e Reiniciar");
        restartBtn.getStyleClass().add("secondary-button");
        restartBtn.setOnAction(e -> completeExecution(true));

        cancelExecBtn = new Button("✗  Cancelar Execução");
        cancelExecBtn.getStyleClass().add("danger-button");
        cancelExecBtn.setOnAction(e -> cancelCurrentExecution());

        HBox actionBar = new HBox(8, completeBtn, restartBtn, createSpacer(), cancelExecBtn);
        actionBar.setAlignment(Pos.CENTER_LEFT);
        actionBar.setPadding(new Insets(8, 0, 0, 0));
        actionBar.setStyle("-fx-border-color: #d6e4f5; -fx-border-width: 1 0 0 0;");

        activeExecPanel = new VBox(8, stepsScroll, notesLbl, execNotesArea, actionBar);
        activeExecPanel.setPadding(new Insets(8, 0, 0, 0));
        VBox.setVgrow(stepsScroll, Priority.ALWAYS);
        VBox.setVgrow(activeExecPanel, Priority.ALWAYS);

        VBox panel = new VBox(8, execHeaderLabel, noExecBox);
        panel.setPadding(new Insets(12));
        panel.getStyleClass().add("section-card");
        VBox.setVgrow(panel, Priority.ALWAYS);

        panel.setUserData(new Object[]{ noExecBox, activeExecPanel });
        return panel;
    }

    // ── Painel de Histórico ──────────────────────────────────────────────────

    private VBox buildHistoryPanel() {
        Label title = new Label(" Histórico de Execuções");
        title.setStyle("-fx-font-size: 13px; -fx-font-weight: 700; -fx-text-fill: #03183e;"
                + " -fx-border-color: transparent transparent #d6e4f5 transparent;"
                + " -fx-border-width: 0 0 1 0; -fx-padding: 0 0 6 0;");
        title.setMaxWidth(Double.MAX_VALUE);

        historyList = new ListView<>(historyItems);
        historyList.getStyleClass().add("clean-list");
        historyList.setCellFactory(lv -> new ListCell<>() {
            @Override protected void updateItem(ProtocolExecution e, boolean empty) {
                super.updateItem(e, empty);
                if (empty || e == null) { setText(null); setGraphic(null); return; }

                String icon  = e.isCompleted() ? "✓" : e.isCancelled() ? "✗" : "●";
                Color  color = e.isCompleted() ? Color.web("#27ae60")
                             : e.isCancelled() ? Color.web("#e74c3c") : Color.web("#e67e22");
                String iter  = e.executionType() == ProtocolExecutionType.EXPERIMENTO
                             ? "  Iter. " + e.iterationNumber() : "";
                String dt    = e.startedAt() != null ? e.startedAt().format(DT_FMT) : "?";
                String steps = e.totalSteps() > 0
                             ? "  " + e.checkedSteps() + "/" + e.totalSteps() + " passos" : "";

                Label iconLbl = new Label(icon);
                iconLbl.setTextFill(color);
                iconLbl.setStyle("-fx-font-weight: bold; -fx-font-size: 14px;");

                Label mainLbl = new Label(dt + iter + steps);
                mainLbl.getStyleClass().add("study-plan-detail");

                Label statusLbl = new Label("  " + e.status() + "  ");
                statusLbl.getStyleClass().addAll("study-badge",
                        "badge-status-" + e.status().toLowerCase());

                Region sp2 = new Region(); HBox.setHgrow(sp2, Priority.ALWAYS);
                HBox row = new HBox(8, iconLbl, mainLbl, sp2, statusLbl);
                row.setAlignment(Pos.CENTER_LEFT);
                setGraphic(row); setText(null);
            }
        });
        VBox.setVgrow(historyList, Priority.ALWAYS);

        // Painel de detalhes da execução selecionada
        historyDetailBox = new VBox(6);
        historyDetailBox.setStyle("-fx-background-color: #f8fafc;"
                + " -fx-background-radius: 5; -fx-border-color: #dce8f5;"
                + " -fx-border-radius: 5; -fx-padding: 8;");
        historyDetailBox.setMinHeight(80);

        Label detailHdr = new Label("Detalhes da Execução");
        detailHdr.setStyle("-fx-font-size: 10.5px; -fx-text-fill: #5a7a9e; -fx-font-weight: 700;");
        historyDetailBox.getChildren().add(
                new Label("Selecione uma execução para ver detalhes.") {{
                    getStyleClass().add("study-dates-label"); }});

        historyList.getSelectionModel().selectedItemProperty().addListener(
            (obs, old, sel) -> showHistoryDetail(sel));

        VBox panel = new VBox(8, title, historyList, historyDetailBox);
        panel.setPadding(new Insets(12));
        panel.getStyleClass().add("section-card");
        VBox.setVgrow(panel, Priority.ALWAYS);
        return panel;
    }

    // ── Lógica de Execução ───────────────────────────────────────────────────

    private void loadCurrentExecution() {
        currentExecution = repo.findActiveExecution(protocol.id()).orElse(null);
        refreshExecutionPanel();
    }

    private void loadHistory() {
        historyItems.setAll(repo.findExecutions(protocol.id(), null));
    }

    @SuppressWarnings("unchecked")
    private void refreshExecutionPanel() {
        SplitPane sp = (SplitPane) ((VBox) stage.getScene().getRoot())
                .getChildren().stream()
                .filter(n -> n instanceof SplitPane)
                .findFirst().orElse(null);
        if (sp == null) return;

        VBox execPanel = (VBox) sp.getItems().get(0);
        Object[] refs  = (Object[]) execPanel.getUserData();
        if (refs == null) return;

        VBox noExecBox   = (VBox) refs[0];
        VBox activePanel = (VBox) refs[1];

        if (currentExecution == null) {
            execHeaderLabel.setText("Nenhuma execução ativa");
            execProgressBar.setProgress(0);
            execProgressLabel.setText("—");

            boolean unicoJaUsado = protocol.executionType() == ProtocolExecutionType.UNICO
                    && !repo.findExecutions(protocol.id(), "CONCLUIDA").isEmpty();
            if (unicoJaUsado) {
                noExecLabel.setText("Este protocolo é de uso único e já foi executado.\n"
                        + "Consulte o histórico para ver o registro completo.");
                startBtn.setVisible(false); startBtn.setManaged(false);
            } else {
                noExecLabel.setText("Nenhuma execução em andamento.\nClique em 'Iniciar Execução' para começar.");
                startBtn.setVisible(true); startBtn.setManaged(true);
            }

            execPanel.getChildren().remove(activePanel);
            if (!execPanel.getChildren().contains(noExecBox)) execPanel.getChildren().add(noExecBox);
        } else {
            int iter = currentExecution.iterationNumber();
            String iterLabel = protocol.executionType() == ProtocolExecutionType.EXPERIMENTO
                    ? "  —  Iteração " + iter : "";
            execHeaderLabel.setText("Em execução" + iterLabel
                    + "  ·  Iniciada: "
                    + (currentExecution.startedAt() != null
                       ? currentExecution.startedAt().format(DT_FMT) : "?"));

            double prog = currentExecution.progressPercent() / 100.0;
            execProgressBar.setProgress(prog);
            execProgressLabel.setText(currentExecution.checkedSteps()
                    + "/" + currentExecution.totalSteps() + " passos");

            execPanel.getChildren().remove(noExecBox);
            if (!execPanel.getChildren().contains(activePanel)) execPanel.getChildren().add(activePanel);

            refreshSteps();

            boolean supportsRestart = protocol.executionType().supportsRestart();
            restartBtn.setVisible(supportsRestart); restartBtn.setManaged(supportsRestart);

            if (protocol.executionType() == ProtocolExecutionType.EXPERIMENTO) {
                restartBtn.setText("↺  Concluir Iter. " + iter + " → Próxima");
                completeBtn.setText("✓  Encerrar Experimento");
            } else if (supportsRestart) {
                restartBtn.setText("↺  Concluir e Reiniciar");
                completeBtn.setText("✓  Concluir sem Reiniciar");
            } else if (protocol.executionType() == ProtocolExecutionType.UNICO) {
                completeBtn.setText("✓  Concluir (uso único)");
            } else {
                completeBtn.setText("✓  Concluir Execução");
            }
        }
    }

    private void refreshSteps() {
        stepsContainer.getChildren().clear();
        if (currentExecution == null) return;

        List<ProtocolExecutionStep> steps = repo.findExecutionSteps(currentExecution.id());

        for (ProtocolExecutionStep s : steps) {
            boolean done = s.checked();

            CheckBox cb = new CheckBox();
            cb.setSelected(done);
            cb.setDisable(done);

            Label numLbl = new Label(s.stepOrder() + ".");
            numLbl.setStyle("-fx-font-weight: 700; -fx-font-size: 12px; -fx-text-fill: #5a7a9e;"
                    + " -fx-min-width: 28px;");

            Label stepLbl = new Label(s.stepText());
            stepLbl.getStyleClass().add(s.critical() ? "study-plan-title" : "study-plan-detail");
            stepLbl.setWrapText(true);
            HBox.setHgrow(stepLbl, Priority.ALWAYS);
            if (done) stepLbl.setStyle("-fx-opacity: 0.5; -fx-strikethrough: true;");

            Label critLbl = new Label();
            if (s.critical()) {
                critLbl.setText("⚠ crítico");
                critLbl.setStyle("-fx-font-size: 9.5px; -fx-font-weight: 700;"
                        + " -fx-text-fill: #b71c1c; -fx-background-color: #fde8e8;"
                        + " -fx-background-radius: 8; -fx-padding: 1 6 1 6;");
            }

            Label timeStampLbl = new Label(s.checkedAt() != null ? s.checkedAt().format(DT_FMT) : "");
            timeStampLbl.setStyle("-fx-font-size: 10px; -fx-text-fill: #5a7a9e;"
                    + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");

            Button undoBtn = new Button("↩");
            undoBtn.getStyleClass().add("secondary-button");
            undoBtn.setStyle("-fx-font-size: 11px; -fx-padding: 2 8 2 8;");
            undoBtn.setTooltip(new Tooltip("Desmarcar este passo"));
            undoBtn.setVisible(done); undoBtn.setManaged(done);
            undoBtn.setOnAction(e -> { repo.uncheckStep(s.id()); reloadExecution(); });

            cb.setOnAction(e -> {
                if (cb.isSelected()) { repo.checkStep(s.id(), null); reloadExecution(); }
            });

            HBox row = new HBox(8, cb, numLbl, stepLbl, critLbl,
                    new Region() {{ HBox.setHgrow(this, Priority.ALWAYS); }},
                    timeStampLbl, undoBtn);
            row.setAlignment(Pos.CENTER_LEFT);
            row.setPadding(new Insets(6, 10, 6, 10));
            row.setStyle("-fx-background-color: " + (done ? "#f8fffe" : "white") + ";"
                    + " -fx-background-radius: 5;"
                    + " -fx-border-color: " + (done ? "#b2dfdb" : "#e8eef4") + ";"
                    + " -fx-border-radius: 5; -fx-border-width: 1;");
            stepsContainer.getChildren().add(row);
        }
    }

    private void reloadExecution() {
        currentExecution = repo.findActiveExecution(protocol.id()).orElse(null);
        refreshExecutionPanel();
        loadHistory();
    }

    private void startNewExecution() {
        repo.startExecution(protocol.id()); reloadExecution();
    }

    private void completeExecution(boolean andRestart) {
        if (currentExecution == null) return;
        String notes = execNotesArea.getText();

        List<ProtocolExecutionStep> steps = repo.findExecutionSteps(currentExecution.id());
        long criticalPending = steps.stream().filter(s -> s.critical() && !s.checked()).count();
        if (criticalPending > 0) {
            Alert warn = new Alert(Alert.AlertType.CONFIRMATION);
            warn.setTitle("Passos Críticos Pendentes");
            warn.setHeaderText(criticalPending + " passo(s) CRÍTICO(S) ainda não foram marcados.");
            warn.setContentText("Deseja concluir mesmo assim?");
            Optional<ButtonType> r = warn.showAndWait();
            if (r.isEmpty() || r.get() != ButtonType.OK) return;
        }

        repo.completeExecution(currentExecution.id(), notes);
        execNotesArea.clear();

        if (andRestart) {
            repo.startExecution(protocol.id());
        } else {
            currentExecution = null;
        }
        reloadExecution();
    }

    private void cancelCurrentExecution() {
        if (currentExecution == null) return;
        Alert confirm = new Alert(Alert.AlertType.CONFIRMATION);
        confirm.setTitle("Cancelar Execução");
        confirm.setHeaderText("Cancelar a execução em andamento?");
        confirm.setContentText(
                "O progresso será perdido. A execução ficará registrada como Cancelada no histórico.");
        confirm.showAndWait().filter(b -> b == ButtonType.OK).ifPresent(b -> {
            repo.cancelExecution(currentExecution.id());
            currentExecution = null;
            reloadExecution();
        });
    }

    private void showHistoryDetail(ProtocolExecution exec) {
        historyDetailBox.getChildren().clear();
        if (exec == null) {
            historyDetailBox.getChildren().add(new Label("Selecione uma execução para ver detalhes.") {{
                getStyleClass().add("study-dates-label");
            }});
            return;
        }

        // Status badge
        Label statusBadge = new Label("  " + exec.status() + "  ");
        statusBadge.getStyleClass().addAll("study-badge",
                "badge-status-" + exec.status().toLowerCase());

        // Métricas
        HBox statusRow = new HBox(8, statusBadge);
        if (exec.executionType() == ProtocolExecutionType.EXPERIMENTO)
            statusRow.getChildren().add(new Label("Iteração " + exec.iterationNumber() + "  ") {{
                setStyle("-fx-font-size: 11px; -fx-text-fill: #5a7a9e;"
                        + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");
            }});
        statusRow.setAlignment(Pos.CENTER_LEFT);

        historyDetailBox.getChildren().add(statusRow);

        // Detalhes de tempo
        addDetailRow(historyDetailBox, "Início",
                exec.startedAt() != null ? exec.startedAt().format(DT_FMT) : "—");
        addDetailRow(historyDetailBox, "Conclusão",
                exec.completedAt() != null ? exec.completedAt().format(DT_FMT) : "—");

        // Duração
        if (exec.startedAt() != null && exec.completedAt() != null) {
            long mins = java.time.Duration.between(exec.startedAt(), exec.completedAt()).toMinutes();
            addDetailRow(historyDetailBox, "Duração",
                    mins < 60 ? mins + " min"
                              : (mins / 60) + "h " + (mins % 60) + "min");
        }

        addDetailRow(historyDetailBox, "Progresso",
                exec.checkedSteps() + " / " + exec.totalSteps() + " passos concluídos");

        if (exec.notes() != null && !exec.notes().isBlank()) {
            Label notesLbl = new Label("Obs: " + exec.notes());
            notesLbl.setStyle("-fx-font-size: 11px; -fx-text-fill: #1e3a5f; -fx-wrap-text: true;"
                    + " -fx-background-color: #f0f5fc; -fx-background-radius: 4; -fx-padding: 4 6 4 6;");
            notesLbl.setWrapText(true);
            historyDetailBox.getChildren().add(notesLbl);
        }
    }

    private static void addDetailRow(VBox parent, String key, String value) {
        Label lbl = new Label(key + ":  " + value);
        lbl.setStyle("-fx-font-size: 11px; -fx-text-fill: #1e3a5f;"
                + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");
        parent.getChildren().add(lbl);
    }

    // ── Spacer helper ────────────────────────────────────────────────────────

    private static Region createSpacer() {
        Region r = new Region();
        HBox.setHgrow(r, Priority.ALWAYS);
        return r;
    }
}

package com.pessoal.agenda.ui.view;

import com.pessoal.agenda.model.*;
import com.pessoal.agenda.repository.ProtocolRepository;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.*;
import javafx.scene.paint.Color;
import javafx.stage.Modality;
import javafx.stage.Stage;

import java.time.format.DateTimeFormatter;
import java.util.List;
import java.util.Optional;

/**
 * Janela de execução de um Protocolo Operacional.
 *
 * Layout:
 *   TOP    — header-bar: nome, tipo, categoria, validade, progresso
 *   CENTER — SplitPane(execução atual com checkboxes | histórico de execuções)
 */
public class ProtocolExecutionWindow {

    private static final DateTimeFormatter DT_FMT =
            DateTimeFormatter.ofPattern("dd/MM/yyyy HH:mm");
    private static final DateTimeFormatter DATE_FMT =
            DateTimeFormatter.ofPattern("dd/MM/yyyy");

    /** Janelas abertas por ID de protocolo. */
    private static final java.util.Map<Long, Stage> openWindows =
            new java.util.HashMap<>();

    private final Protocol           protocol;
    private final ProtocolRepository repo;
    private final Runnable           onCloseCallback;

    private Stage stage;

    // ── Execução atual ──────────────────────────────────────────────────────
    private ProtocolExecution currentExecution;
    private Label             execHeaderLabel;
    private Label             execProgressLabel;
    private ProgressBar       execProgressBar;
    private VBox              stepsContainer;
    private TextArea          execNotesArea;
    private Label             noExecLabel;
    private VBox              activeExecPanel;
    private Button            startBtn;
    private Button            completeBtn;
    private Button            restartBtn;
    private Button            cancelExecBtn;

    // ── Histórico ──────────────────────────────────────────────────────────
    private final ObservableList<ProtocolExecution> historyItems =
            FXCollections.observableArrayList();
    private ListView<ProtocolExecution> historyList;
    private VBox                        historyDetailBox;

    public ProtocolExecutionWindow(Protocol protocol,
                                   ProtocolRepository repo,
                                   Runnable onCloseCallback) {
        this.protocol        = protocol;
        this.repo            = repo;
        this.onCloseCallback = onCloseCallback;
    }

    public void show() {
        Stage existing = openWindows.get(protocol.id());
        if (existing != null && existing.isShowing()) {
            existing.toFront(); existing.requestFocus(); return;
        }

        stage = new Stage();
        stage.initModality(Modality.APPLICATION_MODAL);
        stage.setTitle(protocol.executionType().icon() + "  " + protocol.name());
        stage.setMinWidth(920);
        stage.setMinHeight(580);

        VBox root = new VBox(0);
        root.getStyleClass().add("app-root");
        root.getChildren().addAll(buildHeader(), buildCenter());

        Scene scene = new Scene(root, 1020, 650);
        ThemeManager.getInstance().applyTo(scene);
        stage.setScene(scene);
        stage.setOnHidden(e -> {
            openWindows.remove(protocol.id());
            if (onCloseCallback != null) onCloseCallback.run();
        });

        openWindows.put(protocol.id(), stage);
        loadCurrentExecution();
        loadHistory();
        stage.show();
    }

    // ── Header (header-bar) ─────────────────────────────────────────────────

    private HBox buildHeader() {
        // Badge de tipo
        Label typeBadge = new Label("  " + protocol.executionType().icon()
                + "  " + protocol.executionType().label() + "  ");
        typeBadge.getStyleClass().addAll("study-badge", "badge-type");
        typeBadge.setStyle(typeBadge.getStyle()
                + "-fx-font-size: 11px; -fx-text-fill: #7ec8e3;"
                + " -fx-background-color: rgba(0,180,216,0.15);"
                + " -fx-border-color: rgba(0,180,216,0.4); -fx-border-radius: 10;");

        // Nome do protocolo
        Label nameLbl = new Label(protocol.name());
        nameLbl.getStyleClass().add("page-title");
        nameLbl.setWrapText(true);

        // Categoria
        Label catBadge = new Label("  " + (protocol.category() != null ? protocol.category() : "Geral") + "  ");
        catBadge.setStyle("-fx-font-size: 10.5px; -fx-text-fill: #a8d4e6;"
                + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");

        // Barra de progresso
        execProgressBar = new ProgressBar(0);
        execProgressBar.setPrefWidth(220);
        execProgressBar.setPrefHeight(10);
        execProgressBar.getStyleClass().add("study-progress-bar");

        execProgressLabel = new Label("—");
        execProgressLabel.setStyle("-fx-font-size: 11.5px; -fx-font-weight: 700;"
                + " -fx-text-fill: #7ec8e3;"
                + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");

        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);
        HBox topRow = new HBox(10, typeBadge, nameLbl, catBadge, spacer,
                execProgressBar, execProgressLabel);
        topRow.setAlignment(Pos.CENTER_LEFT);

        // Descrição / hint de tipo
        Label descLbl = new Label(
            protocol.description() != null && !protocol.description().isBlank()
                ? protocol.description() : protocol.executionType().description());
        descLbl.setStyle("-fx-text-fill: #a8d4e6; -fx-font-size: 11.5px;"
                + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");
        descLbl.setWrapText(true);

        // Badge de validade
        Label validityLbl = new Label();
        validityLbl.setWrapText(false);
        if (protocol.hasValidity()) {
            java.time.LocalDate nextDue = repo.nextDueDate(protocol.id(), protocol.validityDays());
            if (nextDue != null) {
                long days = java.time.temporal.ChronoUnit.DAYS.between(
                        java.time.LocalDate.now(), nextDue);
                if (days < 0) {
                    validityLbl.setText("⚠  Validade VENCIDA há " + (-days) + " dias"
                            + "  (ciclo: " + protocol.validityDays() + "d)");
                    validityLbl.setStyle("-fx-text-fill: #ff6b6b; -fx-font-weight: 700;"
                            + " -fx-font-size: 11px;"
                            + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");
                } else {
                    validityLbl.setText("  Válido por mais " + days + " dias"
                            + "  (expira: " + nextDue.format(DATE_FMT) + ")");
                    validityLbl.setStyle("-fx-text-fill: " + (days <= 7 ? "#ffa94d" : "#69db7c") + ";"
                            + " -fx-font-size: 11px;"
                            + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");
                }
            } else {
                validityLbl.setText("  Validade: " + protocol.validityDays() + " dias após conclusão");
                validityLbl.setStyle("-fx-text-fill: #a8d4e6; -fx-font-size: 11px;"
                        + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");
            }
        }

        VBox headerContent = new VBox(5, topRow, descLbl);
        if (protocol.hasValidity()) headerContent.getChildren().add(validityLbl);
        headerContent.setMaxWidth(Double.MAX_VALUE);
        HBox.setHgrow(headerContent, Priority.ALWAYS);

        HBox header = new HBox(headerContent);
        header.setPadding(new Insets(14, 18, 12, 18));
        header.getStyleClass().add("header-bar");
        return header;
    }

    // ── Center ──────────────────────────────────────────────────────────────

    private SplitPane buildCenter() {
        SplitPane sp = new SplitPane(buildExecutionPanel(), buildHistoryPanel());
        sp.setDividerPositions(0.60);
        VBox.setVgrow(sp, Priority.ALWAYS);
        return sp;
    }

    // ── Painel de Execução Atual ─────────────────────────────────────────────

    private VBox buildExecutionPanel() {
        execHeaderLabel = new Label("Nenhuma execução ativa");
        execHeaderLabel.setStyle("-fx-font-size: 13px; -fx-font-weight: 700;"
                + " -fx-text-fill: #03183e;"
                + " -fx-border-color: transparent transparent #d6e4f5 transparent;"
                + " -fx-border-width: 0 0 1 0; -fx-padding: 0 0 6 0;");
        execHeaderLabel.setMaxWidth(Double.MAX_VALUE);

        // Painel "sem execução"
        noExecLabel = new Label("Nenhuma execução em andamento.\nClique em 'Iniciar Execução' para começar.");
        noExecLabel.getStyleClass().add("study-dates-label");
        noExecLabel.setWrapText(true);
        noExecLabel.setTextAlignment(javafx.scene.text.TextAlignment.CENTER);

        startBtn = new Button("▶  Iniciar Execução");
        startBtn.getStyleClass().add("primary-button");
        startBtn.setOnAction(e -> startNewExecution());

        VBox noExecBox = new VBox(16, noExecLabel, startBtn);
        noExecBox.setAlignment(Pos.CENTER);
        noExecBox.setPadding(new Insets(40));

        // Passos da execução ativa
        stepsContainer = new VBox(5);
        stepsContainer.setPadding(new Insets(4, 0, 4, 0));

        ScrollPane stepsScroll = new ScrollPane(stepsContainer);
        stepsScroll.setFitToWidth(true);
        stepsScroll.getStyleClass().add("edge-to-edge");
        VBox.setVgrow(stepsScroll, Priority.ALWAYS);

        // Notas
        Label notesLbl = new Label("Observações da execução:");
        notesLbl.setStyle("-fx-font-size: 11px; -fx-text-fill: #5a7a9e; -fx-font-weight: 600;");
        execNotesArea = new TextArea();
        execNotesArea.getStyleClass().add("input-control");
        execNotesArea.setPromptText("Observações desta execução (opcional)...");
        execNotesArea.setPrefRowCount(2);
        execNotesArea.setWrapText(true);

        // Botões de conclusão
        completeBtn = new Button("✓  Concluir Execução");
        completeBtn.getStyleClass().add("primary-button");
        completeBtn.setOnAction(e -> completeExecution(false));

        restartBtn = new Button("↺  Concluir e Reiniciar");
        restartBtn.getStyleClass().add("secondary-button");
        restartBtn.setOnAction(e -> completeExecution(true));

        cancelExecBtn = new Button("✗  Cancelar Execução");
        cancelExecBtn.getStyleClass().add("danger-button");
        cancelExecBtn.setOnAction(e -> cancelCurrentExecution());

        HBox actionBar = new HBox(8, completeBtn, restartBtn, createSpacer(), cancelExecBtn);
        actionBar.setAlignment(Pos.CENTER_LEFT);
        actionBar.setPadding(new Insets(8, 0, 0, 0));
        actionBar.setStyle("-fx-border-color: #d6e4f5; -fx-border-width: 1 0 0 0;");

        activeExecPanel = new VBox(8, stepsScroll, notesLbl, execNotesArea, actionBar);
        activeExecPanel.setPadding(new Insets(8, 0, 0, 0));
        VBox.setVgrow(stepsScroll, Priority.ALWAYS);
        VBox.setVgrow(activeExecPanel, Priority.ALWAYS);

        VBox panel = new VBox(8, execHeaderLabel, noExecBox);
        panel.setPadding(new Insets(12));
        panel.getStyleClass().add("section-card");
        VBox.setVgrow(panel, Priority.ALWAYS);

        panel.setUserData(new Object[]{ noExecBox, activeExecPanel });
        return panel;
    }

    // ── Painel de Histórico ──────────────────────────────────────────────────

    private VBox buildHistoryPanel() {
        Label title = new Label(" Histórico de Execuções");
        title.setStyle("-fx-font-size: 13px; -fx-font-weight: 700; -fx-text-fill: #03183e;"
                + " -fx-border-color: transparent transparent #d6e4f5 transparent;"
                + " -fx-border-width: 0 0 1 0; -fx-padding: 0 0 6 0;");
        title.setMaxWidth(Double.MAX_VALUE);

        historyList = new ListView<>(historyItems);
        historyList.getStyleClass().add("clean-list");
        historyList.setCellFactory(lv -> new ListCell<>() {
            @Override protected void updateItem(ProtocolExecution e, boolean empty) {
                super.updateItem(e, empty);
                if (empty || e == null) { setText(null); setGraphic(null); return; }

                String icon  = e.isCompleted() ? "✓" : e.isCancelled() ? "✗" : "●";
                Color  color = e.isCompleted() ? Color.web("#27ae60")
                             : e.isCancelled() ? Color.web("#e74c3c") : Color.web("#e67e22");
                String iter  = e.executionType() == ProtocolExecutionType.EXPERIMENTO
                             ? "  Iter. " + e.iterationNumber() : "";
                String dt    = e.startedAt() != null ? e.startedAt().format(DT_FMT) : "?";
                String steps = e.totalSteps() > 0
                             ? "  " + e.checkedSteps() + "/" + e.totalSteps() + " passos" : "";

                Label iconLbl = new Label(icon);
                iconLbl.setTextFill(color);
                iconLbl.setStyle("-fx-font-weight: bold; -fx-font-size: 14px;");

                Label mainLbl = new Label(dt + iter + steps);
                mainLbl.getStyleClass().add("study-plan-detail");

                Label statusLbl = new Label("  " + e.status() + "  ");
                statusLbl.getStyleClass().addAll("study-badge",
                        "badge-status-" + e.status().toLowerCase());

                Region sp2 = new Region(); HBox.setHgrow(sp2, Priority.ALWAYS);
                HBox row = new HBox(8, iconLbl, mainLbl, sp2, statusLbl);
                row.setAlignment(Pos.CENTER_LEFT);
                setGraphic(row); setText(null);
            }
        });
        VBox.setVgrow(historyList, Priority.ALWAYS);

        // Painel de detalhes da execução selecionada
        historyDetailBox = new VBox(6);
        historyDetailBox.setStyle("-fx-background-color: #f8fafc;"
                + " -fx-background-radius: 5; -fx-border-color: #dce8f5;"
                + " -fx-border-radius: 5; -fx-padding: 8;");
        historyDetailBox.setMinHeight(80);

        Label detailHdr = new Label("Detalhes da Execução");
        detailHdr.setStyle("-fx-font-size: 10.5px; -fx-text-fill: #5a7a9e; -fx-font-weight: 700;");
        historyDetailBox.getChildren().add(
                new Label("Selecione uma execução para ver detalhes.") {{
                    getStyleClass().add("study-dates-label"); }});

        historyList.getSelectionModel().selectedItemProperty().addListener(
            (obs, old, sel) -> showHistoryDetail(sel));

        VBox panel = new VBox(8, title, historyList, historyDetailBox);
        panel.setPadding(new Insets(12));
        panel.getStyleClass().add("section-card");
        VBox.setVgrow(panel, Priority.ALWAYS);
        return panel;
    }

    // ── Lógica de Execução ───────────────────────────────────────────────────

    private void loadCurrentExecution() {
        currentExecution = repo.findActiveExecution(protocol.id()).orElse(null);
        refreshExecutionPanel();
    }

    private void loadHistory() {
        historyItems.setAll(repo.findExecutions(protocol.id(), null));
    }

    @SuppressWarnings("unchecked")
    private void refreshExecutionPanel() {
        SplitPane sp = (SplitPane) ((VBox) stage.getScene().getRoot())
                .getChildren().stream()
                .filter(n -> n instanceof SplitPane)
                .findFirst().orElse(null);
        if (sp == null) return;

        VBox execPanel = (VBox) sp.getItems().get(0);
        Object[] refs  = (Object[]) execPanel.getUserData();
        if (refs == null) return;

        VBox noExecBox   = (VBox) refs[0];
        VBox activePanel = (VBox) refs[1];

        if (currentExecution == null) {
            execHeaderLabel.setText("Nenhuma execução ativa");
            execProgressBar.setProgress(0);
            execProgressLabel.setText("—");

            boolean unicoJaUsado = protocol.executionType() == ProtocolExecutionType.UNICO
                    && !repo.findExecutions(protocol.id(), "CONCLUIDA").isEmpty();
            if (unicoJaUsado) {
                noExecLabel.setText("Este protocolo é de uso único e já foi executado.\n"
                        + "Consulte o histórico para ver o registro completo.");
                startBtn.setVisible(false); startBtn.setManaged(false);
            } else {
                noExecLabel.setText("Nenhuma execução em andamento.\nClique em 'Iniciar Execução' para começar.");
                startBtn.setVisible(true); startBtn.setManaged(true);
            }

            execPanel.getChildren().remove(activePanel);
            if (!execPanel.getChildren().contains(noExecBox)) execPanel.getChildren().add(noExecBox);
        } else {
            int iter = currentExecution.iterationNumber();
            String iterLabel = protocol.executionType() == ProtocolExecutionType.EXPERIMENTO
                    ? "  —  Iteração " + iter : "";
            execHeaderLabel.setText("Em execução" + iterLabel
                    + "  ·  Iniciada: "
                    + (currentExecution.startedAt() != null
                       ? currentExecution.startedAt().format(DT_FMT) : "?"));

            double prog = currentExecution.progressPercent() / 100.0;
            execProgressBar.setProgress(prog);
            execProgressLabel.setText(currentExecution.checkedSteps()
                    + "/" + currentExecution.totalSteps() + " passos");

            execPanel.getChildren().remove(noExecBox);
            if (!execPanel.getChildren().contains(activePanel)) execPanel.getChildren().add(activePanel);

            refreshSteps();

            boolean supportsRestart = protocol.executionType().supportsRestart();
            restartBtn.setVisible(supportsRestart); restartBtn.setManaged(supportsRestart);

            if (protocol.executionType() == ProtocolExecutionType.EXPERIMENTO) {
                restartBtn.setText("↺  Concluir Iter. " + iter + " → Próxima");
                completeBtn.setText("✓  Encerrar Experimento");
            } else if (supportsRestart) {
                restartBtn.setText("↺  Concluir e Reiniciar");
                completeBtn.setText("✓  Concluir sem Reiniciar");
            } else if (protocol.executionType() == ProtocolExecutionType.UNICO) {
                completeBtn.setText("✓  Concluir (uso único)");
            } else {
                completeBtn.setText("✓  Concluir Execução");
            }
        }
    }

    private void refreshSteps() {
        stepsContainer.getChildren().clear();
        if (currentExecution == null) return;

        List<ProtocolExecutionStep> steps = repo.findExecutionSteps(currentExecution.id());

        for (ProtocolExecutionStep s : steps) {
            boolean done = s.checked();

            CheckBox cb = new CheckBox();
            cb.setSelected(done);
            cb.setDisable(done);

            Label numLbl = new Label(s.stepOrder() + ".");
            numLbl.setStyle("-fx-font-weight: 700; -fx-font-size: 12px; -fx-text-fill: #5a7a9e;"
                    + " -fx-min-width: 28px;");

            Label stepLbl = new Label(s.stepText());
            stepLbl.getStyleClass().add(s.critical() ? "study-plan-title" : "study-plan-detail");
            stepLbl.setWrapText(true);
            HBox.setHgrow(stepLbl, Priority.ALWAYS);
            if (done) stepLbl.setStyle("-fx-opacity: 0.5; -fx-strikethrough: true;");

            Label critLbl = new Label();
            if (s.critical()) {
                critLbl.setText("⚠ crítico");
                critLbl.setStyle("-fx-font-size: 9.5px; -fx-font-weight: 700;"
                        + " -fx-text-fill: #b71c1c; -fx-background-color: #fde8e8;"
                        + " -fx-background-radius: 8; -fx-padding: 1 6 1 6;");
            }

            Label timeStampLbl = new Label(s.checkedAt() != null ? s.checkedAt().format(DT_FMT) : "");
            timeStampLbl.setStyle("-fx-font-size: 10px; -fx-text-fill: #5a7a9e;"
                    + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");

            Button undoBtn = new Button("↩");
            undoBtn.getStyleClass().add("secondary-button");
            undoBtn.setStyle("-fx-font-size: 11px; -fx-padding: 2 8 2 8;");
            undoBtn.setTooltip(new Tooltip("Desmarcar este passo"));
            undoBtn.setVisible(done); undoBtn.setManaged(done);
            undoBtn.setOnAction(e -> { repo.uncheckStep(s.id()); reloadExecution(); });

            cb.setOnAction(e -> {
                if (cb.isSelected()) { repo.checkStep(s.id(), null); reloadExecution(); }
            });

            HBox row = new HBox(8, cb, numLbl, stepLbl, critLbl,
                    new Region() {{ HBox.setHgrow(this, Priority.ALWAYS); }},
                    timeStampLbl, undoBtn);
            row.setAlignment(Pos.CENTER_LEFT);
            row.setPadding(new Insets(6, 10, 6, 10));
            row.setStyle("-fx-background-color: " + (done ? "#f8fffe" : "white") + ";"
                    + " -fx-background-radius: 5;"
                    + " -fx-border-color: " + (done ? "#b2dfdb" : "#e8eef4") + ";"
                    + " -fx-border-radius: 5; -fx-border-width: 1;");
            stepsContainer.getChildren().add(row);
        }
    }

    private void reloadExecution() {
        currentExecution = repo.findActiveExecution(protocol.id()).orElse(null);
        refreshExecutionPanel();
        loadHistory();
    }

    private void startNewExecution() {
        repo.startExecution(protocol.id()); reloadExecution();
    }

    private void completeExecution(boolean andRestart) {
        if (currentExecution == null) return;
        String notes = execNotesArea.getText();

        List<ProtocolExecutionStep> steps = repo.findExecutionSteps(currentExecution.id());
        long criticalPending = steps.stream().filter(s -> s.critical() && !s.checked()).count();
        if (criticalPending > 0) {
            Alert warn = new Alert(Alert.AlertType.CONFIRMATION);
            warn.setTitle("Passos Críticos Pendentes");
            warn.setHeaderText(criticalPending + " passo(s) CRÍTICO(S) ainda não foram marcados.");
            warn.setContentText("Deseja concluir mesmo assim?");
            Optional<ButtonType> r = warn.showAndWait();
            if (r.isEmpty() || r.get() != ButtonType.OK) return;
        }

        repo.completeExecution(currentExecution.id(), notes);
        execNotesArea.clear();

        if (andRestart) {
            repo.startExecution(protocol.id());
        } else {
            currentExecution = null;
        }
        reloadExecution();
    }

    private void cancelCurrentExecution() {
        if (currentExecution == null) return;
        Alert confirm = new Alert(Alert.AlertType.CONFIRMATION);
        confirm.setTitle("Cancelar Execução");
        confirm.setHeaderText("Cancelar a execução em andamento?");
        confirm.setContentText(
                "O progresso será perdido. A execução ficará registrada como Cancelada no histórico.");
        confirm.showAndWait().filter(b -> b == ButtonType.OK).ifPresent(b -> {
            repo.cancelExecution(currentExecution.id());
            currentExecution = null;
            reloadExecution();
        });
    }

    private void showHistoryDetail(ProtocolExecution exec) {
        historyDetailBox.getChildren().clear();
        if (exec == null) {
            historyDetailBox.getChildren().add(new Label("Selecione uma execução para ver detalhes.") {{
                getStyleClass().add("study-dates-label");
            }});
            return;
        }

        // Status badge
        Label statusBadge = new Label("  " + exec.status() + "  ");
        statusBadge.getStyleClass().addAll("study-badge",
                "badge-status-" + exec.status().toLowerCase());

        // Métricas
        HBox statusRow = new HBox(8, statusBadge);
        if (exec.executionType() == ProtocolExecutionType.EXPERIMENTO)
            statusRow.getChildren().add(new Label("Iteração " + exec.iterationNumber() + "  ") {{
                setStyle("-fx-font-size: 11px; -fx-text-fill: #5a7a9e;"
                        + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");
            }});
        statusRow.setAlignment(Pos.CENTER_LEFT);

        historyDetailBox.getChildren().add(statusRow);

        // Detalhes de tempo
        addDetailRow(historyDetailBox, "Início",
                exec.startedAt() != null ? exec.startedAt().format(DT_FMT) : "—");
        addDetailRow(historyDetailBox, "Conclusão",
                exec.completedAt() != null ? exec.completedAt().format(DT_FMT) : "—");

        // Duração
        if (exec.startedAt() != null && exec.completedAt() != null) {
            long mins = java.time.Duration.between(exec.startedAt(), exec.completedAt()).toMinutes();
            addDetailRow(historyDetailBox, "Duração",
                    mins < 60 ? mins + " min"
                              : (mins / 60) + "h " + (mins % 60) + "min");
        }

        addDetailRow(historyDetailBox, "Progresso",
                exec.checkedSteps() + " / " + exec.totalSteps() + " passos concluídos");

        if (exec.notes() != null && !exec.notes().isBlank()) {
            Label notesLbl = new Label("Obs: " + exec.notes());
            notesLbl.setStyle("-fx-font-size: 11px; -fx-text-fill: #1e3a5f; -fx-wrap-text: true;"
                    + " -fx-background-color: #f0f5fc; -fx-background-radius: 4; -fx-padding: 4 6 4 6;");
            notesLbl.setWrapText(true);
            historyDetailBox.getChildren().add(notesLbl);
        }
    }

    private static void addDetailRow(VBox parent, String key, String value) {
        Label lbl = new Label(key + ":  " + value);
        lbl.setStyle("-fx-font-size: 11px; -fx-text-fill: #1e3a5f;"
                + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");
        parent.getChildren().add(lbl);
    }

    // ── Spacer helper ────────────────────────────────────────────────────────

    private static Region createSpacer() {
        Region r = new Region();
        HBox.setHgrow(r, Priority.ALWAYS);
        return r;
    }
}

package com.pessoal.agenda.ui.view;

import com.pessoal.agenda.model.TaskSession;
import com.pessoal.agenda.repository.TaskSessionRepository;
import javafx.application.Platform;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.beans.property.SimpleIntegerProperty;
import javafx.beans.property.SimpleStringProperty;
import javafx.scene.layout.BorderPane;
import javafx.scene.layout.HBox;
import javafx.scene.layout.Priority;
import javafx.scene.layout.VBox;
import javafx.stage.Modality;
import javafx.stage.Stage;

import java.io.FileWriter;
import java.io.PrintWriter;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.List;
import com.pessoal.agenda.app.AppContextHolder;
import java.util.concurrent.CompletableFuture;

/**
 * Improved Window that shows session history either by task or by date range.
 * Features:
 * - Period quick-filters (Day/Week/Month/Year)
 * - From / To DatePicker range
 * - Optional taskId filter (when opened for a specific task)
 * - TableView with columns (Date, Subject, Minutes, Notes)
 * - Total minutes label and CSV export button
 */
public class SessionHistoryWindow {
    private final TaskSessionRepository repo;
    private final Long taskId; // nullable - open focused on a task
    private Stage stage;

    // UI
    private final ObservableList<TaskSession> data = FXCollections.observableArrayList();

    public SessionHistoryWindow(TaskSessionRepository repo, Long taskId) {
        this.repo = repo;
        this.taskId = taskId;
    }

    public void show() {
        stage = new Stage();
        WindowManager.register(stage);
        stage.initModality(Modality.NONE);
        stage.setTitle("Histórico de sessões");

        BorderPane root = new BorderPane();
        root.getStyleClass().add("app-root");

        // ── Barra superior elegante igual ao form principal ──
        Label title = new Label("Histórico de sessões");
        title.getStyleClass().add("page-title");
        HBox headerBar = new HBox(title);
        headerBar.getStyleClass().add("header-bar");
        headerBar.setPadding(new Insets(16, 28, 16, 28));
        headerBar.setAlignment(Pos.CENTER_LEFT);

        // ── Filtros logo abaixo, integrados ──
        ToggleGroup periodGroup = new ToggleGroup();
        ToggleButton btnDay = new ToggleButton("Dia");
        ToggleButton btnWeek = new ToggleButton("Semana");
        ToggleButton btnMonth = new ToggleButton("Mês");
        ToggleButton btnYear = new ToggleButton("Ano");
        for (ToggleButton b : List.of(btnDay, btnWeek, btnMonth, btnYear)) {
            b.setToggleGroup(periodGroup);
            b.getStyleClass().add("view-toggle-btn");
            b.setMinWidth(56);
        }
        btnWeek.setSelected(true);
        HBox periodBox = new HBox(0, btnDay, btnWeek, btnMonth, btnYear);
        periodBox.getStyleClass().add("view-toggle-bar");
        periodBox.setAlignment(Pos.CENTER_LEFT);
        periodBox.setSpacing(0);

        DatePicker fromPicker = new DatePicker(LocalDate.now().minusWeeks(1));
        fromPicker.getStyleClass().add("input-control");
        fromPicker.setMinWidth(110);
        fromPicker.setPrefWidth(110);
        DatePicker toPicker = new DatePicker(LocalDate.now());
        toPicker.getStyleClass().add("input-control");
        toPicker.setMinWidth(110);
        toPicker.setPrefWidth(110);

        TextField taskFilter = new TextField();
        taskFilter.setPromptText("Filtrar por tarefa (texto no assunto)");
        taskFilter.getStyleClass().add("input-control");
        taskFilter.setMinWidth(140);
        if (taskId != null) { taskFilter.setText("#" + taskId); taskFilter.setDisable(true); }

        Button refreshBtn = new Button("Atualizar");
        refreshBtn.getStyleClass().add("primary-button");
        Button exportBtn = new Button("Exportar CSV");
        exportBtn.getStyleClass().add("secondary-button");

        Label periodoLabel = new Label("Período:");
        periodoLabel.setMinWidth(54);
        Label deLabel = new Label("De:");
        deLabel.setMinWidth(28);
        Label ateLabel = new Label("Até:");
        ateLabel.setMinWidth(28);

        HBox filtersRow = new HBox(14,
            periodoLabel, periodBox,
            deLabel, fromPicker, ateLabel, toPicker,
            taskFilter, refreshBtn, exportBtn
        );
        filtersRow.setAlignment(Pos.CENTER_LEFT);
        filtersRow.setPadding(new Insets(12, 28, 12, 28));
        HBox.setHgrow(taskFilter, Priority.ALWAYS);

        VBox topPanel = new VBox(headerBar, filtersRow);
        topPanel.setSpacing(0);
        // Não precisa de fundo extra, segue padrão do app

        // ── Tabela central ──
        TableView<TaskSession> table = new TableView<>();
        table.setColumnResizePolicy(TableView.CONSTRAINED_RESIZE_POLICY_ALL_COLUMNS);
        table.getStyleClass().add("clean-list");
        TableColumn<TaskSession, String> dateCol = new TableColumn<>("Data");
        dateCol.setCellValueFactory(cell -> new SimpleStringProperty(
            cell.getValue().sessionDate() != null ? cell.getValue().sessionDate().format(DateTimeFormatter.ofPattern("dd/MM/yyyy")) : ""));
        dateCol.setMinWidth(90);
        TableColumn<TaskSession, String> subjCol = new TableColumn<>("Assunto");
        subjCol.setCellValueFactory(cell -> new SimpleStringProperty(
            cell.getValue().subject() != null ? cell.getValue().subject() : ""));
        subjCol.setMinWidth(220);
        TableColumn<TaskSession, Number> minsCol = new TableColumn<>("Minutos");
        minsCol.setCellValueFactory(cell -> new SimpleIntegerProperty(cell.getValue().durationMinutes()));
        minsCol.setMinWidth(70);
        TableColumn<TaskSession, String> notesCol = new TableColumn<>("Notas");
        notesCol.setCellValueFactory(cell -> new SimpleStringProperty(
            cell.getValue().notes() != null ? cell.getValue().notes() : ""));
        notesCol.setMinWidth(120);
        table.getColumns().addAll(dateCol, subjCol, minsCol, notesCol);
        table.setItems(data);
        VBox.setVgrow(table, Priority.ALWAYS);

        // ── Rodapé ──
        HBox bottom = new HBox(18);
        bottom.setAlignment(Pos.CENTER_LEFT);
        bottom.setPadding(new Insets(10, 28, 0, 28));
        Label totalLabel = new Label("Total: 0 min");
        totalLabel.getStyleClass().add("section-title");
        Label hint = new Label("Clique duas vezes em uma linha para abrir a sessão/tarefa.");
        hint.getStyleClass().add("form-label");
        bottom.getChildren().addAll(totalLabel, hint);

        VBox centerVBox = new VBox(8, table, bottom);
        centerVBox.setPadding(new Insets(0, 0, 18, 0));
        VBox.setVgrow(table, Priority.ALWAYS);

        root.setTop(topPanel);
        root.setCenter(centerVBox);

        Scene sc = new Scene(root);
        var cssUrl = SessionHistoryWindow.class.getResource("/com/pessoal/agenda/app.css");
        if (cssUrl != null) sc.getStylesheets().add(cssUrl.toExternalForm());
        stage.setScene(sc);

        // actions
        Runnable doLoad = () -> loadData(fromPicker.getValue(), toPicker.getValue(), taskFilter.getText(), totalLabel);
        btnDay.setOnAction(e -> { fromPicker.setValue(LocalDate.now()); toPicker.setValue(LocalDate.now()); doLoad.run(); });
        btnWeek.setOnAction(e -> { fromPicker.setValue(LocalDate.now().minusWeeks(1)); toPicker.setValue(LocalDate.now()); doLoad.run(); });
        btnMonth.setOnAction(e -> { fromPicker.setValue(LocalDate.now().minusMonths(1)); toPicker.setValue(LocalDate.now()); doLoad.run(); });
        btnYear.setOnAction(e -> { fromPicker.setValue(LocalDate.now().minusYears(1)); toPicker.setValue(LocalDate.now()); doLoad.run(); });
        refreshBtn.setOnAction(e -> doLoad.run());
        exportBtn.setOnAction(e -> exportCsv());
        table.setRowFactory(tv -> {
            TableRow<TaskSession> row = new TableRow<>();
            row.setOnMouseClicked(ev -> {
                if (ev.getClickCount() == 2 && !row.isEmpty()) {
                    TaskSession s = row.getItem();
                    Long tid = extractTaskIdFromSubject(s.subject());
                    if (tid != null) {
                        Platform.runLater(() -> new TaskTimerWindow(AppContextHolder.get().taskService().findById(tid).orElseThrow(), AppContextHolder.get().taskSessionRepository()).show());
                    }
                }
            });
            return row;
        });
        Platform.runLater(doLoad);
        stage.show();
    }

    private static Long extractTaskIdFromSubject(String subj) {
        if (subj == null) return null;
        // try to find pattern '#<digits>'
        int idx = subj.indexOf('#');
        if (idx >= 0 && idx + 1 < subj.length()) {
            String tail = subj.substring(idx + 1);
            StringBuilder digits = new StringBuilder();
            for (int i = 0; i < tail.length(); i++) {
                char c = tail.charAt(i);
                if (Character.isDigit(c)) digits.append(c); else break;
            }
            if (digits.length() > 0) {
                try { return Long.parseLong(digits.toString()); } catch (NumberFormatException ignored) {}
            }
        }
        return null;
    }

    private void loadData(LocalDate from, LocalDate to, String taskFilter, Label totalLabel) {
        CompletableFuture.supplyAsync(() -> {
            try {
                if (taskId != null) {
                    return repo.findByTaskId(taskId);
                }
                if (taskFilter != null && taskFilter.trim().startsWith("#")) {
                    // try parse id
                    String digits = taskFilter.trim().substring(1).replaceAll("\\D", "");
                    if (!digits.isEmpty()) {
                        try { long tid = Long.parseLong(digits); return repo.findByTaskId(tid); } catch (NumberFormatException ex) {}
                    }
                }
                // default date-range query
                LocalDate f = from == null ? LocalDate.now().minusMonths(1) : from;
                LocalDate t = to == null ? LocalDate.now() : to;
                return repo.findByDateRange(f, t);
            } catch (Throwable ex) {
                ex.printStackTrace();
                return List.<TaskSession>of();
            }
        }).thenAccept(list -> Platform.runLater(() -> {
            data.clear();
            if (taskFilter != null && !taskFilter.trim().isEmpty() && !(taskFilter.trim().startsWith("#"))) {
                String tf = taskFilter.trim().toLowerCase();
                for (TaskSession s : list) if (s.subject() != null && s.subject().toLowerCase().contains(tf)) data.add(s);
            } else {
                data.addAll(list);
            }
            int total = data.stream().mapToInt(TaskSession::durationMinutes).sum();
            totalLabel.setText("Total: " + total + " min");
        }));
    }

    private void exportCsv() {
        try {
            var dlg = new javafx.stage.FileChooser();
            dlg.setTitle("Salvar CSV");
            dlg.getExtensionFilters().add(new javafx.stage.FileChooser.ExtensionFilter("CSV","*.csv"));
            var file = dlg.showSaveDialog(stage);
            if (file == null) return;
            try (PrintWriter pw = new PrintWriter(new FileWriter(file))) {
                pw.println("date,subject,minutes,notes");
                for (TaskSession s : data) {
                    String notes = s.notes() == null ? "" : s.notes().replaceAll("[\\r\\n]"," ").replaceAll(",",";");
                    pw.printf("%s,%s,%d,%s\n", s.sessionDate(), s.subject().replaceAll(",",";"), s.durationMinutes(), notes);
                }
            }
        } catch (Throwable ex) {
            ex.printStackTrace();
            // best-effort: show simple alert
            Platform.runLater(() -> {
                Alert a = new Alert(Alert.AlertType.ERROR, "Não foi possível exportar CSV: " + ex.getMessage(), ButtonType.OK);
                a.initOwner(stage);
                a.showAndWait();
            });
        }
    }
}

