        entryPageStartField = new TextField(); entryPageStartField.getStyleClass().add("input-control");
        entryPageStartField.setPromptText("início"); entryPageStartField.setPrefWidth(70);
        entryPageEndField   = new TextField(); entryPageEndField.getStyleClass().add("input-control");
        entryPageEndField.setPromptText("fim"); entryPageEndField.setPrefWidth(70);

        GridPane form = new GridPane();
        form.getStyleClass().add("form-grid"); form.setHgap(10); form.setVgap(7);
        form.add(new Label("Data:"),             0, 0); form.add(entryDatePicker,    1, 0);
        form.add(new Label("Tipo:"),             2, 0); form.add(entryTypeCombo,     3, 0);
        form.add(new Label("Duração (min):"),    4, 0); form.add(entryDurationField, 5, 0);
        form.add(new Label("Título da entrada:"),0, 1);
        form.add(entryTitleField,                1, 1, 5, 1);
        GridPane.setHgrow(entryTitleField, Priority.ALWAYS);

        pagesRowContainer = new HBox(8,
                new Label("Páginas cobertas:"), entryPageStartField, new Label("→"), entryPageEndField);
        pagesRowContainer.setAlignment(Pos.CENTER_LEFT);
        pagesRowContainer.setVisible(currentPlan.isBook()); pagesRowContainer.setManaged(currentPlan.isBook());

        // ── barra de ferramentas extra (cola sem formatação) ───────────────
        Button pasteNoFmtBtn = new Button("  Colar sem formatação");
        pasteNoFmtBtn.getStyleClass().add("secondary-button");
        pasteNoFmtBtn.setTooltip(new Tooltip(
                "Cola o conteúdo da área de transferência como texto puro,\n" +
                "removendo toda formatação HTML copiada de sites ou outros editores."));
        pasteNoFmtBtn.setOnAction(e -> pasteAsPlainText());

        Label editorHint = new Label(
                "Ctrl+B = negrito  ·  Ctrl+I = itálico  ·  Ctrl+U = sublinhado  ·  " +
                "Ctrl+V = colar com formatação");
        editorHint.getStyleClass().add("study-plan-detail");

        HBox extraToolbar = new HBox(12, pasteNoFmtBtn, editorHint);
        extraToolbar.setAlignment(Pos.CENTER_LEFT);
        extraToolbar.getStyleClass().add("rich-editor-toolbar");
        extraToolbar.setPadding(new Insets(4, 6, 4, 6));

        // ── Timer controls (play / pause / stop) ───────────────────────
        timerPlayPauseBtn = new Button("▶");
        timerPlayPauseBtn.getStyleClass().addAll("icon-button");
        timerPlayPauseBtn.setTooltip(new Tooltip("Iniciar / Pausar sessão de estudo"));
        timerStopBtn = new Button("■");
        timerStopBtn.getStyleClass().addAll("icon-button", "danger-button");
        timerStopBtn.setTooltip(new Tooltip("Parar sessão (salva e registra tempo)"));
        timerLabel = new Label("00:00:00"); timerLabel.getStyleClass().add("study-dates-label");
        timerAutoSaveChk = new CheckBox("Salvar automaticamente ao parar"); timerAutoSaveChk.setSelected(true);

        HBox timerRow = new HBox(8, timerPlayPauseBtn, timerStopBtn, timerLabel, timerAutoSaveChk);
        timerRow.setAlignment(Pos.CENTER_LEFT);
        timerRow.setPadding(new Insets(6,0,6,0));

        // Handlers
        timerPlayPauseBtn.setOnAction(e -> toggleTimer());
        timerStopBtn.setOnAction(e -> stopTimerAndSave());

        // executor will be created when window opens

        // ── editor rico ────────────────────────────────────────────────────
        richEditor = new HTMLEditor();
        richEditor.getStyleClass().add("diary-rich-editor");
        richEditor.setHtmlText(BLANK_HTML);
        VBox.setVgrow(richEditor, Priority.ALWAYS);

        // ── botões ─────────────────────────────────────────────────────────
        entrySubmitBtn = new Button("Salvar entrada");
        entrySubmitBtn.getStyleClass().add("primary-button");
        entrySubmitBtn.setOnAction(e -> saveCurrentEntry());

        Button cancelBtn = new Button("Cancelar / Limpar");
        cancelBtn.getStyleClass().add("secondary-button");
        cancelBtn.setOnAction(e -> clearEntryForm());

        HBox btnRow = new HBox(8, entrySubmitBtn, cancelBtn);
        btnRow.setAlignment(Pos.CENTER_LEFT);

        Label notesLbl = new Label("Anotações / Diário científico:");
        notesLbl.getStyleClass().add("form-label");

        VBox panel = new VBox(8, entryFormModeLabel, form, pagesRowContainer,
                notesLbl, extraToolbar, timerRow, richEditor, btnRow);
        panel.setPadding(new Insets(12)); panel.getStyleClass().add("section-card");
        return panel;
    }

    // ══════════════════════════════════════════════════════════════════════
    // LÓGICA DE ENTRADAS
    // ══════════════════════════════════════════════════════════════════════

    private void loadEntries() {
        entries.setAll(entryRepo.findByStudyId(currentPlan.id()));
        if (!entries.isEmpty()) indexListView.getSelectionModel().selectLast();
        refreshHeaderStats();
    }

    private void refreshHeaderStats() {
        int count    = entries.size();
        int totalMin = entries.stream().mapToInt(StudyEntry::durationMinutes).sum();
        int hrs = totalMin / 60, mins = totalMin % 60;
        String lastDate = entries.isEmpty() ? "—"
                : entries.get(entries.size() - 1).entryDate()
                         .format(DateTimeFormatter.ofPattern("dd/MM/yyyy", Locale.forLanguageTag("pt-BR")));
        headerStatsLabel.setText(String.format(
                "Entradas: %d   ▸   Tempo total: %dh %02dmin   ▸   Última sessão: %s",
                count, hrs, mins, lastDate));
        double prog = currentPlan.computedProgress();
        headerProgressBar.getStyleClass().removeAll("progress-complete","progress-high","progress-low");
        if      (prog >= 100) headerProgressBar.getStyleClass().add("progress-complete");
        else if (prog >= 60)  headerProgressBar.getStyleClass().add("progress-high");
        else if (prog <  25)  headerProgressBar.getStyleClass().add("progress-low");
    }

    private void loadEntryIntoForm(StudyEntry e) {
        editingEntryId = e.id();
        entryDatePicker.setValue(e.entryDate() != null ? e.entryDate() : LocalDate.now());
        entryTitleField.setText(e.hasTitle() ? e.entryTitle() : "");
        entryDurationField.setText(e.durationMinutes() > 0 ? String.valueOf(e.durationMinutes()) : "");
        entryPageStartField.setText(e.pageStart() > 0 ? String.valueOf(e.pageStart()) : "");
        entryPageEndField.setText(e.pageEnd()   > 0 ? String.valueOf(e.pageEnd())   : "");
        // Carregar conteúdo — compatível com texto puro (entradas antigas) e HTML
        String html = e.content() != null ? e.content() : "";
        if (!html.trim().toLowerCase().startsWith("<html")) {
            html = "<html><body style='font-family:\"Segoe UI\",Inter,sans-serif;font-size:13px;'><p>"
                    + html.replace("&","&amp;").replace("<","&lt;").replace(">","&gt;")
                           .replace("\n","<br>")
                    + "</p></body></html>";
        }
        richEditor.setHtmlText(html);
        entryFormModeLabel.setText("Editando: \"" + (e.hasTitle() ? e.entryTitle() : "entrada") + "\"");
        entrySubmitBtn.setText("Salvar alterações");
    }

    private void clearEntryForm() {
        editingEntryId = null;
        entryDatePicker.setValue(LocalDate.now());
        entryTitleField.clear(); entryDurationField.clear();
        entryPageStartField.clear(); entryPageEndField.clear();
        richEditor.setHtmlText(BLANK_HTML);
        entryTypeCombo.setValue("Leitura");
        entryFormModeLabel.setText("Nova entrada no diário");
        entrySubmitBtn.setText("Salvar entrada");
        indexListView.getSelectionModel().clearSelection();
    }

    private void saveCurrentEntry() {
        String title   = entryTitleField.getText().trim();
        String content = richEditor.getHtmlText();               // HTML completo
        String type    = entryTypeCombo.getValue() != null ? entryTypeCombo.getValue() : "Leitura";
        String fTitle  = title.isBlank() ? type : title;

        // Verificar se o corpo HTML está vazio
        boolean bodyEmpty = content == null || content.isBlank()
                || content.replaceAll("<[^>]+>","").isBlank();
        if (bodyEmpty && fTitle.equals(type)) return;

        LocalDate date = entryDatePicker.getValue() != null ? entryDatePicker.getValue() : LocalDate.now();
        int duration   = parseInt(entryDurationField.getText());
        int pgStart    = parseInt(entryPageStartField.getText());
        int pgEnd      = parseInt(entryPageEndField.getText());

        if (editingEntryId == null) {
            entryRepo.save(currentPlan.id(), fTitle, date, content, duration, pgStart, pgEnd);
        } else {
            entryRepo.update(editingEntryId, fTitle, date, content, duration, pgStart, pgEnd);
        }
        loadEntries(); clearEntryForm();
        if (refreshCallback != null) refreshCallback.run();
    }

    // ── Timer logic ───────────────────────────────────────────────────

    private void toggleTimer() {
        if (!timerRunning) {
            // start
            timerRunning = true;
            timerPlayPauseBtn.setText("⏸");
            playSignal("start"); // start tone or WAV
            // set shared active session indicator if diary not focused
            try { if (sharedCtx != null) sharedCtx.activeStudySessionLabel.setText("Sessão: " + timerLabel.getText()); } catch (Exception ex) { /* ignore */ }
            long start = System.currentTimeMillis();
            timerFuture = timerExecutor.scheduleAtFixedRate(this::tick, 0, 1, java.util.concurrent.TimeUnit.SECONDS);
        } else {
            // pause
            timerRunning = false;
            timerPlayPauseBtn.setText("▶");
            playSignal("pause"); // pause tone or WAV
            // clear shared indicator
            try { if (sharedCtx != null) sharedCtx.activeStudySessionLabel.setText(""); } catch (Exception ex) { /* ignore */ }
            if (timerFuture != null) timerFuture.cancel(false);
        }
    }

    private void stopTimerAndSave() {
        if (timerFuture != null) timerFuture.cancel(false);
        timerRunning = false; timerPlayPauseBtn.setText("▶");
        playSignal("stop"); // stop tone or WAV
        try { if (sharedCtx != null) sharedCtx.activeStudySessionLabel.setText(""); } catch (Exception ex) { /* ignore */ }
        if (timerSeconds.get() > 0 && timerAutoSaveChk.isSelected()) {
            // ask user to confirm and allow editing title/minutes before saving
            int minutes = (int) Math.round(timerSeconds.get() / 60.0);
            if (minutes <= 0) minutes = 1;
            Dialog<ButtonType> dlg = new Dialog<>();
            dlg.setTitle("Confirmar sessão");
            dlg.setHeaderText("Salvar sessão de estudo?");

            ButtonType saveBtn = new ButtonType("Salvar", ButtonBar.ButtonData.OK_DONE);
            dlg.getDialogPane().getButtonTypes().addAll(saveBtn, ButtonType.CANCEL);

            GridPane gp = new GridPane(); gp.setHgap(10); gp.setVgap(10); gp.setPadding(new Insets(10));
            TextField titleField = new TextField("Sessão contabilizada — " + minutes + " min");
            Spinner<Integer> minutesSpinner = new Spinner<>(1, 24 * 60, minutes);
            minutesSpinner.setEditable(true);
            gp.add(new Label("Título:"), 0, 0); gp.add(titleField, 1, 0);
            gp.add(new Label("Duração (min):"), 0, 1); gp.add(minutesSpinner, 1, 1);

            dlg.getDialogPane().setContent(gp);
            // focus title
            Platform.runLater(titleField::requestFocus);

            dlg.setResultConverter(bt -> bt == saveBtn ? saveBtn : null);
            var res = dlg.showAndWait();
            if (res.isPresent() && res.get() == saveBtn) {
                int m = minutesSpinner.getValue();
                if (m <= 0) m = 1;
                entryDatePicker.setValue(LocalDate.now());
                entryDurationField.setText(String.valueOf(m));
                entryTitleField.setText(titleField.getText() == null || titleField.getText().isBlank()
                        ? "Sessão contabilizada — " + m + " min" : titleField.getText());
                saveCurrentEntry();
                loadEntries();
            }
        }
        timerSeconds.set(0); updateTimerLabel();
    }

    private void tick() {
        timerSeconds.incrementAndGet();
        Platform.runLater(this::updateTimerLabel);
    }

    private void updateTimerLabel() {
        long s = timerSeconds.get();
        long hh = s / 3600; long mm = (s % 3600) / 60; long ss = s % 60;
        timerLabel.setText(String.format("%02d:%02d:%02d", hh, mm, ss));
        // update shared context indicator when diary is minimized or not focused
        try {
            if (sharedCtx != null && timerRunning && stage != null) {
                boolean show = false;
                try { show = stage.isIconified() || !stage.isFocused(); } catch (Exception ex) { show = stage.isIconified(); }
                if (show) sharedCtx.activeStudySessionLabel.setText("Sessão: " + timerLabel.getText());
                else sharedCtx.activeStudySessionLabel.setText("");
            }
        } catch (Throwable ignored) { }
    }

    private void playTone(int freq, int ms) {
        playSignal("tone");
    }

    private void playSignal(String name) {
        if (soundExecutor == null) return;
        soundExecutor.submit(() -> {
            boolean played = false;
            // helper to report status messages to user
            java.util.function.Consumer<String> report = msg -> {
                try { if (sharedCtx != null) sharedCtx.setStatus(msg); } catch (Throwable ignored) {}
            };

            // Attempt 1: play packaged WAV resource
            try {
                String res = "/sounds/" + name + ".wav";
                java.net.URL url = StudyDiaryWindow.class.getResource(res);
                if (url != null) {
                    try (AudioInputStream ais = AudioSystem.getAudioInputStream(url)) {
                        Clip clip = AudioSystem.getClip();
                        clip.open(ais);
                        final Object lock = new Object();
                        clip.addLineListener(event -> {
                            if (event.getType() == LineEvent.Type.STOP) {
                                clip.close(); synchronized(lock) { lock.notifyAll(); }
                            }
                        });
                        clip.start();
                        synchronized(lock) { lock.wait(1500); }
                        played = true;
                    }
                }
            } catch (Throwable ex) {
                System.err.println("[StudyDiaryWindow] failed playing resource WAV: " + ex.getMessage());
            }

            if (!played) {
                // Attempt 2: embedded generated tone
                try (AudioInputStream ais = EmbeddedSounds.getAudioInputStream(name)) {
                    if (ais != null) {
                        try {
                            Clip clip = AudioSystem.getClip();
                            clip.open(ais);
                            final Object lock = new Object();
                            clip.addLineListener(event -> {
                                if (event.getType() == LineEvent.Type.STOP) {
                                    clip.close(); synchronized(lock) { lock.notifyAll(); }
                                }
                            });
                            clip.start();
                            synchronized(lock) { lock.wait(1500); }
                            played = true;
                        } catch (Throwable ex) {
                            System.err.println("[StudyDiaryWindow] failed playing embedded tone: " + ex.getMessage());
                        }
                    }
                } catch (Throwable ex) {
                    System.err.println("[StudyDiaryWindow] error obtaining embedded audio: " + ex.getMessage());
                }
            }

            if (!played) {
                // Attempt 3: invoke system audio player (aplay, paplay, play) by writing resource to temp file
                try {
                    java.net.URL url = StudyDiaryWindow.class.getResource("/sounds/" + name + ".wav");
                    java.io.File tmp = java.io.File.createTempFile("agenda-sound-", ".wav");
                    tmp.deleteOnExit();
                    boolean wrote = false;
                    if (url != null) {
                        try (java.io.InputStream is = url.openStream(); java.io.FileOutputStream fos = new java.io.FileOutputStream(tmp)) {
                            byte[] buf = new byte[4096]; int r; while ((r = is.read(buf)) > 0) fos.write(buf, 0, r);
                            wrote = true;
                        } catch (Throwable ex) { System.err.println("[StudyDiaryWindow] failed writing resource to temp file: " + ex.getMessage()); }
                    }
                    if (!wrote) {
                        // try embedded tone
                        try (AudioInputStream eis = EmbeddedSounds.getAudioInputStream(name); java.io.FileOutputStream fos = new java.io.FileOutputStream(tmp)) {
                            if (eis != null) {
                                byte[] buf = new byte[4096]; int r; while ((r = eis.read(buf)) > 0) fos.write(buf, 0, r);
                                wrote = true;
                            }
                        } catch (Throwable ex) { System.err.println("[StudyDiaryWindow] failed writing embedded to temp file: " + ex.getMessage()); }
                    }
                    if (wrote) {
                        String[] candidates = new String[]{"aplay", "paplay", "play"};
                        String player = null;
                        for (String c : candidates) {
                            try { if (java.lang.Runtime.getRuntime().exec(new String[]{"which", c}).waitFor() == 0) { player = c; break; } } catch (Throwable ignore) {}
                        }
                        if (player != null) {
                            try {
                                Process p = new ProcessBuilder(player, tmp.getAbsolutePath()).start();
                                if (!p.waitFor(1500, java.util.concurrent.TimeUnit.MILLISECONDS)) p.destroy();
                                played = true;
                            } catch (Throwable ex) { System.err.println("[StudyDiaryWindow] native player failed: " + ex.getMessage()); }
                        }
                    }
                } catch (Throwable ex) {
                    System.err.println("[StudyDiaryWindow] native player fallback error: " + ex.getMessage());
                }

                // final fallback: system beep
                if (!played) {
                    try {
                        Toolkit.getDefaultToolkit().beep();
                        played = true;
                    } catch (Throwable ex) {
                        System.err.println("[StudyDiaryWindow] final fallback beep failed: " + ex.getMessage());
                    }
                }
            }

            if (!played) {
                report.accept("Áudio: não foi possível reproduzir nenhum sinal (verifique drivers/ALSA/PulseAudio)");
            } else {
                report.accept("Áudio: sinal reproduzido");
            }
        });
    }

    // ══════════════════════════════════════════════════════════════════════
    // COLAR SEM FORMATAÇÃO
    // ══════════════════════════════════════════════════════════════════════

    /**
     * Cola o conteúdo da área de transferência como texto puro no ponto de
     * inserção do editor, usando {@code document.execCommand('insertText')}.
     * Isso remove qualquer formatação HTML proveniente de sites ou outros editores.
     */
    private void pasteAsPlainText() {
        Clipboard cb = Clipboard.getSystemClipboard();
        String plain = cb.getString();
        if (plain == null || plain.isEmpty()) return;

        // Obter o WebView interno do HTMLEditor via lookup CSS
        WebView webView = (WebView) richEditor.lookup(".web-view");
        if (webView == null) return;

        // Escapar caracteres perigosos para JS e preservar quebras de linha
        String safe = plain
                .replace("\\", "\\\\")
                .replace("'",  "\\'")
                .replace("\r\n", "\\n")
                .replace("\n",  "\\n")
                .replace("\r",  "\\n");

        webView.getEngine().executeScript(
                "document.execCommand('insertText', false, '" + safe + "')");
    }

    // ══════════════════════════════════════════════════════════════════════
    // ATUALIZAÇÃO DE PROGRESSO
    // ══════════════════════════════════════════════════════════════════════

    private void updateBookProgress() {
        int curPage  = parseInt(currentPageField.getText());
        int totPages = parseInt(totalPagesField.getText());
        if (totPages <= 0) return;
        double pct = Math.min(100.0, curPage * 100.0 / totPages);
        StudyPlanStatus status = pct >= 100.0 ? StudyPlanStatus.CONCLUIDO : StudyPlanStatus.EM_ANDAMENTO;
        planRepo.updateProgressFull(currentPlan.id(), curPage, totPages, pct, status);
        reloadCurrentPlan(); refreshProgressUI();
        if (refreshCallback != null) refreshCallback.run();
    }

    private void updateManualProgress() {
        double pct = progressSlider.getValue();
        StudyPlanStatus status = pct >= 100.0 ? StudyPlanStatus.CONCLUIDO : StudyPlanStatus.EM_ANDAMENTO;
        planRepo.updateProgress(currentPlan.id(), currentPlan.currentPage(), pct, status);
        reloadCurrentPlan(); refreshProgressUI();
        if (refreshCallback != null) refreshCallback.run();
    }

    private void reloadCurrentPlan() {
        currentPlan = planRepo.findById(currentPlan.id()).orElse(currentPlan);
    }

    private void refreshProgressUI() {
        headerProgressBar.setProgress(currentPlan.computedProgress() / 100.0);
        headerProgressLabel.setText(currentPlan.progressDisplay());
        headerDatesLabel.setText(buildDatesString());
        refreshHeaderStats();
    }

    // ══════════════════════════════════════════════════════════════════════
    // HELPERS
    // ══════════════════════════════════════════════════════════════════════

    private String buildDatesString() {
        DateTimeFormatter fmt = DateTimeFormatter.ofPattern("dd/MM/yyyy", Locale.forLanguageTag("pt-BR"));
        StringBuilder sb = new StringBuilder();
        if (currentPlan.startDate()  != null) sb.append("Início: ").append(currentPlan.startDate().format(fmt));
        if (currentPlan.targetDate() != null) {
            if (!sb.isEmpty()) sb.append("     ");
            sb.append("Prazo: ").append(currentPlan.targetDate().format(fmt));
            long days = currentPlan.daysUntilTarget();
            if (days >= 0) sb.append("  (").append(days).append(" dias restantes)");
            else           sb.append("  ⚠ PRAZO VENCIDO há ").append(-days).append(" dias");
        }
        return sb.isEmpty() ? "Sem datas definidas" : sb.toString();
    }

    private static int parseInt(String s) {
        try { return Integer.parseInt(s.trim()); } catch (Exception e) { return 0; }
    }
}

package com.pessoal.agenda.ui.view;

import com.pessoal.agenda.app.AppContextHolder;
import com.pessoal.agenda.model.*;
import com.pessoal.agenda.model.AttendanceDay.AttendanceStatus;
import com.pessoal.agenda.service.StudyAttendanceService.Summary;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.*;
import javafx.stage.Modality;
import javafx.stage.Stage;

import java.time.DayOfWeek;
import java.time.LocalDate;
import java.time.YearMonth;
import java.time.format.DateTimeFormatter;
import java.time.format.TextStyle;
import java.util.List;
import java.util.Locale;

/**
 * Janela de Monitor de Frequência de Estudo.
 *
 * Painel:
 *   TOP    – KPIs: dias programados, presença, faltas, déficit de horas
 *   CENTER – Calendário dos últimos 8 semanas + semana atual
 *   BOTTOM – Painel de compensações pendentes
 */
public class StudyMonitorWindow {

    // No single-instance registry: allow multiple monitor windows per plan (reverted).
    private static final DateTimeFormatter MONTH_FMT =
            DateTimeFormatter.ofPattern("MMMM yyyy", Locale.forLanguageTag("pt-BR"));
    private static final DateTimeFormatter DAY_FMT =
            DateTimeFormatter.ofPattern("dd/MM/yyyy");

    private final StudyPlan plan;
    private final Runnable  onClose;

    // navegação de mês
    private YearMonth currentMonth;
    private GridPane  calendarGrid;
    private Label     monthLabel;

    // compensações
    private VBox compensationPanel;

    public StudyMonitorWindow(StudyPlan plan, Runnable onClose) {
        this.plan         = plan;
        this.onClose      = onClose;
        this.currentMonth = YearMonth.now();
    }

    public void show() {
        // Always create a new stage for the monitor window (reverted behavior).
        Stage stage = new Stage();
        stage.setTitle("  Monitor de Frequência — " + plan.title());
        stage.setMinWidth(860); stage.setMinHeight(640);
        stage.initModality(Modality.NONE);

        BorderPane root = new BorderPane();
        root.getStyleClass().add("app-root");
        root.setTop(buildHeader());
        root.setCenter(buildCenter());

        Scene scene = new Scene(root, 980, 720);
        var css = StudyMonitorWindow.class.getResource("/com/pessoal/agenda/app.css");
        if (css != null) scene.getStylesheets().add(css.toExternalForm());

        stage.setScene(scene);
        stage.setOnHiding(e -> { if (onClose != null) onClose.run(); });
        stage.show();
    }

    // ── Header ────────────────────────────────────────────────────────────

    private VBox buildHeader() {
        Label title = new Label("  " + plan.title());
        title.getStyleClass().add("page-title");

        Label sub = new Label("Monitor de Frequência  ·  " + plan.studyTypeName()
                + "  ·  " + plan.status().label());
        sub.getStyleClass().add("page-subtitle");

        VBox hdr = new VBox(2, title, sub);
        hdr.setPadding(new Insets(12, 16, 12, 16));
        hdr.getStyleClass().add("header-bar");
        return hdr;
    }

    // ── Centro ────────────────────────────────────────────────────────────

    private SplitPane buildCenter() {
        VBox leftSide  = buildCalendarSide();
        VBox rightSide = buildCompensationSide();
        // Garante largura mínima do painel direito para evitar truncamento dos rótulos dos botões
        rightSide.setMinWidth(320);
        rightSide.setPrefWidth(360);
        SplitPane split = new SplitPane(leftSide, rightSide);
        split.setDividerPositions(0.65);
        return split;
    }

    // ── Lado esquerdo: calendário ─────────────────────────────────────────

    private VBox buildCalendarSide() {
        // KPI bar
        HBox kpiBar = buildKpiBar();

        // navegação de mês
        Button prevBtn = new Button("◀"); prevBtn.getStyleClass().add("secondary-button");
        Button nextBtn = new Button("▶"); nextBtn.getStyleClass().add("secondary-button");
        monthLabel = new Label();
        monthLabel.getStyleClass().add("section-title");
        monthLabel.setMinWidth(200);
        monthLabel.setAlignment(Pos.CENTER);

        prevBtn.setOnAction(e -> { currentMonth = currentMonth.minusMonths(1); rebuildCalendar(); });
        nextBtn.setOnAction(e -> { currentMonth = currentMonth.plusMonths(1); rebuildCalendar(); });

        HBox navBar = new HBox(8, prevBtn, monthLabel, nextBtn);
        navBar.setAlignment(Pos.CENTER);
        navBar.setPadding(new Insets(4, 0, 4, 0));

        // Cabeçalho dos dias da semana
        HBox weekHeader = new HBox(4);
        weekHeader.setAlignment(Pos.CENTER);
        for (DayOfWeek d : DayOfWeek.values()) {
            Label lbl = new Label(StudyScheduleDay.shortLabel(d));
            lbl.getStyleClass().add("calendar-week-header");
            lbl.setPrefWidth(44);
            lbl.setAlignment(Pos.CENTER);
            weekHeader.getChildren().add(lbl);
        }

        calendarGrid = new GridPane();
        calendarGrid.setHgap(4); calendarGrid.setVgap(4);
        calendarGrid.setAlignment(Pos.TOP_CENTER);
        rebuildCalendar();

        ScrollPane scroll = new ScrollPane(calendarGrid);
        scroll.setFitToWidth(true); scroll.setFitToHeight(false);
        scroll.getStyleClass().add("edge-to-edge");
        VBox.setVgrow(scroll, Priority.ALWAYS);

        // Legenda
        HBox legend = buildLegend();

        VBox side = new VBox(10, kpiBar, navBar, weekHeader, scroll, legend);
        side.setPadding(new Insets(12));
        side.getStyleClass().add("section-card");
        return side;
    }

    private void rebuildCalendar() {
        calendarGrid.getChildren().clear();
        monthLabel.setText(currentMonth.format(MONTH_FMT).substring(0, 1).toUpperCase()
                + currentMonth.format(MONTH_FMT).substring(1));

        LocalDate first = currentMonth.atDay(1);
        LocalDate last  = currentMonth.atEndOfMonth();

        // Busca intervalo (mês completo)
        List<AttendanceDay> days = AppContextHolder.get().studyAttendanceService()
                .getCalendar(plan.id(), first, last);
        java.util.Map<LocalDate, AttendanceDay> byDate = new java.util.HashMap<>();
        days.forEach(d -> byDate.put(d.date(), d));

        // Preenche a grade: linha 0 = semana 1...
        int col = first.getDayOfWeek().getValue() - 1; // 0=Seg
        int row = 0;
        for (LocalDate d = first; !d.isAfter(last); d = d.plusDays(1)) {
            AttendanceDay ad = byDate.get(d);
            // Não considerar dias anteriores à data de início do plano como ausências;
            // tratá-los como não programados para evitar mostrar faltas históricas.
            if (plan.startDate() != null && d.isBefore(plan.startDate())) {
                ad = null;
            }
            VBox cell = buildDayCell(d, ad);
            calendarGrid.add(cell, col, row);
            col++;
            if (col == 7) { col = 0; row++; }
        }
    }

    private VBox buildDayCell(LocalDate date, AttendanceDay ad) {
        Label numLbl = new Label(String.valueOf(date.getDayOfMonth()));
        numLbl.getStyleClass().add("calendar-day-num");

        Label symLbl = new Label(ad != null ? ad.status().symbol : "–");
        symLbl.getStyleClass().add("calendar-day-sym");

        VBox cell = new VBox(2, numLbl, symLbl);
        cell.setAlignment(Pos.CENTER);
        cell.setPrefSize(44, 44);
        cell.getStyleClass().add("calendar-day");
        if (ad != null) cell.getStyleClass().add(ad.status().cssClass);
        if (date.equals(LocalDate.now())) cell.getStyleClass().add("calendar-today");

        // Tooltip detalhado
        if (ad != null && ad.status() != AttendanceStatus.NAO_PROGRAMADO) {
            String tip = date.format(DAY_FMT) + "\n"
                    + "Programado: " + fmt(ad.scheduledMinutes()) + "\n"
                    + "Realizado:  " + fmt(ad.actualMinutes());
            Tooltip.install(cell, new Tooltip(tip));
        }
        return cell;
    }

    private HBox buildLegend() {
        HBox box = new HBox(12);
        box.setAlignment(Pos.CENTER_LEFT);
        box.setPadding(new Insets(6, 0, 0, 0));
        for (AttendanceStatus s : AttendanceStatus.values()) {
            if (s == AttendanceStatus.NAO_PROGRAMADO) continue;
            Label sym = new Label(s.symbol + " " + s.name().replace("_", " ").toLowerCase());
            sym.getStyleClass().addAll("calendar-legend", s.cssClass);
            box.getChildren().add(sym);
        }
        return box;
    }

    // ── KPI bar ───────────────────────────────────────────────────────────

    private HBox buildKpiBar() {
        LocalDate from = currentMonth.atDay(1);
        LocalDate to   = currentMonth.atEndOfMonth();
        Summary sum = AppContextHolder.get().studyAttendanceService()
                .getSummary(plan.id(), from, to);

        HBox bar = new HBox(10,
            kpi("Programados", String.valueOf(sum.scheduledDays()), "kpi-blue"),
            kpi("Presença", String.format("%.0f%%", sum.presenceRate()), "kpi-green"),
            kpi("Ausências", String.valueOf(sum.absentDays()), "kpi-orange"),
            kpi("Déficit", fmt(sum.deficitMinutes()), "kpi-red"));
        bar.setAlignment(Pos.CENTER_LEFT);
        return bar;
    }

    // ── Lado direito: compensações ────────────────────────────────────────

    private VBox buildCompensationSide() {
        Label title = new Label("Compensações Pendentes");
        title.getStyleClass().add("section-title");

        Button detectBtn = new Button("");
        detectBtn.getStyleClass().addAll("icon-button");
        detectBtn.setTooltip(new Tooltip("Detectar ausências"));
        detectBtn.setOnAction(e -> detectAndRegisterAbsences());

        compensationPanel = new VBox(8);
        VBox.setVgrow(compensationPanel, Priority.ALWAYS);
        refreshCompensations();

        ScrollPane scroll = new ScrollPane(compensationPanel);
        scroll.setFitToWidth(true);
        scroll.getStyleClass().add("edge-to-edge");
        VBox.setVgrow(scroll, Priority.ALWAYS);

        VBox side = new VBox(10, title, detectBtn, scroll);
        side.setPadding(new Insets(12));
        side.getStyleClass().add("section-card");
        return side;
    }

    private void refreshCompensations() {
        compensationPanel.getChildren().clear();
        var comps = AppContextHolder.get().studyCompensationRepository()
                .findByStudyId(plan.id());
        if (comps.isEmpty()) {
            Label empty = new Label("Nenhuma compensação registrada.");
            empty.getStyleClass().add("study-dates-label");
            compensationPanel.getChildren().add(empty);
            return;
        }
        for (StudyCompensation c : comps) {
            compensationPanel.getChildren().add(buildCompCard(c));
        }
    }

    private VBox buildCompCard(StudyCompensation c) {
        Label dateLbl = new Label("Falta: " + c.missedDate().format(DAY_FMT));
        dateLbl.getStyleClass().add("form-label");

        Label statusLbl = new Label(c.status());
        statusLbl.getStyleClass().addAll("study-badge",
                "PENDENTE".equals(c.status())  ? "badge-status-em_andamento" :
                "CONCLUIDA".equals(c.status()) ? "badge-status-concluido"    :
                                                  "badge-status-abandonado");

        Label minLbl = new Label(fmt(c.compensationMinutes()) + " a compensar");
        minLbl.getStyleClass().add("study-dates-label");

        HBox topRow = new HBox(8, dateLbl, statusLbl, minLbl);
        topRow.setAlignment(Pos.CENTER_LEFT);

        VBox card = new VBox(6, topRow);
        card.getStyleClass().add("comp-card");
        card.setPadding(new Insets(8, 10, 8, 10));

        if (c.isPending()) {
            DatePicker dp = new DatePicker(LocalDate.now());
            dp.getStyleClass().add("input-control");
            dp.setPromptText("Data de compensação");

            Button doneBtn = new Button("✓");
            doneBtn.getStyleClass().addAll("icon-button");
            doneBtn.setTooltip(new Tooltip("Marcar compensação como concluída"));
            doneBtn.setOnAction(e -> {
                if (dp.getValue() == null) return;
                AppContextHolder.get().studyCompensationRepository()
                        .markDone(c.id(), dp.getValue(), null);
                refreshCompensations();
                rebuildCalendar();
            });

            Button cancelBtn = new Button("✕");
            cancelBtn.getStyleClass().addAll("icon-button", "danger-button");
            cancelBtn.setTooltip(new Tooltip("Cancelar compensação"));
            cancelBtn.setOnAction(e -> {
                AppContextHolder.get().studyCompensationRepository().cancel(c.id());
                refreshCompensations();
            });

            HBox actions = new HBox(8, new Label("Compensar em:"), dp, doneBtn, cancelBtn);
            actions.setAlignment(Pos.CENTER_LEFT);
            card.getChildren().add(actions);
        } else if (c.isDone() && c.compensationDate() != null) {
            Label doneLbl = new Label("Compensado em: " + c.compensationDate().format(DAY_FMT));
            doneLbl.getStyleClass().add("study-dates-label");
            card.getChildren().add(doneLbl);
        }
        return card;
    }

    private void detectAndRegisterAbsences() {
        // Não detectar ausências anteriores à data de início do plano.
        LocalDate monthStart = currentMonth.atDay(1);
        LocalDate planStart  = plan.startDate();
        // Iniciar a detecção a partir da data de início do plano, mas nunca antes do início do mês
        // atual — isto evita registros históricos muito antigos por erro de data.
        LocalDate from;
        if (planStart != null) {
            from = planStart.isAfter(monthStart) ? planStart : monthStart;
        } else {
            from = monthStart;
        }
        LocalDate to   = LocalDate.now().isBefore(currentMonth.atEndOfMonth())
                       ? LocalDate.now() : currentMonth.atEndOfMonth();
        var svc = AppContextHolder.get().studyAttendanceService();
        var repo = AppContextHolder.get().studyCompensationRepository();
        var schedule = AppContextHolder.get().studyScheduleRepository()
                .findByStudyId(plan.id());
        java.util.Map<DayOfWeek, Integer> minByDay = new java.util.HashMap<>();
        schedule.forEach(s -> minByDay.put(s.dayOfWeek(), s.minMinutes()));

        List<LocalDate> missing = svc.getUnregisteredAbsences(plan.id(), from, to);
        if (missing.isEmpty()) {
            showInfo("Nenhuma ausência nova detectada no período.");
            return;
        }

        // Se foram detectadas múltiplas ausências, pedir confirmação ao usuário
        if (missing.size() > 1) {
            Alert confirm = new Alert(Alert.AlertType.CONFIRMATION);
            confirm.setTitle("Confirmar registro de ausências");
            confirm.setHeaderText("Foram detectadas " + missing.size() + " ausências.");
            confirm.setContentText("Deseja registrar automaticamente estas ausências como compensações?");

            // lista detalhada (expandable)
            StringBuilder sb = new StringBuilder();
            for (LocalDate d : missing) sb.append(d.format(DAY_FMT)).append('\n');
            TextArea details = new TextArea(sb.toString());
            details.setEditable(false);
            details.setWrapText(true);
            details.setMaxWidth(Double.MAX_VALUE);
            details.setMaxHeight(240);
            confirm.getDialogPane().setExpandableContent(details);
            confirm.getDialogPane().setExpanded(false);

            var opt = confirm.showAndWait();
            if (opt.isEmpty() || opt.get() != ButtonType.OK) {
                showInfo("Operação cancelada pelo usuário.");
                return;
            }
        }

        for (LocalDate d : missing) {
            int sched = minByDay.getOrDefault(d.getDayOfWeek(), 30);
            repo.save(plan.id(), d, sched, null);
        }
        refreshCompensations();
        showInfo(missing.size() + " ausência(s) registrada(s) automaticamente.");
    }

    // ── helpers ───────────────────────────────────────────────────────────

    private static VBox kpi(String label, String value, String styleClass) {
        Label v = new Label(value); v.getStyleClass().addAll("kpi-value", styleClass + "-value");
        Label l = new Label(label); l.getStyleClass().add("kpi-title");
        VBox box = new VBox(2, v, l);
        box.getStyleClass().addAll("kpi-mini", styleClass);
        box.setPadding(new Insets(6, 12, 6, 12));
        return box;
    }

    private static String fmt(int totalMinutes) {
        if (totalMinutes <= 0) return "0 min";
        int h = totalMinutes / 60, m = totalMinutes % 60;
        return h > 0 ? h + "h" + (m > 0 ? " " + m + "min" : "") : m + "min";
    }

    private static void showInfo(String msg) {
        Alert a = new Alert(Alert.AlertType.INFORMATION);
        a.setHeaderText(null);
        a.setContentText(msg);
        a.showAndWait();
    }
}

package com.pessoal.agenda.ui.view;

import com.pessoal.agenda.app.AppContextHolder;
import com.pessoal.agenda.model.*;
import com.pessoal.agenda.model.AttendanceDay.AttendanceStatus;
import com.pessoal.agenda.service.StudyAttendanceService.Summary;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.*;
import javafx.stage.Modality;
import javafx.stage.Stage;

import java.time.DayOfWeek;
import java.time.LocalDate;
import java.time.YearMonth;
import java.time.format.DateTimeFormatter;
import java.time.format.TextStyle;
import java.util.List;
import java.util.Locale;

/**
 * Janela de Monitor de Frequência de Estudo.
 *
 * Painel:
 *   TOP    – KPIs: dias programados, presença, faltas, déficit de horas
 *   CENTER – Calendário dos últimos 8 semanas + semana atual
 *   BOTTOM – Painel de compensações pendentes
 */
public class StudyMonitorWindow {

    // No single-instance registry: allow multiple monitor windows per plan (reverted).
    private static final DateTimeFormatter MONTH_FMT =
            DateTimeFormatter.ofPattern("MMMM yyyy", Locale.forLanguageTag("pt-BR"));
    private static final DateTimeFormatter DAY_FMT =
            DateTimeFormatter.ofPattern("dd/MM/yyyy");

    private final StudyPlan plan;
    private final Runnable  onClose;

    // navegação de mês
    private YearMonth currentMonth;
    private GridPane  calendarGrid;
    private Label     monthLabel;

    // compensações
    private VBox compensationPanel;

    public StudyMonitorWindow(StudyPlan plan, Runnable onClose) {
        this.plan         = plan;
        this.onClose      = onClose;
        this.currentMonth = YearMonth.now();
    }

    public void show() {
        // Always create a new stage for the monitor window (reverted behavior).
        Stage stage = new Stage();
        stage.setTitle("  Monitor de Frequência — " + plan.title());
        stage.setMinWidth(860); stage.setMinHeight(640);
        stage.initModality(Modality.NONE);

        BorderPane root = new BorderPane();
        root.getStyleClass().add("app-root");
        root.setTop(buildHeader());
        root.setCenter(buildCenter());

        Scene scene = new Scene(root, 980, 720);
        ThemeManager.getInstance().applyTo(scene);

        stage.setScene(scene);
        stage.setOnHiding(e -> { if (onClose != null) onClose.run(); });
        stage.show();
    }

    // ── Header ────────────────────────────────────────────────────────────

    private VBox buildHeader() {
        Label title = new Label("  " + plan.title());
        title.getStyleClass().add("page-title");

        Label sub = new Label("Monitor de Frequência  ·  " + plan.studyTypeName()
                + "  ·  " + plan.status().label());
        sub.getStyleClass().add("page-subtitle");

        VBox hdr = new VBox(2, title, sub);
        hdr.setPadding(new Insets(12, 16, 12, 16));
        hdr.getStyleClass().add("header-bar");
        return hdr;
    }

    // ── Centro ────────────────────────────────────────────────────────────

    private SplitPane buildCenter() {
        VBox leftSide  = buildCalendarSide();
        VBox rightSide = buildCompensationSide();
        // Garante largura mínima do painel direito para evitar truncamento dos rótulos dos botões
        rightSide.setMinWidth(320);
        rightSide.setPrefWidth(360);
        SplitPane split = new SplitPane(leftSide, rightSide);
        split.setDividerPositions(0.65);
        return split;
    }

    // ── Lado esquerdo: calendário ─────────────────────────────────────────

    private VBox buildCalendarSide() {
        // KPI bar
        HBox kpiBar = buildKpiBar();

        // navegação de mês
        Button prevBtn = new Button("◀"); prevBtn.getStyleClass().add("secondary-button");
        Button nextBtn = new Button("▶"); nextBtn.getStyleClass().add("secondary-button");
        monthLabel = new Label();
        monthLabel.getStyleClass().add("section-title");
        monthLabel.setMinWidth(200);
        monthLabel.setAlignment(Pos.CENTER);

        prevBtn.setOnAction(e -> { currentMonth = currentMonth.minusMonths(1); rebuildCalendar(); });
        nextBtn.setOnAction(e -> { currentMonth = currentMonth.plusMonths(1); rebuildCalendar(); });

        HBox navBar = new HBox(8, prevBtn, monthLabel, nextBtn);
        navBar.setAlignment(Pos.CENTER);
        navBar.setPadding(new Insets(4, 0, 4, 0));

        // Cabeçalho dos dias da semana
        HBox weekHeader = new HBox(4);
        weekHeader.setAlignment(Pos.CENTER);
        for (DayOfWeek d : DayOfWeek.values()) {
            Label lbl = new Label(StudyScheduleDay.shortLabel(d));
            lbl.getStyleClass().add("calendar-week-header");
            lbl.setPrefWidth(44);
            lbl.setAlignment(Pos.CENTER);
            weekHeader.getChildren().add(lbl);
        }

        calendarGrid = new GridPane();
        calendarGrid.setHgap(4); calendarGrid.setVgap(4);
        calendarGrid.setAlignment(Pos.TOP_CENTER);
        rebuildCalendar();

        ScrollPane scroll = new ScrollPane(calendarGrid);
        scroll.setFitToWidth(true); scroll.setFitToHeight(false);
        scroll.getStyleClass().add("edge-to-edge");
        VBox.setVgrow(scroll, Priority.ALWAYS);

        // Legenda
        HBox legend = buildLegend();

        VBox side = new VBox(10, kpiBar, navBar, weekHeader, scroll, legend);
        side.setPadding(new Insets(12));
        side.getStyleClass().add("section-card");
        return side;
    }

    private void rebuildCalendar() {
        calendarGrid.getChildren().clear();
        monthLabel.setText(currentMonth.format(MONTH_FMT).substring(0, 1).toUpperCase()
                + currentMonth.format(MONTH_FMT).substring(1));

        LocalDate first = currentMonth.atDay(1);
        LocalDate last  = currentMonth.atEndOfMonth();

        // Busca intervalo (mês completo)
        List<AttendanceDay> days = AppContextHolder.get().studyAttendanceService()
                .getCalendar(plan.id(), first, last);
        java.util.Map<LocalDate, AttendanceDay> byDate = new java.util.HashMap<>();
        days.forEach(d -> byDate.put(d.date(), d));

        // Preenche a grade: linha 0 = semana 1...
        int col = first.getDayOfWeek().getValue() - 1; // 0=Seg
        int row = 0;
        for (LocalDate d = first; !d.isAfter(last); d = d.plusDays(1)) {
            AttendanceDay ad = byDate.get(d);
            // Não considerar dias anteriores à data de início do plano como ausências;
            // tratá-los como não programados para evitar mostrar faltas históricas.
            if (plan.startDate() != null && d.isBefore(plan.startDate())) {
                ad = null;
            }
            VBox cell = buildDayCell(d, ad);
            calendarGrid.add(cell, col, row);
            col++;
            if (col == 7) { col = 0; row++; }
        }
    }

    private VBox buildDayCell(LocalDate date, AttendanceDay ad) {
        Label numLbl = new Label(String.valueOf(date.getDayOfMonth()));
        numLbl.getStyleClass().add("calendar-day-num");

        Label symLbl = new Label(ad != null ? ad.status().symbol : "–");
        symLbl.getStyleClass().add("calendar-day-sym");

        VBox cell = new VBox(2, numLbl, symLbl);
        cell.setAlignment(Pos.CENTER);
        cell.setPrefSize(44, 44);
        cell.getStyleClass().add("calendar-day");
        if (ad != null) cell.getStyleClass().add(ad.status().cssClass);
        if (date.equals(LocalDate.now())) cell.getStyleClass().add("calendar-today");

        // Tooltip detalhado
        if (ad != null && ad.status() != AttendanceStatus.NAO_PROGRAMADO) {
            String tip = date.format(DAY_FMT) + "\n"
                    + "Programado: " + fmt(ad.scheduledMinutes()) + "\n"
                    + "Realizado:  " + fmt(ad.actualMinutes());
            Tooltip.install(cell, new Tooltip(tip));
        }
        return cell;
    }

    private HBox buildLegend() {
        HBox box = new HBox(12);
        box.setAlignment(Pos.CENTER_LEFT);
        box.setPadding(new Insets(6, 0, 0, 0));
        for (AttendanceStatus s : AttendanceStatus.values()) {
            if (s == AttendanceStatus.NAO_PROGRAMADO) continue;
            Label sym = new Label(s.symbol + " " + s.name().replace("_", " ").toLowerCase());
            sym.getStyleClass().addAll("calendar-legend", s.cssClass);
            box.getChildren().add(sym);
        }
        return box;
    }

    // ── KPI bar ───────────────────────────────────────────────────────────

    private HBox buildKpiBar() {
        LocalDate from = currentMonth.atDay(1);
        LocalDate to   = currentMonth.atEndOfMonth();
        Summary sum = AppContextHolder.get().studyAttendanceService()
                .getSummary(plan.id(), from, to);

        HBox bar = new HBox(10,
            kpi("Programados", String.valueOf(sum.scheduledDays()), "kpi-blue"),
            kpi("Presença", String.format("%.0f%%", sum.presenceRate()), "kpi-green"),
            kpi("Ausências", String.valueOf(sum.absentDays()), "kpi-orange"),
            kpi("Déficit", fmt(sum.deficitMinutes()), "kpi-red"));
        bar.setAlignment(Pos.CENTER_LEFT);
        return bar;
    }

    // ── Lado direito: compensações ────────────────────────────────────────

    private VBox buildCompensationSide() {
        Label title = new Label("Compensações Pendentes");
        title.getStyleClass().add("section-title");

        Button detectBtn = new Button("");
        detectBtn.getStyleClass().addAll("icon-button");
        detectBtn.setTooltip(new Tooltip("Detectar ausências"));
        detectBtn.setOnAction(e -> detectAndRegisterAbsences());

        compensationPanel = new VBox(8);
        VBox.setVgrow(compensationPanel, Priority.ALWAYS);
        refreshCompensations();

        ScrollPane scroll = new ScrollPane(compensationPanel);
        scroll.setFitToWidth(true);
        scroll.getStyleClass().add("edge-to-edge");
        VBox.setVgrow(scroll, Priority.ALWAYS);

        VBox side = new VBox(10, title, detectBtn, scroll);
        side.setPadding(new Insets(12));
        side.getStyleClass().add("section-card");
        return side;
    }

    private void refreshCompensations() {
        compensationPanel.getChildren().clear();
        var comps = AppContextHolder.get().studyCompensationRepository()
                .findByStudyId(plan.id());
        if (comps.isEmpty()) {
            Label empty = new Label("Nenhuma compensação registrada.");
            empty.getStyleClass().add("study-dates-label");
            compensationPanel.getChildren().add(empty);
            return;
        }
        for (StudyCompensation c : comps) {
            compensationPanel.getChildren().add(buildCompCard(c));
        }
    }

    private VBox buildCompCard(StudyCompensation c) {
        Label dateLbl = new Label("Falta: " + c.missedDate().format(DAY_FMT));
        dateLbl.getStyleClass().add("form-label");

        Label statusLbl = new Label(c.status());
        statusLbl.getStyleClass().addAll("study-badge",
                "PENDENTE".equals(c.status())  ? "badge-status-em_andamento" :
                "CONCLUIDA".equals(c.status()) ? "badge-status-concluido"    :
                                                  "badge-status-abandonado");

        Label minLbl = new Label(fmt(c.compensationMinutes()) + " a compensar");
        minLbl.getStyleClass().add("study-dates-label");

        HBox topRow = new HBox(8, dateLbl, statusLbl, minLbl);
        topRow.setAlignment(Pos.CENTER_LEFT);

        VBox card = new VBox(6, topRow);
        card.getStyleClass().add("comp-card");
        card.setPadding(new Insets(8, 10, 8, 10));

        if (c.isPending()) {
            DatePicker dp = new DatePicker(LocalDate.now());
            dp.getStyleClass().add("input-control");
            dp.setPromptText("Data de compensação");

            Button doneBtn = new Button("✓");
            doneBtn.getStyleClass().addAll("icon-button");
            doneBtn.setTooltip(new Tooltip("Marcar compensação como concluída"));
            doneBtn.setOnAction(e -> {
                if (dp.getValue() == null) return;
                AppContextHolder.get().studyCompensationRepository()
                        .markDone(c.id(), dp.getValue(), null);
                refreshCompensations();
                rebuildCalendar();
            });

            Button cancelBtn = new Button("✕");
            cancelBtn.getStyleClass().addAll("icon-button", "danger-button");
            cancelBtn.setTooltip(new Tooltip("Cancelar compensação"));
            cancelBtn.setOnAction(e -> {
                AppContextHolder.get().studyCompensationRepository().cancel(c.id());
                refreshCompensations();
            });

            HBox actions = new HBox(8, new Label("Compensar em:"), dp, doneBtn, cancelBtn);
            actions.setAlignment(Pos.CENTER_LEFT);
            card.getChildren().add(actions);
        } else if (c.isDone() && c.compensationDate() != null) {
            Label doneLbl = new Label("Compensado em: " + c.compensationDate().format(DAY_FMT));
            doneLbl.getStyleClass().add("study-dates-label");
            card.getChildren().add(doneLbl);
        }
        return card;
    }

    private void detectAndRegisterAbsences() {
        // Não detectar ausências anteriores à data de início do plano.
        LocalDate monthStart = currentMonth.atDay(1);
        LocalDate planStart  = plan.startDate();
        // Iniciar a detecção a partir da data de início do plano, mas nunca antes do início do mês
        // atual — isto evita registros históricos muito antigos por erro de data.
        LocalDate from;
        if (planStart != null) {
            from = planStart.isAfter(monthStart) ? planStart : monthStart;
        } else {
            from = monthStart;
        }
        LocalDate to   = LocalDate.now().isBefore(currentMonth.atEndOfMonth())
                       ? LocalDate.now() : currentMonth.atEndOfMonth();
        var svc = AppContextHolder.get().studyAttendanceService();
        var repo = AppContextHolder.get().studyCompensationRepository();
        var schedule = AppContextHolder.get().studyScheduleRepository()
                .findByStudyId(plan.id());
        java.util.Map<DayOfWeek, Integer> minByDay = new java.util.HashMap<>();
        schedule.forEach(s -> minByDay.put(s.dayOfWeek(), s.minMinutes()));

        List<LocalDate> missing = svc.getUnregisteredAbsences(plan.id(), from, to);
        if (missing.isEmpty()) {
            showInfo("Nenhuma ausência nova detectada no período.");
            return;
        }

        // Se foram detectadas múltiplas ausências, pedir confirmação ao usuário
        if (missing.size() > 1) {
            Alert confirm = new Alert(Alert.AlertType.CONFIRMATION);
            confirm.setTitle("Confirmar registro de ausências");
            confirm.setHeaderText("Foram detectadas " + missing.size() + " ausências.");
            confirm.setContentText("Deseja registrar automaticamente estas ausências como compensações?");

            // lista detalhada (expandable)
            StringBuilder sb = new StringBuilder();
            for (LocalDate d : missing) sb.append(d.format(DAY_FMT)).append('\n');
            TextArea details = new TextArea(sb.toString());
            details.setEditable(false);
            details.setWrapText(true);
            details.setMaxWidth(Double.MAX_VALUE);
            details.setMaxHeight(240);
            confirm.getDialogPane().setExpandableContent(details);
            confirm.getDialogPane().setExpanded(false);

            var opt = confirm.showAndWait();
            if (opt.isEmpty() || opt.get() != ButtonType.OK) {
                showInfo("Operação cancelada pelo usuário.");
                return;
            }
        }

        for (LocalDate d : missing) {
            int sched = minByDay.getOrDefault(d.getDayOfWeek(), 30);
            repo.save(plan.id(), d, sched, null);
        }
        refreshCompensations();
        showInfo(missing.size() + " ausência(s) registrada(s) automaticamente.");
    }

    // ── helpers ───────────────────────────────────────────────────────────

    private static VBox kpi(String label, String value, String styleClass) {
        Label v = new Label(value); v.getStyleClass().addAll("kpi-value", styleClass + "-value");
        Label l = new Label(label); l.getStyleClass().add("kpi-title");
        VBox box = new VBox(2, v, l);
        box.getStyleClass().addAll("kpi-mini", styleClass);
        box.setPadding(new Insets(6, 12, 6, 12));
        return box;
    }

    private static String fmt(int totalMinutes) {
        if (totalMinutes <= 0) return "0 min";
        int h = totalMinutes / 60, m = totalMinutes % 60;
        return h > 0 ? h + "h" + (m > 0 ? " " + m + "min" : "") : m + "min";
    }

    private static void showInfo(String msg) {
        Alert a = new Alert(Alert.AlertType.INFORMATION);
        a.setHeaderText(null);
        a.setContentText(msg);
        a.showAndWait();
    }
}

package com.pessoal.agenda.ui.view;

import com.pessoal.agenda.app.AppContextHolder;
import com.pessoal.agenda.model.Task;
import com.pessoal.agenda.model.TaskChecklistItem;
import com.pessoal.agenda.repository.TaskChecklistRepository;
import javafx.application.Platform;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.input.Clipboard;
import javafx.scene.input.ClipboardContent;
import javafx.scene.input.MouseButton;
import javafx.scene.layout.*;
import javafx.stage.Modality;
import javafx.stage.Stage;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

/**
 * Janela dedicada de Checklist/Kanban para Tarefas da Agenda Científica.
 *
 * Modos de visualização:
 *   • Lista  — flat list com filtros (Todos / Pendentes / Concluídos)
 *   • Kanban — board com 4 colunas: Backlog | Em Andamento | Em Revisão | Concluído
 */
public class TaskChecklistWindow {

    // ── Colunas do Kanban ─────────────────────────────────────────────────────
    private static final String[][] KANBAN_COLS = {
        {"backlog",      "  Backlog",       "#546e7a"},
        {"em_andamento", "⚡  Em Andamento",  "#1565c0"},
        {"em_revisao",   "  Em Revisão",    "#7b1fa2"},
        {"concluido",    "✅  Concluído",      "#2e7d32"},
    };

    // ── Prevenção de janela duplicada ─────────────────────────────────────────
    private static final Map<Long, Stage> openWindows = new HashMap<>();

    private final Task task;
    private final TaskChecklistRepository repo;
    private final Runnable onChanged;

    // ── Estado em memória ─────────────────────────────────────────────────────
    private final List<MutableItem> items = new ArrayList<>();

    // ── Modo de visualização ──────────────────────────────────────────────────
    private boolean isKanban = false;

    // ── Filtro de exibição (lista) ────────────────────────────────────────────
    private enum Filter { ALL, PENDING, DONE }
    private Filter currentFilter = Filter.ALL;

    // ── Componentes da UI ─────────────────────────────────────────────────────
    private VBox itemsBox;
    private StackPane contentArea;
    private Label kpiTotal, kpiDone, kpiPending, kpiPercent;
    private ProgressBar progressBar;
    private Label progressLabel;

    // ── Context menu único reutilizável para itens ────────────────────────────
    private final ContextMenu itemContextMenu = new ContextMenu();

    // ── Modelo mutável de item ────────────────────────────────────────────────
    private static class MutableItem {
        long    id;
        String  text;
        boolean done;
        int     position;
        String  kanbanColumn;

        MutableItem(TaskChecklistItem src) {
            this.id           = src.id();
            this.text         = src.text();
            this.done         = src.done();
            this.position     = src.position();
            this.kanbanColumn = src.kanbanColumn() != null ? src.kanbanColumn() : "backlog";
        }
    }

    // ── Construtor ────────────────────────────────────────────────────────────

    public TaskChecklistWindow(Task task, TaskChecklistRepository repo, Runnable onChanged) {
        this.task      = task;
        this.repo      = repo;
        this.onChanged = onChanged;
    }

    // ── Ponto de entrada ──────────────────────────────────────────────────────

    public void show() {
        if (openWindows.containsKey(task.id())) {
            openWindows.get(task.id()).toFront();
            openWindows.get(task.id()).requestFocus();
            return;
        }

        loadItems();

        Stage stage = new Stage();
        stage.initModality(Modality.NONE);
        stage.setTitle("Checklist — " + task.title());
        stage.setMinWidth(660);
        stage.setMinHeight(540);
        openWindows.put(task.id(), stage);
        stage.setOnHidden(e -> openWindows.remove(task.id()));

        VBox root = new VBox(0);
        root.getStylesheets().add(
                getClass().getResource("/com/pessoal/agenda/app.css").toExternalForm());
        root.getStyleClass().add("app-root");

        contentArea = new StackPane();
        VBox.setVgrow(contentArea, Priority.ALWAYS);

        root.getChildren().addAll(
                buildHeader(),
                buildKpiBar(),
                buildProgressSection(),
                buildViewToolbar(),
                contentArea,
                buildFooter(stage)
        );

        refreshContentArea();

        stage.setScene(new Scene(root, 900, 660));
        stage.show();
    }

    // ── Carregamento ──────────────────────────────────────────────────────────

    private void loadItems() {
        items.clear();
        repo.findByTaskId(task.id()).forEach(i -> items.add(new MutableItem(i)));
    }

    // ── Cabeçalho ─────────────────────────────────────────────────────────────

    private HBox buildHeader() {
        Label icon = new Label("☑");
        icon.setStyle("-fx-font-size: 28px; -fx-text-fill: #00b4d8;");

        Label title = new Label("Checklist da Tarefa");
        title.getStyleClass().add("page-title");

        String catText = task.category() != null ? "  ·  " + task.category() : "";
        String prioText = task.priority() != null ? "  ·  " + task.priority().label() : "";
        Label subtitle = new Label(task.title() + catText + prioText);
        subtitle.getStyleClass().add("page-subtitle");

        VBox texts = new VBox(2, title, subtitle);
        Region spacer = new Region();
        HBox.setHgrow(spacer, Priority.ALWAYS);

        String statusLabel = task.status() != null ? task.status().label() : "—";
        Label statusBadge = new Label(statusLabel);
        statusBadge.setStyle(
                "-fx-background-color: #1565c0; -fx-text-fill: white;"
                + " -fx-font-size: 11px; -fx-font-weight: 700;"
                + " -fx-padding: 4 10 4 10; -fx-background-radius: 12;");

        HBox hdr = new HBox(14, icon, texts, spacer, statusBadge);
        hdr.getStyleClass().add("header-bar");
        hdr.setPadding(new Insets(14, 20, 14, 20));
        hdr.setAlignment(Pos.CENTER_LEFT);
        return hdr;
    }

    // ── KPI bar ───────────────────────────────────────────────────────────────

    private HBox buildKpiBar() {
        kpiTotal   = kpiValue("0");
        kpiDone    = kpiValue("0");
        kpiPending = kpiValue("0");
        kpiPercent = kpiValue("0%");

        HBox bar = new HBox(10,
                kpiCard("TOTAL DE ITENS",   kpiTotal,   "kpi-blue"),
                kpiCard("CONCLUÍDOS",       kpiDone,    "kpi-green"),
                kpiCard("PENDENTES",        kpiPending, "kpi-indigo"),
                kpiCard("PROGRESSO",        kpiPercent, "kpi-cyan"));
        bar.setPadding(new Insets(12, 14, 4, 14));
        for (javafx.scene.Node n : bar.getChildren()) HBox.setHgrow(n, Priority.ALWAYS);
        refreshKpiAndProgress();
        return bar;
    }

    private Label kpiValue(String v) {
        Label l = new Label(v); l.getStyleClass().add("kpi-value"); return l;
    }
    private VBox kpiCard(String title, Label value, String cls) {
        Label lbl = new Label(title); lbl.getStyleClass().add("kpi-title");
        VBox c = new VBox(4, lbl, value); c.getStyleClass().addAll("kpi-card", cls); return c;
    }

    // ── Barra de progresso ────────────────────────────────────────────────────

    private VBox buildProgressSection() {
        progressBar = new ProgressBar(0);
        progressBar.setMaxWidth(Double.MAX_VALUE);
        progressBar.setPrefHeight(14);

        progressLabel = new Label("0 de 0 itens concluídos");
        progressLabel.setStyle("-fx-font-size: 11.5px; -fx-text-fill: #5a7a9e;"
                + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");

        VBox section = new VBox(6, progressBar, progressLabel);
        section.setPadding(new Insets(8, 14, 8, 14));
        section.setStyle("-fx-background-color: white;"
                + " -fx-border-color: transparent transparent #dce8f5 transparent;"
                + " -fx-border-width: 0 0 1 0;");
        return section;
    }

    // ── Barra de ferramentas com toggle Lista/Kanban + filtros ─────────────────

    private HBox buildViewToolbar() {
        ToggleGroup viewGroup = new ToggleGroup();
        ToggleButton listBtn   = new ToggleButton("☰  Lista");
        ToggleButton kanbanBtn = new ToggleButton("⬛  Kanban");
        listBtn.setToggleGroup(viewGroup);   listBtn.setSelected(true);
        kanbanBtn.setToggleGroup(viewGroup);
        listBtn.getStyleClass().add("view-toggle-btn");
        kanbanBtn.getStyleClass().add("view-toggle-btn");
        HBox viewToggle = new HBox(2, listBtn, kanbanBtn);
        viewToggle.getStyleClass().add("view-toggle-bar");

        listBtn.setOnAction(e -> {
            if (!listBtn.isSelected()) { listBtn.setSelected(true); return; }
            isKanban = false; refreshContentArea();
        });
        kanbanBtn.setOnAction(e -> {
            if (!kanbanBtn.isSelected()) { kanbanBtn.setSelected(true); return; }
            isKanban = true; refreshContentArea();
        });

        Separator sep = new Separator(javafx.geometry.Orientation.VERTICAL);
        sep.setPadding(new Insets(0, 4, 0, 4));

        ToggleGroup filterGroup = new ToggleGroup();
        ToggleButton allBtn   = filterToggle("Todos",      filterGroup, Filter.ALL);
        ToggleButton pendBtn  = filterToggle("Pendentes",  filterGroup, Filter.PENDING);
        ToggleButton doneBtn  = filterToggle("Concluídos", filterGroup, Filter.DONE);
        allBtn.setSelected(true);
        HBox filterBar = new HBox(2, allBtn, pendBtn, doneBtn);
        filterBar.getStyleClass().add("view-toggle-bar");

        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);

        Button checkAllBtn   = new Button("✔  Marcar Todos");
        Button uncheckAllBtn = new Button("☐  Desmarcar Todos");
        Button clearDoneBtn  = new Button("  Limpar Concluídos");
        checkAllBtn.getStyleClass().add("secondary-button");
        uncheckAllBtn.getStyleClass().add("secondary-button");
        clearDoneBtn.getStyleClass().add("danger-button");
        checkAllBtn.setStyle("-fx-font-size: 11px;");
        uncheckAllBtn.setStyle("-fx-font-size: 11px;");
        clearDoneBtn.setStyle("-fx-font-size: 11px;");
        checkAllBtn.setOnAction(e -> markAll(true));
        uncheckAllBtn.setOnAction(e -> markAll(false));
        clearDoneBtn.setOnAction(e -> clearDoneItems());

        Button addBtn = new Button("＋  Novo Item");
        addBtn.getStyleClass().add("primary-button");
        addBtn.setStyle("-fx-font-size: 11px;");
        addBtn.setOnAction(e -> showAddItemDialog());

        Button printBtn = new Button("  Imprimir");
        printBtn.getStyleClass().add("secondary-button");
        printBtn.setStyle("-fx-font-size: 11px;");
        printBtn.setOnAction(e -> printChecklist());

        HBox bar = new HBox(8, viewToggle, sep, filterBar, spacer,
                checkAllBtn, uncheckAllBtn, clearDoneBtn, printBtn, addBtn);
        bar.setPadding(new Insets(8, 14, 8, 14));
        bar.setAlignment(Pos.CENTER_LEFT);
        bar.setStyle("-fx-background-color: #f2f7fc;"
                + " -fx-border-color: transparent transparent #dce8f5 transparent;"
                + " -fx-border-width: 0 0 1 0;");
        return bar;
    }

    private ToggleButton filterToggle(String label, ToggleGroup tg, Filter filter) {
        ToggleButton btn = new ToggleButton(label);
        btn.setToggleGroup(tg);
        btn.getStyleClass().add("view-toggle-btn");
        btn.setOnAction(e -> {
            if (!btn.isSelected()) { btn.setSelected(true); return; }
            currentFilter = filter;
            if (!isKanban) refreshContentArea();
        });
        return btn;
    }

    // ── Impressão do checklist ────────────────────────────────────────────────

    private void printChecklist() {
        ComboBox<String> dlgItemsFilter = new ComboBox<>();
        dlgItemsFilter.getItems().addAll("Todos os itens", "Apenas Pendentes", "Apenas Concluídos");
        dlgItemsFilter.setValue(switch (currentFilter) {
            case PENDING -> "Apenas Pendentes";
            case DONE    -> "Apenas Concluídos";
            default      -> "Todos os itens";
        });
        dlgItemsFilter.getStyleClass().add("input-control");
        dlgItemsFilter.setMaxWidth(Double.MAX_VALUE);

        ComboBox<String> dlgColFilter = new ComboBox<>();
        dlgColFilter.getItems().add("Todas as colunas");
        for (String[] c : KANBAN_COLS) dlgColFilter.getItems().add(c[1].replace("  ", " ").trim());
        dlgColFilter.setValue("Todas as colunas");
        dlgColFilter.getStyleClass().add("input-control");
        dlgColFilter.setMaxWidth(Double.MAX_VALUE);

        javafx.scene.layout.GridPane grid = new javafx.scene.layout.GridPane();
        grid.setHgap(10); grid.setVgap(8); grid.setPadding(new Insets(10, 0, 0, 0));
        grid.add(new Label("Mostrar:"), 0, 0); grid.add(dlgItemsFilter, 1, 0);
        grid.add(new Label("Coluna:"),  0, 1); grid.add(dlgColFilter,   1, 1);
        javafx.scene.layout.GridPane.setHgrow(dlgItemsFilter, Priority.ALWAYS);
        javafx.scene.layout.GridPane.setHgrow(dlgColFilter,   Priority.ALWAYS);

        Dialog<ButtonType> printDlg = new Dialog<>();
        printDlg.setTitle("Opções de Impressão");
        printDlg.setHeaderText("Checklist — " + task.title());
        printDlg.getDialogPane().setContent(grid);
        printDlg.getDialogPane().setMinWidth(380);
        printDlg.getDialogPane().getButtonTypes().addAll(ButtonType.OK, ButtonType.CANCEL);
        ((Button) printDlg.getDialogPane().lookupButton(ButtonType.OK)).setText(" Gerar Checklist");
        ((Button) printDlg.getDialogPane().lookupButton(ButtonType.CANCEL)).setText("Cancelar");

        var dlgResult = printDlg.showAndWait();
        if (dlgResult.isEmpty() || dlgResult.get() != ButtonType.OK) return;

        String colSel = dlgColFilter.getValue();
        String colKey = "Todas as colunas".equals(colSel) ? null :
                java.util.Arrays.stream(KANBAN_COLS)
                        .filter(c -> c[1].replace("  ", " ").trim().equals(colSel))
                        .map(c -> c[0])
                        .findFirst().orElse(null);

        String itemsSel = dlgItemsFilter.getValue();
        List<TaskChecklistItem> checkItems = items.stream()
                .filter(mi -> switch (itemsSel) {
                    case "Apenas Pendentes"  -> !mi.done;
                    case "Apenas Concluídos" ->  mi.done;
                    default                  -> true;
                })
                .filter(mi -> colKey == null || colKey.equals(mi.kanbanColumn))
                .map(mi -> new TaskChecklistItem(mi.id, task.id(), mi.text, mi.done, mi.position, mi.kanbanColumn))
                .toList();

        String html = com.pessoal.agenda.ui.util.PrintReportService
                .generateTaskChecklistReport(task, checkItems);
        PrintPreviewWindow.open(html, "Checklist — " + task.title());
    }

    // ── Diálogo de adição de item ─────────────────────────────────────────────

    private void showAddItemDialog() {
        TextField field = new TextField();
        field.getStyleClass().add("input-control");
        field.setPromptText("Descreva o passo ou ação...");
        field.setPrefWidth(380);

        ComboBox<String> colCombo = new ComboBox<>();
        colCombo.getStyleClass().add("input-control");
        for (String[] c : KANBAN_COLS) colCombo.getItems().add(c[1].replace("  ", " ").trim());
        colCombo.setValue(KANBAN_COLS[0][1].replace("  ", " ").trim());

        VBox content = new VBox(8,
                new Label("Texto do item:"), field,
                new Label("Coluna inicial:"), colCombo);
        content.setPadding(new Insets(10));

        Dialog<ButtonType> dlg = new Dialog<>();
        dlg.setTitle("Novo Item");
        dlg.setHeaderText("Adicionar item ao checklist da tarefa");
        dlg.getDialogPane().setContent(content);
        dlg.getDialogPane().getButtonTypes().addAll(ButtonType.OK, ButtonType.CANCEL);
        Platform.runLater(field::requestFocus);

        dlg.showAndWait().ifPresent(btn -> {
            if (btn != ButtonType.OK) return;
            String text = field.getText().trim();
            if (text.isBlank()) return;
            int colIdx = colCombo.getSelectionModel().getSelectedIndex();
            String colKey = KANBAN_COLS[Math.max(0, colIdx)][0];
            TaskChecklistItem saved = repo.addItem(task.id(), text);
            if (!"backlog".equals(colKey)) repo.updateColumn(saved.id(), colKey);
            MutableItem mi = new MutableItem(saved);
            mi.kanbanColumn = colKey;
            mi.done = "concluido".equals(colKey);
            items.add(mi);
            refreshAll();
            if (onChanged != null) onChanged.run();
        });
    }

    // ── Área de conteúdo principal ────────────────────────────────────────────

    private void refreshContentArea() {
        if (contentArea == null) return;
        contentArea.getChildren().setAll(isKanban ? buildKanbanView() : buildListView());
    }

    // ──────────────────────────────────────────────────────────────────────────
    // VISTA LISTA
    // ──────────────────────────────────────────────────────────────────────────

    private javafx.scene.Node buildListView() {
        itemsBox = new VBox(0);
        itemsBox.setFillWidth(true);

        ScrollPane sp = new ScrollPane(itemsBox);
        sp.setFitToWidth(true);
        sp.setFitToHeight(false);
        sp.setHbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
        sp.setVbarPolicy(ScrollPane.ScrollBarPolicy.AS_NEEDED);
        sp.getStyleClass().add("edge-to-edge");
        sp.setStyle("-fx-background-color: #f7fbff;");

        refreshItemsUI();
        return sp;
    }

    private void refreshItemsUI() {
        if (itemsBox == null) return;
        itemsBox.getChildren().clear();

        List<MutableItem> visible = items.stream()
                .filter(it -> switch (currentFilter) {
                    case ALL     -> true;
                    case PENDING -> !it.done;
                    case DONE    -> it.done;
                }).toList();

        if (visible.isEmpty()) {
            Label empty = new Label(switch (currentFilter) {
                case PENDING -> "Nenhum item pendente.  Todos os itens foram concluídos!";
                case DONE    -> "Nenhum item concluído ainda.";
                default      -> "Nenhum item no checklist.\nUse o botão ＋ Novo Item para adicionar.";
            });
            empty.setStyle("-fx-text-fill: #9eafc0; -fx-font-size: 12px; -fx-padding: 30 20 30 20;");
            empty.setWrapText(true); empty.setMaxWidth(Double.MAX_VALUE);
            empty.setAlignment(Pos.CENTER);
            itemsBox.getChildren().add(empty);
            return;
        }
        for (int i = 0; i < visible.size(); i++) itemsBox.getChildren().add(buildItemRow(visible.get(i), i));
    }

    private VBox buildItemRow(MutableItem item, int index) {
        CheckBox cb = new CheckBox();
        cb.setSelected(item.done);
        cb.setStyle("-fx-cursor: hand;");

        int globalIdx = items.indexOf(item) + 1;
        Label numLbl = new Label(String.format("%02d", globalIdx));
        numLbl.setStyle("-fx-font-family:'JetBrains Mono','Consolas',monospace;"
                + " -fx-font-size:10px; -fx-text-fill:#9eafc0; -fx-min-width:24px;");

        Label textLbl = new Label(item.text);
        textLbl.setWrapText(true); textLbl.setMaxWidth(Double.MAX_VALUE);
        HBox.setHgrow(textLbl, Priority.ALWAYS);
        applyDoneStyle(textLbl, item.done);

        String colLabel = columnLabel(item.kanbanColumn);
        String colColor = columnColor(item.kanbanColumn);
        Label colBadge = new Label(colLabel);
        colBadge.setStyle("-fx-background-color:" + colColor + "22; -fx-text-fill:" + colColor + ";"
                + " -fx-font-size:9px; -fx-font-weight:700; -fx-padding:2 6 2 6; -fx-background-radius:8;");

        TextField editField = new TextField(item.text);
        editField.getStyleClass().add("input-control");
        editField.setStyle("-fx-font-size:12px;");
        editField.setVisible(false); editField.setManaged(false);
        HBox.setHgrow(editField, Priority.ALWAYS);

        Button editBtn = new Button("✏");
        editBtn.setTooltip(new Tooltip("Editar (duplo clique)"));
        editBtn.setStyle("-fx-background-color:transparent; -fx-text-fill:#5a7a9e;"
                + " -fx-font-size:12px; -fx-cursor:hand; -fx-padding:2 6 2 6; -fx-background-radius:4;");
        editBtn.setOnAction(e -> enterEditMode(textLbl, editField, item, editBtn));

        Button delBtn = new Button("✕");
        delBtn.setTooltip(new Tooltip("Excluir item"));
        delBtn.setStyle("-fx-background-color:transparent; -fx-text-fill:#9eafc0;"
                + " -fx-font-size:12px; -fx-cursor:hand; -fx-padding:2 6 2 6; -fx-background-radius:4;");
        delBtn.setOnMouseEntered(e -> delBtn.setStyle(
                "-fx-background-color:#fdecea; -fx-text-fill:#c62828;"
                + " -fx-font-size:12px; -fx-cursor:hand; -fx-padding:2 6 2 6; -fx-background-radius:4;"));
        delBtn.setOnMouseExited(e -> delBtn.setStyle(
                "-fx-background-color:transparent; -fx-text-fill:#9eafc0;"
                + " -fx-font-size:12px; -fx-cursor:hand; -fx-padding:2 6 2 6; -fx-background-radius:4;"));
        delBtn.setOnAction(e -> deleteItem(item));

        cb.selectedProperty().addListener((obs, o, n) -> {
            item.done = n;
            item.kanbanColumn = n ? "concluido" : (item.kanbanColumn.equals("concluido") ? "backlog" : item.kanbanColumn);
            repo.updateDone(item.id, n);
            applyDoneStyle(textLbl, n);
            colBadge.setText(columnLabel(item.kanbanColumn));
            colBadge.setStyle("-fx-background-color:" + columnColor(item.kanbanColumn) + "22;"
                    + " -fx-text-fill:" + columnColor(item.kanbanColumn) + ";"
                    + " -fx-font-size:9px; -fx-font-weight:700;"
                    + " -fx-padding:2 6 2 6; -fx-background-radius:8;");
            refreshKpiAndProgress();
            if (onChanged != null) onChanged.run();
        });

        HBox contentRow = new HBox(8, numLbl, textLbl, editField, colBadge);
        contentRow.setAlignment(Pos.CENTER_LEFT);
        HBox.setHgrow(contentRow, Priority.ALWAYS);
        contentRow.setOnMouseClicked(e -> {
            if (e.getClickCount() == 2) enterEditMode(textLbl, editField, item, editBtn);
        });

        HBox row = new HBox(10, cb, contentRow, editBtn, delBtn);
        row.setAlignment(Pos.CENTER_LEFT);
        row.setPadding(new Insets(9, 12, 9, 14));

        String baseColor = index % 2 == 0 ? "#ffffff" : "#f7fbff";
        row.setStyle("-fx-background-color:" + baseColor
                + "; -fx-border-color:transparent transparent #e8f0fa transparent; -fx-border-width:0 0 1 0;");
        row.setOnMouseEntered(e -> row.setStyle("-fx-background-color:#eef6ff;"
                + " -fx-border-color:transparent transparent #e8f0fa transparent; -fx-border-width:0 0 1 0;"));
        row.setOnMouseExited(e  -> row.setStyle("-fx-background-color:" + baseColor
                + "; -fx-border-color:transparent transparent #e8f0fa transparent; -fx-border-width:0 0 1 0;"));

        Region stripe = new Region();
        stripe.setMinWidth(4); stripe.setMaxWidth(4);
        stripe.setStyle("-fx-background-color:" + columnColor(item.kanbanColumn)
                + "; -fx-background-radius:2 0 0 2;");

        HBox outerRow = new HBox(0, stripe, row);
        HBox.setHgrow(row, Priority.ALWAYS);
        outerRow.setAlignment(Pos.CENTER_LEFT);
        outerRow.setOnMouseClicked(e -> {
            if (e.getButton() == MouseButton.SECONDARY) {
                showItemContextMenu(item, textLbl, editField, editBtn, outerRow, e.getScreenX(), e.getScreenY());
                e.consume();
            } else if (e.getButton() == MouseButton.PRIMARY) {
                itemContextMenu.hide();
            }
        });

        return new VBox(outerRow);
    }

    // ──────────────────────────────────────────────────────────────────────────
    // VISTA KANBAN
    // ──────────────────────────────────────────────────────────────────────────

    private javafx.scene.Node buildKanbanView() {
        HBox board = new HBox(10);
        board.setPadding(new Insets(12, 14, 14, 14));
        board.setFillHeight(true);

        for (String[] colDef : KANBAN_COLS) {
            List<MutableItem> colItems = items.stream()
                    .filter(it -> colDef[0].equals(it.kanbanColumn))
                    .toList();
            board.getChildren().add(buildKanbanColumn(colDef, colItems));
        }

        ScrollPane sp = new ScrollPane(board);
        sp.setFitToHeight(true);
        sp.setFitToWidth(false);
        sp.setHbarPolicy(ScrollPane.ScrollBarPolicy.AS_NEEDED);
        sp.setVbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
        sp.getStyleClass().add("edge-to-edge");
        return sp;
    }

    private VBox buildKanbanColumn(String[] colDef, List<MutableItem> colItems) {
        String key = colDef[0], label = colDef[1].replace("  ", " ").trim(), color = colDef[2];

        Label headerLbl = new Label(label + "  (" + colItems.size() + ")");
        headerLbl.setStyle("-fx-font-size:12px; -fx-font-weight:700; -fx-text-fill:white;"
                + " -fx-padding:6 10 6 10; -fx-background-radius:6 6 0 0;"
                + " -fx-background-color:" + color + ";");
        headerLbl.setMaxWidth(Double.MAX_VALUE);

        Button addColBtn = new Button("+");
        addColBtn.setStyle("-fx-background-color:rgba(255,255,255,0.3); -fx-text-fill:white;"
                + " -fx-background-radius:4; -fx-font-weight:bold; -fx-font-size:14; -fx-cursor:hand;"
                + " -fx-padding:1 7 1 7;");
        addColBtn.setTooltip(new Tooltip("Adicionar item nesta coluna"));
        addColBtn.setOnAction(e -> showAddItemDialogForColumn(key));

        HBox colHeader = new HBox(headerLbl, addColBtn);
        colHeader.setAlignment(Pos.CENTER_LEFT);
        colHeader.setStyle("-fx-background-color:" + color + "; -fx-background-radius:6 6 0 0;");
        HBox.setHgrow(headerLbl, Priority.ALWAYS);

        VBox cards = new VBox(6);
        cards.setPadding(new Insets(8));
        if (colItems.isEmpty()) {
            Label empty = new Label("Sem itens");
            empty.setStyle("-fx-text-fill:#aabbcc; -fx-font-size:11px; -fx-padding:12;");
            cards.getChildren().add(empty);
        } else {
            for (MutableItem it : colItems) cards.getChildren().add(buildKanbanCard(it, color));
        }

        ScrollPane cardScroll = new ScrollPane(cards);
        cardScroll.setFitToWidth(true);
        cardScroll.setHbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
        cardScroll.setStyle("-fx-background-color:#f7fbff; -fx-border-color:transparent;");
        VBox.setVgrow(cardScroll, Priority.ALWAYS);

        VBox col = new VBox(0, colHeader, cardScroll);
        col.setPrefWidth(210); col.setMinWidth(190); col.setMaxWidth(240);
        col.setStyle("-fx-background-color:#f7fbff;"
                + " -fx-border-color:#b8cfe8; -fx-border-radius:6; -fx-background-radius:6;"
                + " -fx-effect:dropshadow(gaussian,rgba(3,24,62,0.07),8,0.2,0,2);");
        VBox.setVgrow(col, Priority.ALWAYS);
        return col;
    }

    private VBox buildKanbanCard(MutableItem item, String accentColor) {
        Label numLbl = new Label(String.format("#%02d", items.indexOf(item) + 1));
        numLbl.setStyle("-fx-font-family:'JetBrains Mono','Consolas',monospace;"
                + " -fx-font-size:9px; -fx-text-fill:#9eafc0;");

        Label textLbl = new Label(item.text);
        textLbl.setWrapText(true); textLbl.setMaxWidth(Double.MAX_VALUE);
        textLbl.setStyle((item.done
                ? "-fx-text-fill:#9eafc0; -fx-strikethrough:true;"
                : "-fx-text-fill:#0d1b2a;") + " -fx-font-size:12px; -fx-wrap-text:true;");

        HBox topRow = new HBox(4, numLbl);
        topRow.setAlignment(Pos.CENTER_LEFT);
        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);

        Button cbBtn = new Button(item.done ? "☑" : "☐");
        cbBtn.setStyle("-fx-background-color:transparent; -fx-cursor:hand;"
                + " -fx-font-size:14px; -fx-padding:0 2 0 2;");
        cbBtn.setTooltip(new Tooltip(item.done ? "Marcar como pendente" : "Marcar como concluído"));
        cbBtn.setOnAction(e -> {
            item.done = !item.done;
            item.kanbanColumn = item.done ? "concluido" : "backlog";
            repo.updateDone(item.id, item.done);
            refreshAll();
            if (onChanged != null) onChanged.run();
        });

        topRow.getChildren().addAll(spacer, cbBtn);

        VBox card = new VBox(4, topRow, textLbl);
        card.setStyle("-fx-background-color:white; -fx-background-radius:5;"
                + " -fx-border-color:" + accentColor + "; -fx-border-width:0 0 0 3;"
                + " -fx-border-radius:5; -fx-padding:8 10 8 10; -fx-cursor:hand;"
                + " -fx-effect:dropshadow(gaussian,rgba(0,0,0,0.06),4,0.2,0,1);");

        card.setOnMouseEntered(e -> card.setStyle(
                "-fx-background-color:#f0f7ff; -fx-background-radius:5;"
                + " -fx-border-color:" + accentColor + "; -fx-border-width:0 0 0 3;"
                + " -fx-border-radius:5; -fx-padding:8 10 8 10; -fx-cursor:hand;"
                + " -fx-effect:dropshadow(gaussian,rgba(0,0,0,0.12),6,0.3,0,2);"));
        card.setOnMouseExited(e -> card.setStyle(
                "-fx-background-color:white; -fx-background-radius:5;"
                + " -fx-border-color:" + accentColor + "; -fx-border-width:0 0 0 3;"
                + " -fx-border-radius:5; -fx-padding:8 10 8 10; -fx-cursor:hand;"
                + " -fx-effect:dropshadow(gaussian,rgba(0,0,0,0.06),4,0.2,0,1);"));

        if (item.text.length() > 60) {
            Tooltip tp = new Tooltip(item.text);
            tp.setWrapText(true); tp.setMaxWidth(280);
            Tooltip.install(card, tp);
        }

        card.setOnMouseClicked(e -> {
            if (e.getButton() == MouseButton.SECONDARY) {
                showItemContextMenu(item, textLbl, null, null, card, e.getScreenX(), e.getScreenY());
                e.consume();
            } else if (e.getButton() == MouseButton.PRIMARY) {
                itemContextMenu.hide();
            }
        });

        return card;
    }

    private void showAddItemDialogForColumn(String colKey) {
        TextInputDialog dlg = new TextInputDialog();
        dlg.setTitle("Novo Item");
        dlg.setHeaderText("Adicionar item na coluna \u201c" + columnLabel(colKey) + "\u201d");
        dlg.setContentText("Texto:");
        dlg.showAndWait().ifPresent(text -> {
            if (text.isBlank()) return;
            TaskChecklistItem saved = repo.addItem(task.id(), text);
            if (!"backlog".equals(colKey)) repo.updateColumn(saved.id(), colKey);
            MutableItem mi = new MutableItem(saved);
            mi.kanbanColumn = colKey;
            mi.done = "concluido".equals(colKey);
            items.add(mi);
            refreshAll();
            if (onChanged != null) onChanged.run();
        });
    }

    // ── Modo de edição inline ─────────────────────────────────────────────────

    private void enterEditMode(Label textLbl, TextField editField, MutableItem item, Button editBtn) {
        if (editField == null) return;
        textLbl.setVisible(false); textLbl.setManaged(false);
        editField.setText(item.text);
        editField.setVisible(true); editField.setManaged(true);
        editField.requestFocus(); editField.selectAll();
        if (editBtn != null) editBtn.setText("");

        Runnable save = () -> {
            String newText = editField.getText().trim();
            if (!newText.isBlank() && !newText.equals(item.text)) {
                item.text = newText; repo.updateText(item.id, newText);
                if (onChanged != null) onChanged.run();
            }
            textLbl.setText(item.text);
            textLbl.setVisible(true); textLbl.setManaged(true);
            editField.setVisible(false); editField.setManaged(false);
            if (editBtn != null) editBtn.setText("✏");
        };
        Runnable cancel = () -> {
            textLbl.setVisible(true); textLbl.setManaged(true);
            editField.setVisible(false); editField.setManaged(false);
            if (editBtn != null) editBtn.setText("✏");
        };
        editField.setOnAction(e -> save.run());
        editField.setOnKeyPressed(e -> { if (e.getCode() == javafx.scene.input.KeyCode.ESCAPE) cancel.run(); });
        if (editBtn != null) editBtn.setOnAction(e -> {
            if ("".equals(editBtn.getText())) save.run();
            else enterEditMode(textLbl, editField, item, editBtn);
        });
    }

    // ── Context menu ──────────────────────────────────────────────────────────

    private void showItemContextMenu(MutableItem item, Label textLbl,
                                     TextField editField, Button editBtn,
                                     javafx.scene.Node anchor, double sx, double sy) {
        itemContextMenu.hide();
        itemContextMenu.getItems().clear();
        itemContextMenu.setAutoHide(true);

        MenuItem copyItem = new MenuItem("  Copiar Texto");
        copyItem.setOnAction(e -> copyToClipboard(item.text));

        MenuItem editItem = new MenuItem("✏  Editar");
        if (editField != null) {
            editItem.setOnAction(e -> enterEditMode(textLbl, editField, item, editBtn));
        } else {
            editItem.setOnAction(e -> {
                TextInputDialog dlg = new TextInputDialog(item.text);
                dlg.setTitle("Editar Item"); dlg.setHeaderText(null);
                dlg.setContentText("Texto:");
                dlg.showAndWait().ifPresent(t -> {
                    if (!t.isBlank() && !t.equals(item.text)) {
                        item.text = t; repo.updateText(item.id, t);
                        refreshAll();
                        if (onChanged != null) onChanged.run();
                    }
                });
            });
        }

        MenuItem toggleItem = item.done
                ? new MenuItem("☐  Marcar como Pendente")
                : new MenuItem("✔  Marcar como Concluído");
        toggleItem.setOnAction(e -> {
            item.done = !item.done;
            item.kanbanColumn = item.done ? "concluido"
                    : (item.kanbanColumn.equals("concluido") ? "backlog" : item.kanbanColumn);
            repo.updateDone(item.id, item.done);
            refreshAll();
            if (onChanged != null) onChanged.run();
        });

        Menu moveMenu = new Menu("  Mover para...");
        for (String[] c : KANBAN_COLS) {
            String cKey = c[0], cLabel = c[1].replace("  ", " ").trim();
            MenuItem mi = new MenuItem(cLabel);
            if (cKey.equals(item.kanbanColumn)) mi.setStyle("-fx-font-weight:bold; -fx-text-fill:#1565c0;");
            mi.setOnAction(e -> moveItemToColumn(item, cKey));
            moveMenu.getItems().add(mi);
        }

        SeparatorMenuItem sep = new SeparatorMenuItem();

        MenuItem deleteItem = new MenuItem("  Excluir Item");
        deleteItem.setStyle("-fx-text-fill:#c62828;");
        deleteItem.setOnAction(e -> deleteItem(item));

        itemContextMenu.getItems().addAll(copyItem, editItem, toggleItem, moveMenu, sep, deleteItem);
        itemContextMenu.show(anchor, sx, sy);
    }

    private void moveItemToColumn(MutableItem item, String colKey) {
        item.kanbanColumn = colKey;
        item.done = "concluido".equals(colKey);
        repo.updateColumn(item.id, colKey);
        refreshAll();
        if (onChanged != null) onChanged.run();
    }

    private void deleteItem(MutableItem item) {
        repo.deleteItem(item.id);
        items.remove(item);
        refreshAll();
        if (onChanged != null) onChanged.run();
    }

    // ── Ações em lote ─────────────────────────────────────────────────────────

    private void markAll(boolean done) {
        for (MutableItem it : items) {
            if (it.done != done) {
                it.done = done;
                it.kanbanColumn = done ? "concluido"
                        : (it.kanbanColumn.equals("concluido") ? "backlog" : it.kanbanColumn);
                repo.updateDone(it.id, done);
            }
        }
        refreshAll();
        if (onChanged != null) onChanged.run();
    }

    private void clearDoneItems() {
        long count = items.stream().filter(it -> it.done).count();
        if (count == 0) { new Alert(Alert.AlertType.INFORMATION, "Sem itens concluídos para remover.", ButtonType.OK).showAndWait(); return; }
        Alert confirm = new Alert(Alert.AlertType.CONFIRMATION);
        confirm.setTitle("Limpar Concluídos");
        confirm.setHeaderText("Remover itens concluídos?");
        confirm.setContentText(count + " item(ns) serão excluídos permanentemente.");
        confirm.showAndWait().ifPresent(btn -> {
            if (btn == ButtonType.OK) {
                List<MutableItem> done = items.stream().filter(it -> it.done).toList();
                done.forEach(it -> repo.deleteItem(it.id));
                items.removeAll(done);
                refreshAll();
                if (onChanged != null) onChanged.run();
            }
        });
    }

    // ── Refresh ───────────────────────────────────────────────────────────────

    private void refreshAll() {
        refreshKpiAndProgress();
        refreshContentArea();
    }

    private void refreshKpiAndProgress() {
        int total   = items.size();
        int done    = (int) items.stream().filter(it -> it.done).count();
        int pending = total - done;
        double pct  = total == 0 ? 0.0 : (double) done / total;

        if (kpiTotal   != null) kpiTotal.setText(String.valueOf(total));
        if (kpiDone    != null) kpiDone.setText(String.valueOf(done));
        if (kpiPending != null) kpiPending.setText(String.valueOf(pending));
        if (kpiPercent != null) kpiPercent.setText(Math.round(pct * 100) + "%");

        if (progressBar != null) {
            progressBar.setProgress(pct);
            String accent = pct == 1.0 ? "#1b5e20" : pct >= 0.7 ? "#2e7d32" : pct >= 0.4 ? "#f57f17" : "#c62828";
            progressBar.setStyle("-fx-accent:" + accent
                    + "; -fx-background-color:#d6e4f5; -fx-background-radius:7; -fx-border-radius:7;");
        }
        if (progressLabel != null) progressLabel.setText(
                done + " de " + total + " itens concluídos"
                + (total > 0 ? "  (" + Math.round(pct * 100) + "%)" : ""));
    }

    // ── Rodapé ────────────────────────────────────────────────────────────────

    private HBox buildFooter(Stage stage) {
        Label hint = new Label("  Duplo clique para editar  ·  Botão direito para mais opções  ·  ⬛ Kanban mostra colunas de progresso");
        hint.setStyle("-fx-font-size:11px; -fx-text-fill:#7a9abc;"
                + " -fx-font-family:'JetBrains Mono','Consolas',monospace;");
        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);

        Button printBtn = new Button("  Imprimir Checklist");
        printBtn.getStyleClass().add("secondary-button");
        printBtn.setOnAction(e -> printChecklist());

        Button closeBtn = new Button("✕  Fechar");
        closeBtn.getStyleClass().add("secondary-button");
        closeBtn.setOnAction(e -> stage.close());
        HBox footer = new HBox(12, hint, spacer, printBtn, closeBtn);
        footer.setPadding(new Insets(10, 18, 10, 18)); footer.setAlignment(Pos.CENTER_LEFT);
        footer.setStyle("-fx-background-color:#edf1f8; -fx-border-color:#b8cfe8; -fx-border-width:1 0 0 0;");
        return footer;
    }

    // ── Helpers de Kanban ─────────────────────────────────────────────────────

    private String columnLabel(String key) {
        for (String[] c : KANBAN_COLS) if (c[0].equals(key)) return c[1].replace("  ", " ").trim();
        return key;
    }
    private String columnColor(String key) {
        for (String[] c : KANBAN_COLS) if (c[0].equals(key)) return c[2];
        return "#546e7a";
    }

    // ── Helpers visuais ───────────────────────────────────────────────────────

    private void applyDoneStyle(Label lbl, boolean done) {
        lbl.setStyle(done
                ? "-fx-text-fill:#9eafc0; -fx-strikethrough:true;  -fx-font-size:12px;"
                : "-fx-text-fill:#0d1b2a; -fx-strikethrough:false; -fx-font-size:12px;");
    }

    private void copyToClipboard(String text) {
        ClipboardContent c = new ClipboardContent(); c.putString(text);
        Clipboard.getSystemClipboard().setContent(c);
    }

    // ── Fábrica estática ──────────────────────────────────────────────────────

    public static void open(Task task, Runnable onChanged) {
        TaskChecklistRepository repo = AppContextHolder.get().taskChecklistRepository();
        new TaskChecklistWindow(task, repo, onChanged).show();
    }
}

package com.pessoal.agenda.ui.view;

import com.pessoal.agenda.app.AppContextHolder;
import com.pessoal.agenda.model.Task;
import com.pessoal.agenda.model.TaskChecklistItem;
import com.pessoal.agenda.repository.TaskChecklistRepository;
import javafx.application.Platform;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.input.Clipboard;
import javafx.scene.input.ClipboardContent;
import javafx.scene.input.MouseButton;
import javafx.scene.layout.*;
import javafx.stage.Modality;
import javafx.stage.Stage;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

/**
 * Janela dedicada de Checklist/Kanban para Tarefas da Agenda Científica.
 *
 * Modos de visualização:
 *   • Lista  — flat list com filtros (Todos / Pendentes / Concluídos)
 *   • Kanban — board com 4 colunas: Backlog | Em Andamento | Em Revisão | Concluído
 */
public class TaskChecklistWindow {

    // ── Colunas do Kanban ─────────────────────────────────────────────────────
    private static final String[][] KANBAN_COLS = {
        {"backlog",      "  Backlog",       "#546e7a"},
        {"em_andamento", "⚡  Em Andamento",  "#1565c0"},
        {"em_revisao",   "  Em Revisão",    "#7b1fa2"},
        {"concluido",    "✅  Concluído",      "#2e7d32"},
    };

    // ── Prevenção de janela duplicada ─────────────────────────────────────────
    private static final Map<Long, Stage> openWindows = new HashMap<>();

    private final Task task;
    private final TaskChecklistRepository repo;
    private final Runnable onChanged;

    // ── Estado em memória ─────────────────────────────────────────────────────
    private final List<MutableItem> items = new ArrayList<>();

    // ── Modo de visualização ──────────────────────────────────────────────────
    private boolean isKanban = false;

    // ── Filtro de exibição (lista) ────────────────────────────────────────────
    private enum Filter { ALL, PENDING, DONE }
    private Filter currentFilter = Filter.ALL;

    // ── Componentes da UI ─────────────────────────────────────────────────────
    private VBox itemsBox;
    private StackPane contentArea;
    private Label kpiTotal, kpiDone, kpiPending, kpiPercent;
    private ProgressBar progressBar;
    private Label progressLabel;

    // ── Context menu único reutilizável para itens ────────────────────────────
    private final ContextMenu itemContextMenu = new ContextMenu();

    // ── Modelo mutável de item ────────────────────────────────────────────────
    private static class MutableItem {
        long    id;
        String  text;
        boolean done;
        int     position;
        String  kanbanColumn;

        MutableItem(TaskChecklistItem src) {
            this.id           = src.id();
            this.text         = src.text();
            this.done         = src.done();
            this.position     = src.position();
            this.kanbanColumn = src.kanbanColumn() != null ? src.kanbanColumn() : "backlog";
        }
    }

    // ── Construtor ────────────────────────────────────────────────────────────

    public TaskChecklistWindow(Task task, TaskChecklistRepository repo, Runnable onChanged) {
        this.task      = task;
        this.repo      = repo;
        this.onChanged = onChanged;
    }

    // ── Ponto de entrada ──────────────────────────────────────────────────────

    public void show() {
        if (openWindows.containsKey(task.id())) {
            openWindows.get(task.id()).toFront();
            openWindows.get(task.id()).requestFocus();
            return;
        }

        loadItems();

        Stage stage = new Stage();
        stage.initModality(Modality.NONE);
        stage.setTitle("Checklist — " + task.title());
        stage.setMinWidth(660);
        stage.setMinHeight(540);
        openWindows.put(task.id(), stage);
        stage.setOnHidden(e -> openWindows.remove(task.id()));

        VBox root = new VBox(0);
        root.getStyleClass().add("app-root");

        contentArea = new StackPane();
        VBox.setVgrow(contentArea, Priority.ALWAYS);

        root.getChildren().addAll(
                buildHeader(),
                buildKpiBar(),
                buildProgressSection(),
                buildViewToolbar(),
                contentArea,
                buildFooter(stage)
        );

        refreshContentArea();

        Scene scene = new Scene(root, 900, 660);
        ThemeManager.getInstance().applyTo(scene);
        stage.setScene(scene);
        stage.show();
    }

    // ── Carregamento ──────────────────────────────────────────────────────────

    private void loadItems() {
        items.clear();
        repo.findByTaskId(task.id()).forEach(i -> items.add(new MutableItem(i)));
    }

    // ── Cabeçalho ─────────────────────────────────────────────────────────────

    private HBox buildHeader() {
        Label icon = new Label("☑");
        icon.setStyle("-fx-font-size: 28px; -fx-text-fill: #00b4d8;");

        Label title = new Label("Checklist da Tarefa");
        title.getStyleClass().add("page-title");

        String catText = task.category() != null ? "  ·  " + task.category() : "";
        String prioText = task.priority() != null ? "  ·  " + task.priority().label() : "";
        Label subtitle = new Label(task.title() + catText + prioText);
        subtitle.getStyleClass().add("page-subtitle");

        VBox texts = new VBox(2, title, subtitle);
        Region spacer = new Region();
        HBox.setHgrow(spacer, Priority.ALWAYS);

        String statusLabel = task.status() != null ? task.status().label() : "—";
        Label statusBadge = new Label(statusLabel);
        statusBadge.setStyle(
                "-fx-background-color: #1565c0; -fx-text-fill: white;"
                + " -fx-font-size: 11px; -fx-font-weight: 700;"
                + " -fx-padding: 4 10 4 10; -fx-background-radius: 12;");

        HBox hdr = new HBox(14, icon, texts, spacer, statusBadge);
        hdr.getStyleClass().add("header-bar");
        hdr.setPadding(new Insets(14, 20, 14, 20));
        hdr.setAlignment(Pos.CENTER_LEFT);
        return hdr;
    }

    // ── KPI bar ───────────────────────────────────────────────────────────────

    private HBox buildKpiBar() {
        kpiTotal   = kpiValue("0");
        kpiDone    = kpiValue("0");
        kpiPending = kpiValue("0");
        kpiPercent = kpiValue("0%");

        HBox bar = new HBox(10,
                kpiCard("TOTAL DE ITENS",   kpiTotal,   "kpi-blue"),
                kpiCard("CONCLUÍDOS",       kpiDone,    "kpi-green"),
                kpiCard("PENDENTES",        kpiPending, "kpi-indigo"),
                kpiCard("PROGRESSO",        kpiPercent, "kpi-cyan"));
        bar.setPadding(new Insets(12, 14, 4, 14));
        for (javafx.scene.Node n : bar.getChildren()) HBox.setHgrow(n, Priority.ALWAYS);
        refreshKpiAndProgress();
        return bar;
    }

    private Label kpiValue(String v) {
        Label l = new Label(v); l.getStyleClass().add("kpi-value"); return l;
    }
    private VBox kpiCard(String title, Label value, String cls) {
        Label lbl = new Label(title); lbl.getStyleClass().add("kpi-title");
        VBox c = new VBox(4, lbl, value); c.getStyleClass().addAll("kpi-card", cls); return c;
    }

    // ── Barra de progresso ────────────────────────────────────────────────────

    private VBox buildProgressSection() {
        progressBar = new ProgressBar(0);
        progressBar.setMaxWidth(Double.MAX_VALUE);
        progressBar.setPrefHeight(14);

        progressLabel = new Label("0 de 0 itens concluídos");
        progressLabel.setStyle("-fx-font-size: 11.5px; -fx-text-fill: #5a7a9e;"
                + " -fx-font-family: 'JetBrains Mono','Consolas',monospace;");

        VBox section = new VBox(6, progressBar, progressLabel);
        section.setPadding(new Insets(8, 14, 8, 14));
        section.setStyle("-fx-background-color: white;"
                + " -fx-border-color: transparent transparent #dce8f5 transparent;"
                + " -fx-border-width: 0 0 1 0;");
        return section;
    }

    // ── Barra de ferramentas com toggle Lista/Kanban + filtros ─────────────────

    private HBox buildViewToolbar() {
        ToggleGroup viewGroup = new ToggleGroup();
        ToggleButton listBtn   = new ToggleButton("☰  Lista");
        ToggleButton kanbanBtn = new ToggleButton("⬛  Kanban");
        listBtn.setToggleGroup(viewGroup);   listBtn.setSelected(true);
        kanbanBtn.setToggleGroup(viewGroup);
        listBtn.getStyleClass().add("view-toggle-btn");
        kanbanBtn.getStyleClass().add("view-toggle-btn");
        HBox viewToggle = new HBox(2, listBtn, kanbanBtn);
        viewToggle.getStyleClass().add("view-toggle-bar");

        listBtn.setOnAction(e -> {
            if (!listBtn.isSelected()) { listBtn.setSelected(true); return; }
            isKanban = false; refreshContentArea();
        });
        kanbanBtn.setOnAction(e -> {
            if (!kanbanBtn.isSelected()) { kanbanBtn.setSelected(true); return; }
            isKanban = true; refreshContentArea();
        });

        Separator sep = new Separator(javafx.geometry.Orientation.VERTICAL);
        sep.setPadding(new Insets(0, 4, 0, 4));

        ToggleGroup filterGroup = new ToggleGroup();
        ToggleButton allBtn   = filterToggle("Todos",      filterGroup, Filter.ALL);
        ToggleButton pendBtn  = filterToggle("Pendentes",  filterGroup, Filter.PENDING);
        ToggleButton doneBtn  = filterToggle("Concluídos", filterGroup, Filter.DONE);
        allBtn.setSelected(true);
        HBox filterBar = new HBox(2, allBtn, pendBtn, doneBtn);
        filterBar.getStyleClass().add("view-toggle-bar");

        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);

        Button checkAllBtn   = new Button("✔  Marcar Todos");
        Button uncheckAllBtn = new Button("☐  Desmarcar Todos");
        Button clearDoneBtn  = new Button("  Limpar Concluídos");
        checkAllBtn.getStyleClass().add("secondary-button");
        uncheckAllBtn.getStyleClass().add("secondary-button");
        clearDoneBtn.getStyleClass().add("danger-button");
        checkAllBtn.setStyle("-fx-font-size: 11px;");
        uncheckAllBtn.setStyle("-fx-font-size: 11px;");
        clearDoneBtn.setStyle("-fx-font-size: 11px;");
        checkAllBtn.setOnAction(e -> markAll(true));
        uncheckAllBtn.setOnAction(e -> markAll(false));
        clearDoneBtn.setOnAction(e -> clearDoneItems());

        Button addBtn = new Button("＋  Novo Item");
        addBtn.getStyleClass().add("primary-button");
        addBtn.setStyle("-fx-font-size: 11px;");
        addBtn.setOnAction(e -> showAddItemDialog());

        Button printBtn = new Button("  Imprimir");
        printBtn.getStyleClass().add("secondary-button");
        printBtn.setStyle("-fx-font-size: 11px;");
        printBtn.setOnAction(e -> printChecklist());

        HBox bar = new HBox(8, viewToggle, sep, filterBar, spacer,
                checkAllBtn, uncheckAllBtn, clearDoneBtn, printBtn, addBtn);
        bar.setPadding(new Insets(8, 14, 8, 14));
        bar.setAlignment(Pos.CENTER_LEFT);
        bar.setStyle("-fx-background-color: #f2f7fc;"
                + " -fx-border-color: transparent transparent #dce8f5 transparent;"
                + " -fx-border-width: 0 0 1 0;");
        return bar;
    }

    private ToggleButton filterToggle(String label, ToggleGroup tg, Filter filter) {
        ToggleButton btn = new ToggleButton(label);
        btn.setToggleGroup(tg);
        btn.getStyleClass().add("view-toggle-btn");
        btn.setOnAction(e -> {
            if (!btn.isSelected()) { btn.setSelected(true); return; }
            currentFilter = filter;
            if (!isKanban) refreshContentArea();
        });
        return btn;
    }

    // ── Impressão do checklist ────────────────────────────────────────────────

    private void printChecklist() {
        ComboBox<String> dlgItemsFilter = new ComboBox<>();
        dlgItemsFilter.getItems().addAll("Todos os itens", "Apenas Pendentes", "Apenas Concluídos");
        dlgItemsFilter.setValue(switch (currentFilter) {
            case PENDING -> "Apenas Pendentes";
            case DONE    -> "Apenas Concluídos";
            default      -> "Todos os itens";
        });
        dlgItemsFilter.getStyleClass().add("input-control");
        dlgItemsFilter.setMaxWidth(Double.MAX_VALUE);

        ComboBox<String> dlgColFilter = new ComboBox<>();
        dlgColFilter.getItems().add("Todas as colunas");
        for (String[] c : KANBAN_COLS) dlgColFilter.getItems().add(c[1].replace("  ", " ").trim());
        dlgColFilter.setValue("Todas as colunas");
        dlgColFilter.getStyleClass().add("input-control");
        dlgColFilter.setMaxWidth(Double.MAX_VALUE);

        javafx.scene.layout.GridPane grid = new javafx.scene.layout.GridPane();
        grid.setHgap(10); grid.setVgap(8); grid.setPadding(new Insets(10, 0, 0, 0));
        grid.add(new Label("Mostrar:"), 0, 0); grid.add(dlgItemsFilter, 1, 0);
        grid.add(new Label("Coluna:"),  0, 1); grid.add(dlgColFilter,   1, 1);
        javafx.scene.layout.GridPane.setHgrow(dlgItemsFilter, Priority.ALWAYS);
        javafx.scene.layout.GridPane.setHgrow(dlgColFilter,   Priority.ALWAYS);

        Dialog<ButtonType> printDlg = new Dialog<>();
        printDlg.setTitle("Opções de Impressão");
        printDlg.setHeaderText("Checklist — " + task.title());
        printDlg.getDialogPane().setContent(grid);
        printDlg.getDialogPane().setMinWidth(380);
        printDlg.getDialogPane().getButtonTypes().addAll(ButtonType.OK, ButtonType.CANCEL);
        ((Button) printDlg.getDialogPane().lookupButton(ButtonType.OK)).setText(" Gerar Checklist");
        ((Button) printDlg.getDialogPane().lookupButton(ButtonType.CANCEL)).setText("Cancelar");

        var dlgResult = printDlg.showAndWait();
        if (dlgResult.isEmpty() || dlgResult.get() != ButtonType.OK) return;

        String colSel = dlgColFilter.getValue();
        String colKey = "Todas as colunas".equals(colSel) ? null :
                java.util.Arrays.stream(KANBAN_COLS)
                        .filter(c -> c[1].replace("  ", " ").trim().equals(colSel))
                        .map(c -> c[0])
                        .findFirst().orElse(null);

        String itemsSel = dlgItemsFilter.getValue();
        List<TaskChecklistItem> checkItems = items.stream()
                .filter(mi -> switch (itemsSel) {
                    case "Apenas Pendentes"  -> !mi.done;
                    case "Apenas Concluídos" ->  mi.done;
                    default                  -> true;
                })
                .filter(mi -> colKey == null || colKey.equals(mi.kanbanColumn))
                .map(mi -> new TaskChecklistItem(mi.id, task.id(), mi.text, mi.done, mi.position, mi.kanbanColumn))
                .toList();

        String html = com.pessoal.agenda.ui.util.PrintReportService
                .generateTaskChecklistReport(task, checkItems);
        PrintPreviewWindow.open(html, "Checklist — " + task.title());
    }

    // ── Diálogo de adição de item ─────────────────────────────────────────────

    private void showAddItemDialog() {
        TextField field = new TextField();
        field.getStyleClass().add("input-control");
        field.setPromptText("Descreva o passo ou ação...");
        field.setPrefWidth(380);

        ComboBox<String> colCombo = new ComboBox<>();
        colCombo.getStyleClass().add("input-control");
        for (String[] c : KANBAN_COLS) colCombo.getItems().add(c[1].replace("  ", " ").trim());
        colCombo.setValue(KANBAN_COLS[0][1].replace("  ", " ").trim());

        VBox content = new VBox(8,
                new Label("Texto do item:"), field,
                new Label("Coluna inicial:"), colCombo);
        content.setPadding(new Insets(10));

        Dialog<ButtonType> dlg = new Dialog<>();
        dlg.setTitle("Novo Item");
        dlg.setHeaderText("Adicionar item ao checklist da tarefa");
        dlg.getDialogPane().setContent(content);
        dlg.getDialogPane().getButtonTypes().addAll(ButtonType.OK, ButtonType.CANCEL);
        Platform.runLater(field::requestFocus);

        dlg.showAndWait().ifPresent(btn -> {
            if (btn != ButtonType.OK) return;
            String text = field.getText().trim();
            if (text.isBlank()) return;
            int colIdx = colCombo.getSelectionModel().getSelectedIndex();
            String colKey = KANBAN_COLS[Math.max(0, colIdx)][0];
            TaskChecklistItem saved = repo.addItem(task.id(), text);
            if (!"backlog".equals(colKey)) repo.updateColumn(saved.id(), colKey);
            MutableItem mi = new MutableItem(saved);
            mi.kanbanColumn = colKey;
            mi.done = "concluido".equals(colKey);
            items.add(mi);
            refreshAll();
            if (onChanged != null) onChanged.run();
        });
    }

    // ── Área de conteúdo principal ────────────────────────────────────────────

    private void refreshContentArea() {
        if (contentArea == null) return;
        contentArea.getChildren().setAll(isKanban ? buildKanbanView() : buildListView());
    }

    // ──────────────────────────────────────────────────────────────────────────
    // VISTA LISTA
    // ──────────────────────────────────────────────────────────────────────────

    private javafx.scene.Node buildListView() {
        itemsBox = new VBox(0);
        itemsBox.setFillWidth(true);

        ScrollPane sp = new ScrollPane(itemsBox);
        sp.setFitToWidth(true);
        sp.setFitToHeight(false);
        sp.setHbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
        sp.setVbarPolicy(ScrollPane.ScrollBarPolicy.AS_NEEDED);
        sp.getStyleClass().add("edge-to-edge");
        sp.setStyle("-fx-background-color: #f7fbff;");

        refreshItemsUI();
        return sp;
    }

    private void refreshItemsUI() {
        if (itemsBox == null) return;
        itemsBox.getChildren().clear();

        List<MutableItem> visible = items.stream()
                .filter(it -> switch (currentFilter) {
                    case ALL     -> true;
                    case PENDING -> !it.done;
                    case DONE    -> it.done;
                }).toList();

        if (visible.isEmpty()) {
            Label empty = new Label(switch (currentFilter) {
                case PENDING -> "Nenhum item pendente.  Todos os itens foram concluídos!";
                case DONE    -> "Nenhum item concluído ainda.";
                default      -> "Nenhum item no checklist.\nUse o botão ＋ Novo Item para adicionar.";
            });
            empty.setStyle("-fx-text-fill: #9eafc0; -fx-font-size: 12px; -fx-padding: 30 20 30 20;");
            empty.setWrapText(true); empty.setMaxWidth(Double.MAX_VALUE);
            empty.setAlignment(Pos.CENTER);
            itemsBox.getChildren().add(empty);
            return;
        }
        for (int i = 0; i < visible.size(); i++) itemsBox.getChildren().add(buildItemRow(visible.get(i), i));
    }

    private VBox buildItemRow(MutableItem item, int index) {
        CheckBox cb = new CheckBox();
        cb.setSelected(item.done);
        cb.setStyle("-fx-cursor: hand;");

        int globalIdx = items.indexOf(item) + 1;
        Label numLbl = new Label(String.format("%02d", globalIdx));
        numLbl.setStyle("-fx-font-family:'JetBrains Mono','Consolas',monospace;"
                + " -fx-font-size:10px; -fx-text-fill:#9eafc0; -fx-min-width:24px;");

        Label textLbl = new Label(item.text);
        textLbl.setWrapText(true); textLbl.setMaxWidth(Double.MAX_VALUE);
        HBox.setHgrow(textLbl, Priority.ALWAYS);
        applyDoneStyle(textLbl, item.done);

        String colLabel = columnLabel(item.kanbanColumn);
        String colColor = columnColor(item.kanbanColumn);
        Label colBadge = new Label(colLabel);
        colBadge.setStyle("-fx-background-color:" + colColor + "22; -fx-text-fill:" + colColor + ";"
                + " -fx-font-size:9px; -fx-font-weight:700; -fx-padding:2 6 2 6; -fx-background-radius:8;");

        TextField editField = new TextField(item.text);
        editField.getStyleClass().add("input-control");
        editField.setStyle("-fx-font-size:12px;");
        editField.setVisible(false); editField.setManaged(false);
        HBox.setHgrow(editField, Priority.ALWAYS);

        Button editBtn = new Button("✏");
        editBtn.setTooltip(new Tooltip("Editar (duplo clique)"));
        editBtn.setStyle("-fx-background-color:transparent; -fx-text-fill:#5a7a9e;"
                + " -fx-font-size:12px; -fx-cursor:hand; -fx-padding:2 6 2 6; -fx-background-radius:4;");
        editBtn.setOnAction(e -> enterEditMode(textLbl, editField, item, editBtn));

        Button delBtn = new Button("✕");
        delBtn.setTooltip(new Tooltip("Excluir item"));
        delBtn.setStyle("-fx-background-color:transparent; -fx-text-fill:#9eafc0;"
                + " -fx-font-size:12px; -fx-cursor:hand; -fx-padding:2 6 2 6; -fx-background-radius:4;");
        delBtn.setOnMouseEntered(e -> delBtn.setStyle(
                "-fx-background-color:#fdecea; -fx-text-fill:#c62828;"
                + " -fx-font-size:12px; -fx-cursor:hand; -fx-padding:2 6 2 6; -fx-background-radius:4;"));
        delBtn.setOnMouseExited(e -> delBtn.setStyle(
                "-fx-background-color:transparent; -fx-text-fill:#9eafc0;"
                + " -fx-font-size:12px; -fx-cursor:hand; -fx-padding:2 6 2 6; -fx-background-radius:4;"));
        delBtn.setOnAction(e -> deleteItem(item));

        cb.selectedProperty().addListener((obs, o, n) -> {
            item.done = n;
            item.kanbanColumn = n ? "concluido" : (item.kanbanColumn.equals("concluido") ? "backlog" : item.kanbanColumn);
            repo.updateDone(item.id, n);
            applyDoneStyle(textLbl, n);
            colBadge.setText(columnLabel(item.kanbanColumn));
            colBadge.setStyle("-fx-background-color:" + columnColor(item.kanbanColumn) + "22;"
                    + " -fx-text-fill:" + columnColor(item.kanbanColumn) + ";"
                    + " -fx-font-size:9px; -fx-font-weight:700;"
                    + " -fx-padding:2 6 2 6; -fx-background-radius:8;");
            refreshKpiAndProgress();
            if (onChanged != null) onChanged.run();
        });

        HBox contentRow = new HBox(8, numLbl, textLbl, editField, colBadge);
        contentRow.setAlignment(Pos.CENTER_LEFT);
        HBox.setHgrow(contentRow, Priority.ALWAYS);
        contentRow.setOnMouseClicked(e -> {
            if (e.getClickCount() == 2) enterEditMode(textLbl, editField, item, editBtn);
        });

        HBox row = new HBox(10, cb, contentRow, editBtn, delBtn);
        row.setAlignment(Pos.CENTER_LEFT);
        row.setPadding(new Insets(9, 12, 9, 14));

        String baseColor = index % 2 == 0 ? "#ffffff" : "#f7fbff";
        row.setStyle("-fx-background-color:" + baseColor
                + "; -fx-border-color:transparent transparent #e8f0fa transparent; -fx-border-width:0 0 1 0;");
        row.setOnMouseEntered(e -> row.setStyle("-fx-background-color:#eef6ff;"
                + " -fx-border-color:transparent transparent #e8f0fa transparent; -fx-border-width:0 0 1 0;"));
        row.setOnMouseExited(e  -> row.setStyle("-fx-background-color:" + baseColor
                + "; -fx-border-color:transparent transparent #e8f0fa transparent; -fx-border-width:0 0 1 0;"));

        Region stripe = new Region();
        stripe.setMinWidth(4); stripe.setMaxWidth(4);
        stripe.setStyle("-fx-background-color:" + columnColor(item.kanbanColumn)
                + "; -fx-background-radius:2 0 0 2;");

        HBox outerRow = new HBox(0, stripe, row);
        HBox.setHgrow(row, Priority.ALWAYS);
        outerRow.setAlignment(Pos.CENTER_LEFT);
        outerRow.setOnMouseClicked(e -> {
            if (e.getButton() == MouseButton.SECONDARY) {
                showItemContextMenu(item, textLbl, editField, editBtn, outerRow, e.getScreenX(), e.getScreenY());
                e.consume();
            } else if (e.getButton() == MouseButton.PRIMARY) {
                itemContextMenu.hide();
            }
        });

        return new VBox(outerRow);
    }

    // ──────────────────────────────────────────────────────────────────────────
    // VISTA KANBAN
    // ──────────────────────────────────────────────────────────────────────────

    private javafx.scene.Node buildKanbanView() {
        HBox board = new HBox(10);
        board.setPadding(new Insets(12, 14, 14, 14));
        board.setFillHeight(true);

        for (String[] colDef : KANBAN_COLS) {
            List<MutableItem> colItems = items.stream()
                    .filter(it -> colDef[0].equals(it.kanbanColumn))
                    .toList();
            board.getChildren().add(buildKanbanColumn(colDef, colItems));
        }

        ScrollPane sp = new ScrollPane(board);
        sp.setFitToHeight(true);
        sp.setFitToWidth(false);
        sp.setHbarPolicy(ScrollPane.ScrollBarPolicy.AS_NEEDED);
        sp.setVbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
        sp.getStyleClass().add("edge-to-edge");
        return sp;
    }

    private VBox buildKanbanColumn(String[] colDef, List<MutableItem> colItems) {
        String key = colDef[0], label = colDef[1].replace("  ", " ").trim(), color = colDef[2];

        Label headerLbl = new Label(label + "  (" + colItems.size() + ")");
        headerLbl.setStyle("-fx-font-size:12px; -fx-font-weight:700; -fx-text-fill:white;"
                + " -fx-padding:6 10 6 10; -fx-background-radius:6 6 0 0;"
                + " -fx-background-color:" + color + ";");
        headerLbl.setMaxWidth(Double.MAX_VALUE);

        Button addColBtn = new Button("+");
        addColBtn.setStyle("-fx-background-color:rgba(255,255,255,0.3); -fx-text-fill:white;"
                + " -fx-background-radius:4; -fx-font-weight:bold; -fx-font-size:14; -fx-cursor:hand;"
                + " -fx-padding:1 7 1 7;");
        addColBtn.setTooltip(new Tooltip("Adicionar item nesta coluna"));
        addColBtn.setOnAction(e -> showAddItemDialogForColumn(key));

        HBox colHeader = new HBox(headerLbl, addColBtn);
        colHeader.setAlignment(Pos.CENTER_LEFT);
        colHeader.setStyle("-fx-background-color:" + color + "; -fx-background-radius:6 6 0 0;");
        HBox.setHgrow(headerLbl, Priority.ALWAYS);

        VBox cards = new VBox(6);
        cards.setPadding(new Insets(8));
        if (colItems.isEmpty()) {
            Label empty = new Label("Sem itens");
            empty.setStyle("-fx-text-fill:#aabbcc; -fx-font-size:11px; -fx-padding:12;");
            cards.getChildren().add(empty);
        } else {
            for (MutableItem it : colItems) cards.getChildren().add(buildKanbanCard(it, color));
        }

        ScrollPane cardScroll = new ScrollPane(cards);
        cardScroll.setFitToWidth(true);
        cardScroll.setHbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
        cardScroll.setStyle("-fx-background-color:#f7fbff; -fx-border-color:transparent;");
        VBox.setVgrow(cardScroll, Priority.ALWAYS);

        VBox col = new VBox(0, colHeader, cardScroll);
        col.setPrefWidth(210); col.setMinWidth(190); col.setMaxWidth(240);
        col.setStyle("-fx-background-color:#f7fbff;"
                + " -fx-border-color:#b8cfe8; -fx-border-radius:6; -fx-background-radius:6;"
                + " -fx-effect:dropshadow(gaussian,rgba(3,24,62,0.07),8,0.2,0,2);");
        VBox.setVgrow(col, Priority.ALWAYS);
        return col;
    }

    private VBox buildKanbanCard(MutableItem item, String accentColor) {
        Label numLbl = new Label(String.format("#%02d", items.indexOf(item) + 1));
        numLbl.setStyle("-fx-font-family:'JetBrains Mono','Consolas',monospace;"
                + " -fx-font-size:9px; -fx-text-fill:#9eafc0;");

        Label textLbl = new Label(item.text);
        textLbl.setWrapText(true); textLbl.setMaxWidth(Double.MAX_VALUE);
        textLbl.setStyle((item.done
                ? "-fx-text-fill:#9eafc0; -fx-strikethrough:true;"
                : "-fx-text-fill:#0d1b2a;") + " -fx-font-size:12px; -fx-wrap-text:true;");

        HBox topRow = new HBox(4, numLbl);
        topRow.setAlignment(Pos.CENTER_LEFT);
        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);

        Button cbBtn = new Button(item.done ? "☑" : "☐");
        cbBtn.setStyle("-fx-background-color:transparent; -fx-cursor:hand;"
                + " -fx-font-size:14px; -fx-padding:0 2 0 2;");
        cbBtn.setTooltip(new Tooltip(item.done ? "Marcar como pendente" : "Marcar como concluído"));
        cbBtn.setOnAction(e -> {
            item.done = !item.done;
            item.kanbanColumn = item.done ? "concluido" : "backlog";
            repo.updateDone(item.id, item.done);
            refreshAll();
            if (onChanged != null) onChanged.run();
        });

        topRow.getChildren().addAll(spacer, cbBtn);

        VBox card = new VBox(4, topRow, textLbl);
        card.setStyle("-fx-background-color:white; -fx-background-radius:5;"
                + " -fx-border-color:" + accentColor + "; -fx-border-width:0 0 0 3;"
                + " -fx-border-radius:5; -fx-padding:8 10 8 10; -fx-cursor:hand;"
                + " -fx-effect:dropshadow(gaussian,rgba(0,0,0,0.06),4,0.2,0,1);");

        card.setOnMouseEntered(e -> card.setStyle(
                "-fx-background-color:#f0f7ff; -fx-background-radius:5;"
                + " -fx-border-color:" + accentColor + "; -fx-border-width:0 0 0 3;"
                + " -fx-border-radius:5; -fx-padding:8 10 8 10; -fx-cursor:hand;"
                + " -fx-effect:dropshadow(gaussian,rgba(0,0,0,0.12),6,0.3,0,2);"));
        card.setOnMouseExited(e -> card.setStyle(
                "-fx-background-color:white; -fx-background-radius:5;"
                + " -fx-border-color:" + accentColor + "; -fx-border-width:0 0 0 3;"
                + " -fx-border-radius:5; -fx-padding:8 10 8 10; -fx-cursor:hand;"
                + " -fx-effect:dropshadow(gaussian,rgba(0,0,0,0.06),4,0.2,0,1);"));

        if (item.text.length() > 60) {
            Tooltip tp = new Tooltip(item.text);
            tp.setWrapText(true); tp.setMaxWidth(280);
            Tooltip.install(card, tp);
        }

        card.setOnMouseClicked(e -> {
            if (e.getButton() == MouseButton.SECONDARY) {
                showItemContextMenu(item, textLbl, null, null, card, e.getScreenX(), e.getScreenY());
                e.consume();
            } else if (e.getButton() == MouseButton.PRIMARY) {
                itemContextMenu.hide();
            }
        });

        return card;
    }

    private void showAddItemDialogForColumn(String colKey) {
        TextInputDialog dlg = new TextInputDialog();
        dlg.setTitle("Novo Item");
        dlg.setHeaderText("Adicionar item na coluna \u201c" + columnLabel(colKey) + "\u201d");
        dlg.setContentText("Texto:");
        dlg.showAndWait().ifPresent(text -> {
            if (text.isBlank()) return;
            TaskChecklistItem saved = repo.addItem(task.id(), text);
            if (!"backlog".equals(colKey)) repo.updateColumn(saved.id(), colKey);
            MutableItem mi = new MutableItem(saved);
            mi.kanbanColumn = colKey;
            mi.done = "concluido".equals(colKey);
            items.add(mi);
            refreshAll();
            if (onChanged != null) onChanged.run();
        });
    }

    // ── Modo de edição inline ─────────────────────────────────────────────────

    private void enterEditMode(Label textLbl, TextField editField, MutableItem item, Button editBtn) {
        if (editField == null) return;
        textLbl.setVisible(false); textLbl.setManaged(false);
        editField.setText(item.text);
        editField.setVisible(true); editField.setManaged(true);
        editField.requestFocus(); editField.selectAll();
        if (editBtn != null) editBtn.setText("");

        Runnable save = () -> {
            String newText = editField.getText().trim();
            if (!newText.isBlank() && !newText.equals(item.text)) {
                item.text = newText; repo.updateText(item.id, newText);
                if (onChanged != null) onChanged.run();
            }
            textLbl.setText(item.text);
            textLbl.setVisible(true); textLbl.setManaged(true);
            editField.setVisible(false); editField.setManaged(false);
            if (editBtn != null) editBtn.setText("✏");
        };
        Runnable cancel = () -> {
            textLbl.setVisible(true); textLbl.setManaged(true);
            editField.setVisible(false); editField.setManaged(false);
            if (editBtn != null) editBtn.setText("✏");
        };
        editField.setOnAction(e -> save.run());
        editField.setOnKeyPressed(e -> { if (e.getCode() == javafx.scene.input.KeyCode.ESCAPE) cancel.run(); });
        if (editBtn != null) editBtn.setOnAction(e -> {
            if ("".equals(editBtn.getText())) save.run();
            else enterEditMode(textLbl, editField, item, editBtn);
        });
    }

    // ── Context menu ──────────────────────────────────────────────────────────

    private void showItemContextMenu(MutableItem item, Label textLbl,
                                     TextField editField, Button editBtn,
                                     javafx.scene.Node anchor, double sx, double sy) {
        itemContextMenu.hide();
        itemContextMenu.getItems().clear();
        itemContextMenu.setAutoHide(true);

        MenuItem copyItem = new MenuItem("  Copiar Texto");
        copyItem.setOnAction(e -> copyToClipboard(item.text));

        MenuItem editItem = new MenuItem("✏  Editar");
        if (editField != null) {
            editItem.setOnAction(e -> enterEditMode(textLbl, editField, item, editBtn));
        } else {
            editItem.setOnAction(e -> {
                TextInputDialog dlg = new TextInputDialog(item.text);
                dlg.setTitle("Editar Item"); dlg.setHeaderText(null);
                dlg.setContentText("Texto:");
                dlg.showAndWait().ifPresent(t -> {
                    if (!t.isBlank() && !t.equals(item.text)) {
                        item.text = t; repo.updateText(item.id, t);
                        refreshAll();
                        if (onChanged != null) onChanged.run();
                    }
                });
            });
        }

        MenuItem toggleItem = item.done
                ? new MenuItem("☐  Marcar como Pendente")
                : new MenuItem("✔  Marcar como Concluído");
        toggleItem.setOnAction(e -> {
            item.done = !item.done;
            item.kanbanColumn = item.done ? "concluido"
                    : (item.kanbanColumn.equals("concluido") ? "backlog" : item.kanbanColumn);
            repo.updateDone(item.id, item.done);
            refreshAll();
            if (onChanged != null) onChanged.run();
        });

        Menu moveMenu = new Menu("  Mover para...");
        for (String[] c : KANBAN_COLS) {
            String cKey = c[0], cLabel = c[1].replace("  ", " ").trim();
            MenuItem mi = new MenuItem(cLabel);
            if (cKey.equals(item.kanbanColumn)) mi.setStyle("-fx-font-weight:bold; -fx-text-fill:#1565c0;");
            mi.setOnAction(e -> moveItemToColumn(item, cKey));
            moveMenu.getItems().add(mi);
        }

        SeparatorMenuItem sep = new SeparatorMenuItem();

        MenuItem deleteItem = new MenuItem("  Excluir Item");
        deleteItem.setStyle("-fx-text-fill:#c62828;");
        deleteItem.setOnAction(e -> deleteItem(item));

        itemContextMenu.getItems().addAll(copyItem, editItem, toggleItem, moveMenu, sep, deleteItem);
        itemContextMenu.show(anchor, sx, sy);
    }

    private void moveItemToColumn(MutableItem item, String colKey) {
        item.kanbanColumn = colKey;
        item.done = "concluido".equals(colKey);
        repo.updateColumn(item.id, colKey);
        refreshAll();
        if (onChanged != null) onChanged.run();
    }

    private void deleteItem(MutableItem item) {
        repo.deleteItem(item.id);
        items.remove(item);
        refreshAll();
        if (onChanged != null) onChanged.run();
    }

    // ── Ações em lote ─────────────────────────────────────────────────────────

    private void markAll(boolean done) {
        for (MutableItem it : items) {
            if (it.done != done) {
                it.done = done;
                it.kanbanColumn = done ? "concluido"
                        : (it.kanbanColumn.equals("concluido") ? "backlog" : it.kanbanColumn);
                repo.updateDone(it.id, done);
            }
        }
        refreshAll();
        if (onChanged != null) onChanged.run();
    }

    private void clearDoneItems() {
        long count = items.stream().filter(it -> it.done).count();
        if (count == 0) { new Alert(Alert.AlertType.INFORMATION, "Sem itens concluídos para remover.", ButtonType.OK).showAndWait(); return; }
        Alert confirm = new Alert(Alert.AlertType.CONFIRMATION);
        confirm.setTitle("Limpar Concluídos");
        confirm.setHeaderText("Remover itens concluídos?");
        confirm.setContentText(count + " item(ns) serão excluídos permanentemente.");
        confirm.showAndWait().ifPresent(btn -> {
            if (btn == ButtonType.OK) {
                List<MutableItem> done = items.stream().filter(it -> it.done).toList();
                done.forEach(it -> repo.deleteItem(it.id));
                items.removeAll(done);
                refreshAll();
                if (onChanged != null) onChanged.run();
            }
        });
    }

    // ── Refresh ───────────────────────────────────────────────────────────────

    private void refreshAll() {
        refreshKpiAndProgress();
        refreshContentArea();
    }

    private void refreshKpiAndProgress() {
        int total   = items.size();
        int done    = (int) items.stream().filter(it -> it.done).count();
        int pending = total - done;
        double pct  = total == 0 ? 0.0 : (double) done / total;

        if (kpiTotal   != null) kpiTotal.setText(String.valueOf(total));
        if (kpiDone    != null) kpiDone.setText(String.valueOf(done));
        if (kpiPending != null) kpiPending.setText(String.valueOf(pending));
        if (kpiPercent != null) kpiPercent.setText(Math.round(pct * 100) + "%");

        if (progressBar != null) {
            progressBar.setProgress(pct);
            String accent = pct == 1.0 ? "#1b5e20" : pct >= 0.7 ? "#2e7d32" : pct >= 0.4 ? "#f57f17" : "#c62828";
            progressBar.setStyle("-fx-accent:" + accent
                    + "; -fx-background-color:#d6e4f5; -fx-background-radius:7; -fx-border-radius:7;");
        }
        if (progressLabel != null) progressLabel.setText(
                done + " de " + total + " itens concluídos"
                + (total > 0 ? "  (" + Math.round(pct * 100) + "%)" : ""));
    }

    // ── Rodapé ────────────────────────────────────────────────────────────────

    private HBox buildFooter(Stage stage) {
        Label hint = new Label("  Duplo clique para editar  ·  Botão direito para mais opções  ·  ⬛ Kanban mostra colunas de progresso");
        hint.setStyle("-fx-font-size:11px; -fx-text-fill:#7a9abc;"
                + " -fx-font-family:'JetBrains Mono','Consolas',monospace;");
        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);

        Button printBtn = new Button("  Imprimir Checklist");
        printBtn.getStyleClass().add("secondary-button");
        printBtn.setOnAction(e -> printChecklist());

        Button closeBtn = new Button("✕  Fechar");
        closeBtn.getStyleClass().add("secondary-button");
        closeBtn.setOnAction(e -> stage.close());
        HBox footer = new HBox(12, hint, spacer, printBtn, closeBtn);
        footer.setPadding(new Insets(10, 18, 10, 18)); footer.setAlignment(Pos.CENTER_LEFT);
        footer.setStyle("-fx-background-color:#edf1f8; -fx-border-color:#b8cfe8; -fx-border-width:1 0 0 0;");
        return footer;
    }

    // ── Helpers de Kanban ─────────────────────────────────────────────────────

    private String columnLabel(String key) {
        for (String[] c : KANBAN_COLS) if (c[0].equals(key)) return c[1].replace("  ", " ").trim();
        return key;
    }
    private String columnColor(String key) {
        for (String[] c : KANBAN_COLS) if (c[0].equals(key)) return c[2];
        return "#546e7a";
    }

    // ── Helpers visuais ───────────────────────────────────────────────────────

    private void applyDoneStyle(Label lbl, boolean done) {
        lbl.setStyle(done
                ? "-fx-text-fill:#9eafc0; -fx-strikethrough:true;  -fx-font-size:12px;"
                : "-fx-text-fill:#0d1b2a; -fx-strikethrough:false; -fx-font-size:12px;");
    }

    private void copyToClipboard(String text) {
        ClipboardContent c = new ClipboardContent(); c.putString(text);
        Clipboard.getSystemClipboard().setContent(c);
    }

    // ── Fábrica estática ──────────────────────────────────────────────────────

    public static void open(Task task, Runnable onChanged) {
        TaskChecklistRepository repo = AppContextHolder.get().taskChecklistRepository();
        new TaskChecklistWindow(task, repo, onChanged).show();
    }
}

package com.pessoal.agenda.ui.view;

import com.pessoal.agenda.model.Task;
import com.pessoal.agenda.model.TaskSession;
import com.pessoal.agenda.repository.TaskSessionRepository;
import javafx.application.Platform;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.BorderPane;
import javafx.scene.layout.HBox;
import javafx.scene.layout.GridPane;
import javafx.scene.layout.Priority;
import javafx.scene.layout.Region;
import javafx.scene.layout.VBox;
import javafx.stage.Modality;
import javafx.stage.Stage;

import java.time.LocalDate;
import java.util.List;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledFuture;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicLong;

/** Robust timer window for task sessions with history and metadata. */

public class TaskTimerWindow {
    // Gerencia janelas abertas por taskId
    private static final java.util.Map<Long, Stage> openWindows = new java.util.HashMap<>();

    private final Task task;
    private final TaskSessionRepository repo;
    private Stage stage;

    // UI
    private Button playPauseBtn;
    private Button stopBtn;
    private Button resetBtn;
    private Label timerLabel;
    private TextArea notesArea;
    private Label totalLabel;
    private ListView<String> historyList;

    // Estado do timer (apenas flags locais)
    private volatile boolean running = false;

    private final Runnable refreshCallback;

    // Para remover o tickListener ao fechar
    private Runnable tickUnsubscriber = null;
    // Tick listener para este timer
    private java.util.function.Consumer<Long> tickListener;

    public TaskTimerWindow(Task task, TaskSessionRepository repo, Runnable refreshCallback) {
        this.task = task; this.repo = repo; this.refreshCallback = refreshCallback;
        this.tickListener = sec -> {
            var timerService = com.pessoal.agenda.service.TaskTimerService.get();
            if (timerService.getActiveTaskId() != null && timerService.getActiveTaskId().equals(task.id())) {
                javafx.application.Platform.runLater(() -> timerLabel.setText(formatTimer(sec)));
            }
        };
    }
    public TaskTimerWindow(Task task, TaskSessionRepository repo) {
        this(task, repo, null);
    }

    public void show() {
        // ── Evita abrir duplicata para a mesma tarefa ──
        Stage existing = openWindows.get(task.id());
        if (existing != null && existing.isShowing()) {
            existing.toFront();
            existing.requestFocus();
            return;
        }

        stage = new Stage();
        openWindows.put(task.id(), stage);
        WindowManager.register(stage);
        stage.initModality(Modality.NONE);
        stage.setTitle("Timer — " + task.title());

        BorderPane root = new BorderPane();
        root.getStyleClass().add("app-root");

        // ── Barra superior elegante ──
        Label title = new Label("Timer da tarefa");
        title.getStyleClass().add("page-title");
        Label typeBadge = new Label(task.priority() != null ? "  " + task.priority().label() + "  " : "  NORMAL  ");
        typeBadge.getStyleClass().addAll("study-badge", "badge-type");
        HBox headerBar = new HBox(10, title, typeBadge);
        headerBar.getStyleClass().add("header-bar");
        headerBar.setPadding(new Insets(16, 28, 16, 28));
        headerBar.setAlignment(Pos.CENTER_LEFT);

        // Espaço extra entre headerBar e main
        Region spacer = new Region();
        spacer.setMinHeight(10); // ajuste conforme necessário
        VBox topContainer = new VBox(headerBar, spacer);
        root.setTop(topContainer);

        // ── Painel central com controles e histórico ──
        HBox main = new HBox(24);
        main.setPadding(new Insets(0, 28, 18, 28));

        // Coluna esquerda: metadados, controles, notas
        VBox left = new VBox(16);
        left.setPrefWidth(360);

        GridPane metaGrid = new GridPane();
        metaGrid.setHgap(8);
        metaGrid.setVgap(6);
        metaGrid.add(new Label("Tarefa:"), 0, 0);
        Label taskTitleLbl = new Label(task.title());
        taskTitleLbl.getStyleClass().add("section-title");
        metaGrid.add(taskTitleLbl, 1, 0);
        metaGrid.add(new Label("Categoria:"), 0, 1);
        Label catLbl = new Label(task.category() == null ? "Geral" : task.category());
        catLbl.getStyleClass().add("study-plan-detail");
        metaGrid.add(catLbl, 1, 1);
        metaGrid.add(new Label("Vencimento:"), 0, 2);
        metaGrid.add(new Label(task.dueDate() != null ? task.dueDate().toString() : "—"), 1, 2);
        metaGrid.add(new Label("Status:"), 0, 3);
        metaGrid.add(new Label(task.status() != null ? task.status().label() : "PENDENTE"), 1, 3);

        // Timer controls
        timerLabel = new Label("00:00:00");
        timerLabel.getStyleClass().add("page-title");
        playPauseBtn = new Button("▶");
        playPauseBtn.getStyleClass().addAll("primary-button", "icon-button");
        playPauseBtn.setPrefWidth(56);
        stopBtn = new Button("■");
        stopBtn.getStyleClass().addAll("danger-button", "icon-button");
        stopBtn.setPrefWidth(56);
        resetBtn = new Button("⟲");
        resetBtn.getStyleClass().addAll("secondary-button", "icon-button");
        resetBtn.setPrefWidth(56);
        HBox controls = new HBox(8, playPauseBtn, stopBtn, resetBtn, timerLabel);
        controls.setAlignment(Pos.CENTER_LEFT);

        // Notes
        Label notesLbl = new Label("Observações da sessão:");
        notesLbl.getStyleClass().add("form-label");
        notesArea = new TextArea();
        notesArea.getStyleClass().add("input-control");
        notesArea.setPrefRowCount(4);

        left.getChildren().addAll(metaGrid, controls, notesLbl, notesArea);
        VBox.setVgrow(notesArea, Priority.ALWAYS);

        // Coluna direita: histórico e total
        VBox right = new VBox(12);
        right.setPrefWidth(260);
        Label histTitle = new Label("Histórico de sessões");
        histTitle.getStyleClass().add("section-title");
        historyList = new ListView<>();
        historyList.setPrefHeight(260);
        totalLabel = new Label("Tempo total: 0 min");
        totalLabel.getStyleClass().add("section-title");
        right.getChildren().addAll(histTitle, historyList, totalLabel);
        VBox.setVgrow(historyList, Priority.ALWAYS);

        main.getChildren().addAll(left, right);
        HBox.setHgrow(left, Priority.ALWAYS);
        HBox.setHgrow(right, Priority.NEVER);

        root.setCenter(main);

        // Handlers
        playPauseBtn.setOnAction(e -> toggle());
        stopBtn.setOnAction(e -> stopAndSave());
        resetBtn.setOnAction(e -> resetCounter());

        Scene sc = new Scene(root, 700, 440);
        var cssUrl = TaskTimerWindow.class.getResource("/com/pessoal/agenda/app.css");
        if (cssUrl != null) sc.getStylesheets().add(cssUrl.toExternalForm());
        stage.setScene(sc);
        stage.setOnHiding(e -> {
            // Remove tickListener e referência da janela
            if (tickUnsubscriber != null) tickUnsubscriber.run();
            openWindows.remove(task.id());
            if (refreshCallback != null) refreshCallback.run();
        });

        // Atualiza o label do timer com o valor global
        updateTimerLabelFromService();
        // Listener para ticks globais (agora múltiplos listeners)
        var timerService = com.pessoal.agenda.service.TaskTimerService.get();
        timerService.addTickListener(tickListener);
        tickUnsubscriber = () -> timerService.removeTickListener(tickListener);

        loadHistory();
        updateTotalLabel();
        stage.show();
    }

    private synchronized void toggle() {
        var timerService = com.pessoal.agenda.service.TaskTimerService.get();
        if (!timerService.isRunning() || timerService.getActiveTaskId() == null || !timerService.getActiveTaskId().equals(task.id())) {
            startTimer();
        } else {
            pauseTimer();
        }
    }

    private synchronized void startTimer() {
        var timerService = com.pessoal.agenda.service.TaskTimerService.get();
        timerService.start(task.id());
        playPauseBtn.setText("⏸");
        if (refreshCallback != null) Platform.runLater(refreshCallback);
    }

    private synchronized void pauseTimer() {
        var timerService = com.pessoal.agenda.service.TaskTimerService.get();
        timerService.pause();
        playPauseBtn.setText("▶");
        if (refreshCallback != null) Platform.runLater(refreshCallback);
    }

    private synchronized void resumeTimer() {
        var timerService = com.pessoal.agenda.service.TaskTimerService.get();
        timerService.resume();
        playPauseBtn.setText("⏸");
        if (refreshCallback != null) Platform.runLater(refreshCallback);
    }

    // Não há mais tick local

    private synchronized void stopAndSave() {
        var timerService = com.pessoal.agenda.service.TaskTimerService.get();
        timerService.stop();
        playPauseBtn.setText("▶");
        if (refreshCallback != null) Platform.runLater(refreshCallback);
        showSaveSessionDialog(task, repo, notesArea.getText(), () -> {
            Platform.runLater(() -> timerLabel.setText("00:00:00"));
            notesArea.clear();
            loadHistory(); updateTotalLabel();
        });
    }

    /** Utilitário para exibir o diálogo de salvar sessão, reutilizável pela lista principal. */
    public static void showSaveSessionDialog(Task task, TaskSessionRepository repo, String notesText, Runnable onSave) {
        var timerService = com.pessoal.agenda.service.TaskTimerService.get();
        long s = timerService.getElapsedSeconds();
        int minutes = (int) Math.max(1, Math.round(s / 60.0));
        Dialog<ButtonType> dlg = new Dialog<>();
        dlg.setTitle("Salvar sessão"); dlg.setHeaderText("Salvar sessão de trabalho para a tarefa?");
        ButtonType saveBtn = new ButtonType("Salvar", ButtonBar.ButtonData.OK_DONE);
        dlg.getDialogPane().getButtonTypes().addAll(saveBtn, ButtonType.CANCEL);
        TextField titleField = new TextField("Tarefa:#" + task.id() + " — " + task.title());
        Spinner<Integer> minutesSpinner = new Spinner<>(1, 24*60, minutes);
        TextArea notes = new TextArea(notesText != null ? notesText : ""); notes.setPrefRowCount(4);
        VBox content = new VBox(8, new Label("Título:"), titleField, new Label("Duração (min):"), minutesSpinner, new Label("Observações:"), notes);
        content.setPadding(new Insets(8));
        dlg.getDialogPane().setContent(content);
        dlg.setResultConverter(bt -> bt == saveBtn ? saveBtn : null);
        dlg.showAndWait().ifPresent(res -> {
            if (res == saveBtn) {
                int m = minutesSpinner.getValue();
                String subj = titleField.getText();
                String noteTxt = notes.getText();
                repo.save(task.id(), subj, LocalDate.now(), m, noteTxt);
                if (onSave != null) onSave.run();
            }
        });
    }

    private void resetCounter() {
        pauseTimer();
        var timerService = com.pessoal.agenda.service.TaskTimerService.get();
        timerService.reset();
        Platform.runLater(() -> timerLabel.setText("00:00:00"));
        if (refreshCallback != null) Platform.runLater(refreshCallback);
    }

    private void updateTimerLabelFromService() {
        var timerService = com.pessoal.agenda.service.TaskTimerService.get();
        if (timerService.getActiveTaskId() != null && timerService.getActiveTaskId().equals(task.id())) {
            timerLabel.setText(formatTimer(timerService.getElapsedSeconds()));
        } else {
            timerLabel.setText("00:00:00");
        }
    }

    private static String formatTimer(long s) {
        long hh = s / 3600; long mm = (s % 3600) / 60; long ss = s % 60;
        return String.format("%02d:%02d:%02d", hh, mm, ss);
    }

    private void loadHistory() {
        try {
            List<TaskSession> sessions = repo.findByTaskId(task.id());
            Platform.runLater(() -> {
                historyList.getItems().clear();
                for (TaskSession s : sessions) {
                    historyList.getItems().add(String.format("%s — %d min — %s", s.sessionDate(), s.durationMinutes(), s.notes() == null ? "" : s.notes()));
                }
            });
        } catch (Throwable ex) {
            System.err.println("[TaskTimerWindow] failed loading history: " + ex.getMessage());
        }
    }

    private void updateTotalLabel() {
        try {
            List<TaskSession> sessions = repo.findByTaskId(task.id());
            int total = sessions.stream().mapToInt(TaskSession::durationMinutes).sum();
            Platform.runLater(() -> totalLabel.setText("Tempo total: " + total + " min"));
        } catch (Throwable ex) {
            System.err.println("[TaskTimerWindow] failed updating total: " + ex.getMessage());
        }
    }
}

