        timerService.stop();
        playPauseBtn.setText("▶");
        if (refreshCallback != null) Platform.runLater(refreshCallback);
        showSaveSessionDialog(task, repo, notesArea.getText(), () -> {
            Platform.runLater(() -> timerLabel.setText("00:00:00"));
            notesArea.clear();
            loadHistory(); updateTotalLabel();
        });
    }

    /** Utilitário para exibir o diálogo de salvar sessão, reutilizável pela lista principal. */
    public static void showSaveSessionDialog(Task task, TaskSessionRepository repo, String notesText, Runnable onSave) {
        var timerService = com.pessoal.agenda.service.TaskTimerService.get();
        long s = timerService.getElapsedSeconds();
        int minutes = (int) Math.max(1, Math.round(s / 60.0));
        Dialog<ButtonType> dlg = new Dialog<>();
        dlg.setTitle("Salvar sessão"); dlg.setHeaderText("Salvar sessão de trabalho para a tarefa?");
        ButtonType saveBtn = new ButtonType("Salvar", ButtonBar.ButtonData.OK_DONE);
        dlg.getDialogPane().getButtonTypes().addAll(saveBtn, ButtonType.CANCEL);
        TextField titleField = new TextField("Tarefa:#" + task.id() + " — " + task.title());
        Spinner<Integer> minutesSpinner = new Spinner<>(1, 24*60, minutes);
        TextArea notes = new TextArea(notesText != null ? notesText : ""); notes.setPrefRowCount(4);
        VBox content = new VBox(8, new Label("Título:"), titleField, new Label("Duração (min):"), minutesSpinner, new Label("Observações:"), notes);
        content.setPadding(new Insets(8));
        dlg.getDialogPane().setContent(content);
        dlg.setResultConverter(bt -> bt == saveBtn ? saveBtn : null);
        dlg.showAndWait().ifPresent(res -> {
            if (res == saveBtn) {
                int m = minutesSpinner.getValue();
                String subj = titleField.getText();
                String noteTxt = notes.getText();
                repo.save(task.id(), subj, LocalDate.now(), m, noteTxt);
                if (onSave != null) onSave.run();
            }
        });
    }

    private void resetCounter() {
        pauseTimer();
        var timerService = com.pessoal.agenda.service.TaskTimerService.get();
        timerService.reset();
        Platform.runLater(() -> timerLabel.setText("00:00:00"));
        if (refreshCallback != null) Platform.runLater(refreshCallback);
    }

    private void updateTimerLabelFromService() {
        var timerService = com.pessoal.agenda.service.TaskTimerService.get();
        if (timerService.getActiveTaskId() != null && timerService.getActiveTaskId().equals(task.id())) {
            timerLabel.setText(formatTimer(timerService.getElapsedSeconds()));
        } else {
            timerLabel.setText("00:00:00");
        }
    }

    private static String formatTimer(long s) {
        long hh = s / 3600; long mm = (s % 3600) / 60; long ss = s % 60;
        return String.format("%02d:%02d:%02d", hh, mm, ss);
    }

    private void loadHistory() {
        try {
            List<TaskSession> sessions = repo.findByTaskId(task.id());
            Platform.runLater(() -> {
                historyList.getItems().clear();
                for (TaskSession s : sessions) {
                    historyList.getItems().add(String.format("%s — %d min — %s", s.sessionDate(), s.durationMinutes(), s.notes() == null ? "" : s.notes()));
                }
            });
        } catch (Throwable ex) {
            System.err.println("[TaskTimerWindow] failed loading history: " + ex.getMessage());
        }
    }

    private void updateTotalLabel() {
        try {
            List<TaskSession> sessions = repo.findByTaskId(task.id());
            int total = sessions.stream().mapToInt(TaskSession::durationMinutes).sum();
            Platform.runLater(() -> totalLabel.setText("Tempo total: " + total + " min"));
        } catch (Throwable ex) {
            System.err.println("[TaskTimerWindow] failed updating total: " + ex.getMessage());
        }
    }
}

package com.pessoal.agenda.ui.view;

import javafx.collections.ObservableList;
import javafx.scene.Parent;
import javafx.scene.Scene;

import java.util.*;
import java.util.function.Consumer;
import java.util.prefs.Preferences;

/**
 * Gerenciador de temas da aplicação.
 *
 * Pattern: Singleton — disponível em toda a aplicação.
 *
 * Uso:
 *   ThemeManager.getInstance().applyTo(scene);   // ao criar uma cena
 *   ThemeManager.getInstance().applyTo(root);    // ao criar um root node sem scene
 *   ThemeManager.getInstance().setTheme(Theme.ESCURO);  // troca o tema globalmente
 */
public class ThemeManager {

    // ── Temas disponíveis ──────────────────────────────────────────────────
    public enum Theme {
        CLARO  ("☀️  Claro",         null),
        ESCURO ("  Escuro",         "/com/pessoal/agenda/theme-dark.css");

        public final String label;
        public final String cssResource;

        Theme(String label, String cssResource) {
            this.label       = label;
            this.cssResource = cssResource;
        }
    }

    // ── Singleton ──────────────────────────────────────────────────────────
    private static final ThemeManager INSTANCE = new ThemeManager();
    public  static ThemeManager getInstance() { return INSTANCE; }

    private static final String APP_CSS = "/com/pessoal/agenda/app.css";

    // ── Estado ────────────────────────────────────────────────────────────
    private Theme currentTheme;

    /**
     * Registro fraco: cada entrada é a lista de stylesheets de uma cena ou nó.
     * WeakHashMap garante que entradas órfãs (janelas fechadas) sejam coletadas.
     */
    private final Map<ObservableList<String>, Void> registered =
            Collections.synchronizedMap(new WeakHashMap<>());

    private final List<Consumer<Theme>> listeners = new ArrayList<>();

    // ── Construtor ────────────────────────────────────────────────────────
    private ThemeManager() {
        Preferences prefs = Preferences.userNodeForPackage(ThemeManager.class);
        try {
            currentTheme = Theme.valueOf(prefs.get("agenda.theme", Theme.CLARO.name()));
        } catch (Exception e) {
            currentTheme = Theme.CLARO;
        }
    }

    // ── API pública ────────────────────────────────────────────────────────

    public Theme getTheme() { return currentTheme; }

    /** Aplica o tema atual a uma Scene e registra para atualizações futuras. */
    public void applyTo(Scene scene) {
        applyToList(scene.getStylesheets());
    }

    /** Aplica o tema atual ao stylesheet de um nó raiz e registra para atualizações futuras. */
    public void applyTo(Parent root) {
        applyToList(root.getStylesheets());
    }

    /** Troca o tema globalmente, atualizando TODAS as cenas/nós registrados. */
    public void setTheme(Theme theme) {
        if (theme == currentTheme) return;
        this.currentTheme = theme;
        Preferences.userNodeForPackage(ThemeManager.class).put("agenda.theme", theme.name());
        updateAllRegistered();
        listeners.forEach(l -> l.accept(theme));
    }

    /** Registra um ouvinte chamado cada vez que o tema mudar. */
    public void addThemeChangeListener(Consumer<Theme> listener) {
        listeners.add(listener);
    }

    public void removeThemeChangeListener(Consumer<Theme> listener) {
        listeners.remove(listener);
    }

    // ── Implementação interna ──────────────────────────────────────────────

    private void applyToList(ObservableList<String> sheets) {
        String appUrl = resolveUrl(APP_CSS);
        if (appUrl == null) return;

        // Garante que app.css está na posição 0
        if (!sheets.contains(appUrl)) {
            sheets.add(0, appUrl);
        }
        // Remove CSS de tema anterior
        sheets.removeIf(s -> s != null && s.contains("/theme-"));
        // Adiciona CSS do tema atual (se não for o padrão Claro)
        if (currentTheme.cssResource != null) {
            String themeUrl = resolveUrl(currentTheme.cssResource);
            if (themeUrl != null && !sheets.contains(themeUrl)) {
                sheets.add(themeUrl);
            }
        }
        // Registra para atualizações futuras
        registered.put(sheets, null);
    }

    private void updateAllRegistered() {
        // Atenção: iteramos sobre uma cópia do keySet para evitar ConcurrentModificationException
        List<ObservableList<String>> snapshot;
        synchronized (registered) {
            snapshot = new ArrayList<>(registered.keySet());
        }
        for (ObservableList<String> sheets : snapshot) {
            // Remove override de tema
            sheets.removeIf(s -> s != null && s.contains("/theme-"));
            // Adiciona novo override
            if (currentTheme.cssResource != null) {
                String themeUrl = resolveUrl(currentTheme.cssResource);
                if (themeUrl != null && !sheets.contains(themeUrl)) {
                    sheets.add(themeUrl);
                }
            }
        }
    }

    private String resolveUrl(String resource) {
        try {
            var url = ThemeManager.class.getResource(resource);
            return (url != null) ? url.toExternalForm() : null;
        } catch (Exception e) {
            return null;
        }
    }
}

package com.pessoal.agenda.ui.view;

import javafx.stage.Stage;
import java.util.Collections;
import java.util.HashSet;
import java.util.Set;

/**
 * Gerencia janelas secundárias abertas para permitir fechamento global.
 */
public class WindowManager {
    private static final Set<Stage> openStages = Collections.synchronizedSet(new HashSet<>());

    public static void register(Stage stage) {
        openStages.add(stage);
        stage.setOnHiding(e -> openStages.remove(stage));
    }

    public static void closeAll() {
        synchronized (openStages) {
            for (Stage s : openStages) {
                if (s.isShowing()) s.close();
            }
            openStages.clear();
        }
    }
}

package com.pessoal.agenda.ui.view;

import javafx.stage.Stage;
import java.util.Collections;
import java.util.HashSet;
import java.util.Set;

/**
 * Gerencia janelas secundárias abertas para permitir fechamento global.
 * Ao registrar uma janela, o tema atual é automaticamente aplicado à cena.
 */
public class WindowManager {
    private static final Set<Stage> openStages = Collections.synchronizedSet(new HashSet<>());

    public static void register(Stage stage) {
        openStages.add(stage);
        stage.setOnHiding(e -> openStages.remove(stage));
        // Aplica tema atual à cena da janela (se já houver cena)
        if (stage.getScene() != null) {
            ThemeManager.getInstance().applyTo(stage.getScene());
        }
    }

    public static void closeAll() {
        synchronized (openStages) {
            for (Stage s : openStages) {
                if (s.isShowing()) s.close();
            }
            openStages.clear();
        }
    }
}

