/* ═══════════════════════════════════════════════════════════════════════════
   AGENDA CIENTÍFICA — SISTEMA DE PLANEJAMENTO PESSOAL
   Visual: Padrão científico/acadêmico — laboratório, pesquisa, precisão
   Paleta: Azul escuro + Ciano + Âmbar + Teal
   ═══════════════════════════════════════════════════════════════════════════ */
.root {
    -fx-font-family: "Inter", "Segoe UI", "DejaVu Sans", sans-serif;
    -fx-font-size: 13px;
}
.app-root { -fx-background-color: #edf1f8; }
/* ── Cabeçalho ───────────────────────────────────────────────────────────── */
.header-bar {
    -fx-background-color: linear-gradient(to right, #03183e 0%, #072d5e 100%);
    -fx-border-color: #00b4d8;
    -fx-border-width: 0 0 2 0;
    -fx-effect: dropshadow(gaussian, rgba(0,180,216,0.25), 14, 0.4, 0, 4);
}
.header-bar .page-title {
    -fx-text-fill: #f0f8ff;
}
.page-title {
    -fx-text-fill: #222;
    -fx-font-size: 21px;
    -fx-font-weight: 700;
}
.page-subtitle {
    -fx-text-fill: #7ec8e3;
    -fx-font-size: 11.5px;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace;
}
/* ── Abas ────────────────────────────────────────────────────────────────── */
.main-tabs { -fx-tab-min-height: 36px; -fx-tab-max-height: 36px; }
.main-tabs .tab-header-area .tab-header-background { -fx-background-color: #d6e4f5; }
.main-tabs .tab {
    -fx-background-color: #cddaed;
    -fx-padding: 6 14 6 14;
    -fx-font-weight: 600;
    -fx-font-size: 12px;
    -fx-text-base-color: #1e3a5f;
}
.main-tabs .tab:selected {
    -fx-background-color: #ffffff;
    -fx-text-base-color: #03183e;
    -fx-border-color: transparent transparent #1565c0 transparent;
    -fx-border-width: 0 0 3 0;
}
/* ── Cards de seção ──────────────────────────────────────────────────────── */
.section-card {
    -fx-background-color: #ffffff;
    -fx-background-radius: 8;
    -fx-border-radius: 8;
    -fx-border-color: #b8cfe8;
    -fx-border-width: 1;
