}
.kpi-blue   { -fx-border-color: #1565c0; } .kpi-blue   .kpi-value { -fx-text-fill: #1565c0; }
.kpi-red    { -fx-border-color: #b71c1c; } .kpi-red    .kpi-value { -fx-text-fill: #b71c1c; }
.kpi-orange { -fx-border-color: #e65100; } .kpi-orange .kpi-value { -fx-text-fill: #e65100; }
.kpi-purple { -fx-border-color: #6a1b9a; } .kpi-purple .kpi-value { -fx-text-fill: #6a1b9a; }
.kpi-cyan   { -fx-border-color: #006d8f; } .kpi-cyan   .kpi-value { -fx-text-fill: #006d8f; }
