    -fx-font-size: 11px; -fx-padding: 3 5 3 5; -fx-background-radius: 4;
    -fx-cursor: hand; -fx-font-family: "JetBrains Mono", "Consolas", monospace;
}
.recurrence-day-check:selected { -fx-text-fill: #1565c0; -fx-font-weight: 700; }
.form-label { -fx-font-size: 12px; -fx-text-fill: #1e3a5f; -fx-font-weight: 600; }
/* ── Configurações — painéis de categoria ────────────────────────────────── */
.config-section {
    -fx-background-color: #ffffff;
    -fx-background-radius: 8;
    -fx-border-color: #b8cfe8;
    -fx-border-radius: 8;
    -fx-border-width: 0 0 0 5;
    -fx-effect: dropshadow(gaussian, rgba(3,24,62,0.07), 10, 0.2, 0, 3);
}
.config-task      { -fx-border-color: #1565c0; }
.config-checklist { -fx-border-color: #006d5b; }
.config-study     { -fx-border-color: #e65100; }
.config-idea      { -fx-border-color: #6a1b9a; }
/* ── Estado vazio ────────────────────────────────────────────────────────── */
.empty-state-label {
    -fx-font-size: 13px; -fx-text-fill: #7a9bbf;
    -fx-font-style: italic;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace;
}
/* ── ScrollPane sem borda visível ────────────────────────────────────────── */
.edge-to-edge { -fx-background-color: transparent; -fx-border-color: transparent; -fx-padding: 0; }
.edge-to-edge .viewport { -fx-background-color: transparent; }

/* ── Diálogo de confirmação ──────────────────────────────────────────────── */
.confirm-dialog {
    -fx-background-color: #ffffff;
    -fx-border-color: #b8cfe8;
    -fx-border-width: 1;
    -fx-font-family: "Inter", "Segoe UI", sans-serif;
}
.confirm-dialog .header-panel {
    -fx-background-color: #03183e;
}
.confirm-dialog .header-panel .label {
    -fx-text-fill: #f0f8ff;
    -fx-font-weight: 700;
    -fx-font-size: 13px;
}
.confirm-dialog .content.label {
    -fx-text-fill: #1e3a5f;
    -fx-font-size: 12.5px;
}

/* ═══════════════════════════════════════════════════════════════════════════
   ABA DE ESTUDOS E ATIVIDADES
   ═══════════════════════════════════════════════════════════════════════════ */

/* ── Células da lista de planos ──────────────────────────────────────────── */
.study-plan-title {
    -fx-font-size: 13px;
    -fx-font-weight: 700;
    -fx-text-fill: #0d1b2a;
}
.study-plan-detail {
    -fx-font-size: 10.5px;
    -fx-text-fill: #5a7a9e;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace;
}

/* ── Badges de tipo e status ─────────────────────────────────────────────── */
.study-badge {
    -fx-padding: 2 8 2 8;
    -fx-background-radius: 10;
    -fx-font-size: 10px;
    -fx-font-weight: 700;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace;
}
.badge-type                { -fx-background-color: #dce8f8; -fx-text-fill: #1565c0; }
.badge-status-planejado    { -fx-background-color: #e8eaf6; -fx-text-fill: #283593; }
.badge-status-em_andamento { -fx-background-color: #fff3e0; -fx-text-fill: #e65100; }
.badge-status-concluido    { -fx-background-color: #e8f5e9; -fx-text-fill: #1b5e20; }
.badge-status-pausado      { -fx-background-color: #fce4ec; -fx-text-fill: #880e4f; }
.badge-status-abandonado   { -fx-background-color: #f5f5f5; -fx-text-fill: #757575; }

/* ── Barra de progresso nos cards de plano ───────────────────────────────── */
.study-progress-bar {
    -fx-pref-height: 9px;
    -fx-min-height:  9px;
}
.study-progress-bar .bar {
    -fx-background-color: linear-gradient(to right, #1565c0, #0d47a1);
    -fx-background-radius: 4;
    -fx-background-insets: 0;
}
.study-progress-bar .track {
    -fx-background-color: #e2ecf8;
    -fx-background-radius: 4;
    -fx-background-insets: 0;
}
.study-progress-bar.progress-complete .bar { -fx-background-color: linear-gradient(to right, #1b5e20, #2e7d32); }
.study-progress-bar.progress-high     .bar { -fx-background-color: linear-gradient(to right, #33691e, #558b2f); }
.study-progress-bar.progress-low      .bar { -fx-background-color: linear-gradient(to right, #b71c1c, #c62828); }

.study-progress-label {
    -fx-font-size: 11.5px;
    -fx-font-weight: 700;
    -fx-text-fill: #1565c0;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace;
}

/* ── Labels de prazo ─────────────────────────────────────────────────────── */
.deadline-ok {
    -fx-text-fill: #1b5e20;
    -fx-font-size: 10.5px;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace;
}
.deadline-warn {
    -fx-text-fill: #e65100;
    -fx-font-size: 10.5px;
    -fx-font-weight: 700;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace;
}
.deadline-overdue {
    -fx-text-fill: #b71c1c;
    -fx-font-size: 10.5px;
    -fx-font-weight: 700;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace;
}

/* ── Label de datas ──────────────────────────────────────────────────────── */
.study-dates-label {
    -fx-font-size: 11.5px;
    -fx-text-fill: #5a7a9e;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace;
}

/* ═══════════════════════════════════════════════════════════════════════════
   DIÁRIO CIENTÍFICO (StudyDiaryWindow)
   ═══════════════════════════════════════════════════════════════════════════ */
.diary-header-bar {
    -fx-background-color: linear-gradient(to right, #03183e 0%, #072d5e 100%);
    -fx-border-color: transparent transparent #00b4d8 transparent;
    -fx-border-width: 0 0 2 0;
    -fx-effect: dropshadow(gaussian, rgba(0,180,216,0.22), 14, 0.35, 0, 4);
}
.diary-header-bar .page-title  { -fx-text-fill: #f0f8ff; }
.diary-header-bar .label       { -fx-text-fill: #a8d4e6; }
.diary-stats-label {
    -fx-text-fill: #7ec8e3;
    -fx-font-size: 11px;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace;
}

/* ═══════════════════════════════════════════════════════════════════════════
   KPI COMPACTO — para uso dentro das abas (menor que o do dashboard)
   ═══════════════════════════════════════════════════════════════════════════ */
.kpi-mini {
    -fx-background-color: #ffffff;
    -fx-background-radius: 7;
    -fx-border-color: #b8cfe8;
    -fx-border-radius: 7;
    -fx-border-width: 0 0 0 4;
    -fx-effect: dropshadow(gaussian, rgba(3,24,62,0.07), 6, 0.15, 0, 2);
    -fx-padding: 8 12 8 12;
    -fx-min-width: 130;
}
.kpi-mini .kpi-title { -fx-font-size: 10px; }
.kpi-mini .kpi-value { -fx-font-size: 22px; }

/* ── Filtros de toggle (status / período) ───────────────────────────────── */
.filter-box {
    -fx-background-color: #f0f5fc;
    -fx-background-radius: 7;
    -fx-border-color: #cad8ee;
    -fx-border-radius: 7;
    -fx-padding: 8 10 8 10;
}
.filter-toggle {
    -fx-background-color: #ffffff;
    -fx-background-radius: 14;
    -fx-border-color: #a8c0de;
    -fx-border-radius: 14;
    -fx-text-fill: #2c4a72;
    -fx-font-size: 11.5px;
    -fx-padding: 3 11 3 11;
    -fx-cursor: hand;
}
.filter-toggle:hover {
    -fx-background-color: #dce8f8;
    -fx-border-color: #5c85c0;
}
.filter-toggle:selected {
    -fx-background-color: #1565c0;
    -fx-border-color: #1565c0;
    -fx-text-fill: white;
    -fx-font-weight: 700;
}
/* período: verde-teal para distinguir visualmente do grupo de status */
.filter-toggle.period-toggle:selected {
    -fx-background-color: #00695c;
    -fx-border-color: #00695c;
}

/* ── Monitor de Frequência — Calendário ─────────────────────────────────── */
.calendar-week-header {
    -fx-font-weight: 700;
    -fx-font-size: 11px;
    -fx-text-fill: #2c4a72;
    -fx-padding: 2 0 2 0;
}
.calendar-day {
    -fx-background-color: #f0f5fc;
    -fx-background-radius: 6;
    -fx-border-color: #c8d9ee;
    -fx-border-radius: 6;
    -fx-cursor: default;
}
.calendar-day-num  { -fx-font-size: 11px; -fx-font-weight: 700; -fx-text-fill: #4a6382; }
.calendar-day-sym  { -fx-font-size: 14px; -fx-font-weight: 700; }
.calendar-today    { -fx-border-color: #1565c0 !important; -fx-border-width: 2; }

/* Status de frequência */
.attend-present     { -fx-background-color: #e8f5e9; }
.attend-present .calendar-day-sym  { -fx-text-fill: #2e7d32; }
.attend-partial     { -fx-background-color: #fff9c4; }
.attend-partial .calendar-day-sym  { -fx-text-fill: #f57f17; }
.attend-absent      { -fx-background-color: #ffebee; }
.attend-absent .calendar-day-sym   { -fx-text-fill: #c62828; }
.attend-compensated { -fx-background-color: #e3f2fd; }
.attend-compensated .calendar-day-sym { -fx-text-fill: #1565c0; }
.attend-future      { -fx-background-color: #f3e5f5; }
.attend-future .calendar-day-sym   { -fx-text-fill: #6a1b9a; }
.attend-none        { -fx-background-color: #f5f5f5; }
.attend-none .calendar-day-sym     { -fx-text-fill: #bdbdbd; }

/* Legenda */
.calendar-legend { -fx-font-size: 11px; -fx-padding: 1 6 1 6;
                   -fx-background-radius: 10; -fx-border-radius: 10; }

/* Card de compensação */
.comp-card {
    -fx-background-color: #ffffff;
    -fx-background-radius: 7;
    -fx-border-color: #c8d9ee;
    -fx-border-radius: 7;
    -fx-effect: dropshadow(gaussian, rgba(3,24,62,0.06), 4, 0.1, 0, 1);
}

/* KPI color variants */
.kpi-red { -fx-border-color: #e53935; }
.kpi-red-value { -fx-text-fill: #c62828; }

/* ── Ideias e Projetos — Kanban & Cards ──────────────────────────────────── */
.ideas-kanban-scroll {
    -fx-background-color: #edf1f8;
    -fx-border-color: transparent;
}
.ideas-kanban-scroll > .viewport {
    -fx-background-color: #edf1f8;
}
.idea-card {
    -fx-background-color: white;
    -fx-background-radius: 6;
    -fx-border-radius: 6;
    -fx-border-width: 0 0 0 4;
    -fx-padding: 8 12 8 12;
    -fx-effect: dropshadow(gaussian, rgba(3,24,62,0.07), 6, 0.2, 0, 2);
    -fx-cursor: hand;
}
.idea-badge {
    -fx-font-size: 10px;
    -fx-font-weight: 600;
    -fx-padding: 2 7 2 7;
    -fx-background-radius: 10;
}
/* Lista de ideias — células expandidas */
.ideas-list .list-cell {
    -fx-padding: 0;
    -fx-background-color: #f7fbff;
    -fx-border-color: transparent transparent #dce8f5 transparent;
    -fx-border-width: 0 0 1 0;
}
.ideas-list .list-cell:selected {
    -fx-background-color: #dce8f8;
}
.ideas-list .list-cell:odd {
    -fx-background-color: #f0f5fc;
}
.ideas-list .list-cell:hover {
    -fx-background-color: #e8f1fa;
}
/* Coluna Kanban */
.kanban-col-header {
    -fx-font-size: 12px;
    -fx-font-weight: 700;
    -fx-text-fill: white;
    -fx-padding: 6 10 6 10;
    -fx-background-radius: 6 6 0 0;
}
.kanban-col-body {
    -fx-background-color: #f3f7fb;
    -fx-border-radius: 0 0 6 6;
    -fx-background-radius: 0 0 6 6;
}

/* ═══════════════════════════════════════════════════════════════════════════
   AGENDA CIENTÍFICA — SISTEMA DE PLANEJAMENTO PESSOAL
   Visual: Padrão científico/acadêmico — laboratório, pesquisa, precisão
   Paleta: Azul escuro + Ciano + Âmbar + Teal
   ───────────────────────────────────────────────────────────────────────────
   Todos os valores de cor são TOKENS definidos aqui no .root.
   Para criar um novo tema, basta criar um CSS que redeclare esses tokens
   e registrá-lo em ThemeManager.Theme.
   ═══════════════════════════════════════════════════════════════════════════ */
.root {
    -fx-font-family: "Inter", "Segoe UI", "DejaVu Sans", sans-serif;
    -fx-font-size: 13px;

    /* ── HEADER / BRAND ─────────────────────────────────── */
    -t-header-a  : #03183e;
    -t-header-b  : #072d5e;
    -t-accent    : #00b4d8;
    -t-accent-fg : #7ec8e3;
    -t-accent-lbl: #a8d4e6;

    /* ── FUNDOS ──────────────────────────────────────────── */
    -t-app-bg    : #edf1f8;
    -t-surface   : #ffffff;
    -t-surface-a : #f5f8fd;
    -t-surface-b : #f7fbff;
    -t-surface-c : #f0f5fc;
    -t-surface-d : #e2ecf8;
    -t-hover     : #edf5ff;
    -t-selected  : #d6eaf8;
    -t-selected2 : #dce8f8;

    /* ── TEXTO ───────────────────────────────────────────── */
    -t-text      : #0d1b2a;
    -t-text-b    : #03183e;
    -t-text-s    : #1e3a5f;
    -t-text-m    : #5a7a9e;
    -t-text-m2   : #7a9bbf;
    -t-text-inv  : #f0f8ff;

    /* ── COR PRIMÁRIA ────────────────────────────────────── */
    -t-pri       : #1565c0;
    -t-pri-dk    : #0d47a1;
    -t-pri-lt    : #eef4fc;
    -t-pri-lt2   : #dce8f8;
    -t-pri-bd    : #5c85c0;

    /* ── BORDAS ──────────────────────────────────────────── */
    -t-bd        : #b8cfe8;
    -t-bd-lt     : #d6e4f5;
    -t-bd-mid    : #9ab4d2;
    -t-bd-sub    : #cad8ee;
    -t-bd-cal    : #c8d9ee;
    -t-bd-list   : #e5eef8;

    /* ── ABAS ────────────────────────────────────────────── */
    -t-tab-bg    : #cddaed;
    -t-tab-hdr   : #d6e4f5;
    -t-tab-sel   : #ffffff;
    -t-tab-fg    : #1e3a5f;
    -t-tab-sfg   : #03183e;

    /* ── INPUT ───────────────────────────────────────────── */
    -t-inp-bg    : #f5f8fd;
    -t-inp-bd    : #9ab4d2;

    /* ── BARRA DE STATUS ─────────────────────────────────── */
    -t-sb-bg     : #03183e;
    -t-sb-bd     : #1a3a5c;
    -t-sb-fg     : #7ec8e3;

    /* ── FILTROS ─────────────────────────────────────────── */
    -t-flt-bg    : #f0f5fc;
    -t-flt-bd    : #cad8ee;
    -t-flt-fg    : #2c4a72;
    -t-flt-sel   : #1565c0;
    -t-flt-per   : #00695c;

    /* ── PERIGO / ERRO ───────────────────────────────────── */
    -t-err       : #b71c1c;
    -t-err-dk    : #c62828;
    -t-err-bg    : #fdf0f0;
    -t-err-hov   : #fde8e8;

    /* ── CALENDÁRIO ──────────────────────────────────────── */
    -t-cal-bg    : #f0f5fc;
    -t-cal-bd    : #c8d9ee;
    -t-cal-hdr   : #2c4a72;
    -t-cal-today : #1565c0;

    /* ── IDEIAS / KANBAN ─────────────────────────────────── */
    -t-kan-bg    : #f3f7fb;
    -t-ideas-bg  : #edf1f8;
}

.app-root { -fx-background-color: -t-app-bg; }

/* ── Cabeçalho ─────────────────────────────────────────────────────────── */
.header-bar {
    -fx-background-color: linear-gradient(to right, -t-header-a 0%, -t-header-b 100%);
    -fx-border-color: -t-accent;
    -fx-border-width: 0 0 2 0;
    -fx-effect: dropshadow(gaussian, rgba(0,180,216,0.25), 14, 0.4, 0, 4);
}
.header-bar .page-title { -fx-text-fill: -t-text-inv; }
.page-title {
    -fx-text-fill: -t-text;
    -fx-font-size: 21px;
    -fx-font-weight: 700;
}
.page-subtitle {
    -fx-text-fill: -t-accent-fg;
    -fx-font-size: 11.5px;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace;
}

/* ── Abas ──────────────────────────────────────────────────────────────── */
.main-tabs { -fx-tab-min-height: 36px; -fx-tab-max-height: 36px; }
.main-tabs .tab-header-area .tab-header-background { -fx-background-color: -t-tab-hdr; }
.main-tabs .tab {
    -fx-background-color: -t-tab-bg;
    -fx-padding: 6 14 6 14;
    -fx-font-weight: 600;
    -fx-font-size: 12px;
    -fx-text-base-color: -t-tab-fg;
}
.main-tabs .tab:selected {
    -fx-background-color: -t-tab-sel;
    -fx-text-base-color: -t-tab-sfg;
    -fx-border-color: transparent transparent -t-pri transparent;
    -fx-border-width: 0 0 3 0;
}

/* ── Cards de seção ─────────────────────────────────────────────────────── */
.section-card {
    -fx-background-color: -t-surface;
    -fx-background-radius: 8;
    -fx-border-radius: 8;
    -fx-border-color: -t-bd;
    -fx-border-width: 1;
    -fx-effect: dropshadow(gaussian, rgba(3,24,62,0.07), 10, 0.2, 0, 3);
}
.section-title {
    -fx-font-size: 14px;
    -fx-font-weight: 700;
    -fx-text-fill: -t-text-b;
    -fx-padding: 0 0 6 0;
    -fx-border-color: transparent transparent -t-bd-lt transparent;
    -fx-border-width: 0 0 1 0;
}

/* ── KPI Cards ──────────────────────────────────────────────────────────── */
.kpi-card {
    -fx-background-color: -t-surface;
    -fx-background-radius: 8;
    -fx-border-radius: 8;
    -fx-border-color: -t-bd;
    -fx-border-width: 0 0 0 4;
    -fx-effect: dropshadow(gaussian, rgba(3,24,62,0.08), 8, 0.2, 0, 2);
    -fx-padding: 12 16 12 16;
}
.kpi-title {
    -fx-font-size: 11px;
    -fx-font-weight: 700;
    -fx-text-fill: -t-text-m;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace;
}
.kpi-value {
    -fx-font-size: 30px;
    -fx-font-weight: 800;
    -fx-font-family: "JetBrains Mono", "Consolas", "Courier New", monospace;
    -fx-text-fill: -t-text;
}
/* Cores KPI são semânticas — mantidas fixas */
.kpi-blue   { -fx-border-color: #1565c0; } .kpi-blue   .kpi-value { -fx-text-fill: #1565c0; }
.kpi-red    { -fx-border-color: #b71c1c; } .kpi-red    .kpi-value { -fx-text-fill: #b71c1c; }
.kpi-orange { -fx-border-color: #e65100; } .kpi-orange .kpi-value { -fx-text-fill: #e65100; }
.kpi-purple { -fx-border-color: #6a1b9a; } .kpi-purple .kpi-value { -fx-text-fill: #6a1b9a; }
.kpi-cyan   { -fx-border-color: #006d8f; } .kpi-cyan   .kpi-value { -fx-text-fill: #006d8f; }
.kpi-green  { -fx-border-color: #1b5e20; } .kpi-green  .kpi-value { -fx-text-fill: #1b5e20; }
.kpi-indigo { -fx-border-color: #283593; } .kpi-indigo .kpi-value { -fx-text-fill: #283593; }
.kpi-red    { -fx-border-color: #e53935; }
.kpi-red-value { -fx-text-fill: #c62828; }

/* ── Botões ─────────────────────────────────────────────────────────────── */
.primary-button {
    -fx-background-color: -t-pri;
    -fx-background-radius: 6;
    -fx-text-fill: -t-text-inv;
    -fx-font-weight: 700;
    -fx-font-size: 12px;
    -fx-cursor: hand;
    -fx-padding: 7 16 7 16;
    -fx-effect: dropshadow(gaussian, rgba(21,101,192,0.3), 6, 0.3, 0, 2);
}
.primary-button:hover { -fx-background-color: -t-pri-dk; }

.secondary-button {
    -fx-background-color: -t-pri-lt;
    -fx-background-radius: 6;
    -fx-border-color: -t-pri-bd;
    -fx-border-radius: 6;
    -fx-text-fill: -t-pri;
    -fx-font-weight: 600;
    -fx-font-size: 12px;
    -fx-cursor: hand;
    -fx-padding: 6 14 6 14;
}
.secondary-button:hover { -fx-background-color: -t-pri-lt2; }

.danger-button {
    -fx-background-color: -t-err-bg;
    -fx-background-radius: 6;
    -fx-border-color: -t-err-dk;
    -fx-border-radius: 6;
    -fx-text-fill: -t-err;
    -fx-font-weight: 700;
    -fx-font-size: 12px;
    -fx-cursor: hand;
    -fx-padding: 6 14 6 14;
}
.danger-button:hover { -fx-background-color: -t-err-hov; }

.icon-button {
    -fx-background-color: -t-pri-lt;
    -fx-background-radius: 5;
    -fx-border-color: -t-pri-bd;
    -fx-border-radius: 5;
    -fx-text-fill: -t-pri;
    -fx-font-weight: 700;
    -fx-font-size: 13px;
    -fx-cursor: hand;
    -fx-padding: 3 6 3 6;
    -fx-min-width: 30px;
    -fx-pref-width: 30px;
}
.icon-button:hover { -fx-background-color: -t-pri-lt2; }
.icon-button.danger { -fx-background-color: -t-err-bg; -fx-border-color: -t-err-dk; -fx-text-fill: -t-err; }
.icon-button.danger:hover { -fx-background-color: -t-err-hov; }

.nav-button {
    -fx-background-color: transparent;
    -fx-border-color: -t-pri-bd;
    -fx-border-radius: 4;
    -fx-text-fill: -t-pri;
    -fx-font-size: 18px;
    -fx-font-weight: 700;
    -fx-cursor: hand;
    -fx-padding: 1 10 1 10;
}
.nav-button:hover { -fx-background-color: -t-pri-lt2; }

/* ── Campos de formulário ───────────────────────────────────────────────── */
.input-control {
    -fx-background-color: -t-inp-bg;
    -fx-background-radius: 5;
    -fx-border-color: -t-inp-bd;
    -fx-border-radius: 5;
    -fx-border-width: 1;
    -fx-font-size: 12.5px;
}
.input-control:focused {
    -fx-border-color: -t-pri;
    -fx-background-color: -t-surface;
    -fx-effect: dropshadow(gaussian, rgba(21,101,192,0.12), 6, 0.3, 0, 0);
}

/* ── Lista limpa ────────────────────────────────────────────────────────── */
.clean-list {
    -fx-background-color: -t-surface-b;
    -fx-border-color: -t-bd;
    -fx-border-radius: 5;
    -fx-background-radius: 5;
}
.clean-list .list-cell {
    -fx-padding: 6 12 6 12;
    -fx-font-size: 11.5px;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace;
    -fx-text-fill: -t-text-s;
    -fx-background-color: -t-surface-b;
    -fx-border-color: transparent transparent -t-bd-list transparent;
    -fx-border-width: 0 0 1 0;
}
.clean-list .list-cell:selected { -fx-background-color: -t-selected;  -fx-text-fill: -t-text-b; }
.clean-list .list-cell:odd      { -fx-background-color: -t-surface-c; }

/* ── Toggle de visualização ─────────────────────────────────────────────── */
.view-toggle-bar {
    -fx-background-color: -t-tab-hdr;
    -fx-background-radius: 7;
    -fx-padding: 3;
}
.view-toggle-btn {
    -fx-background-color: transparent;
    -fx-background-radius: 5;
    -fx-text-fill: -t-tab-fg;
    -fx-font-size: 12px;
    -fx-font-weight: 600;
    -fx-padding: 4 12 4 12;
    -fx-cursor: hand;
}
.view-toggle-btn:selected {
    -fx-background-color: -t-pri;
    -fx-text-fill: -t-text-inv;
    -fx-effect: dropshadow(gaussian, rgba(21,101,192,0.3), 6, 0.3, 0, 2);
}

/* ── Navegação ──────────────────────────────────────────────────────────── */
.nav-period-label {
    -fx-font-size: 13.5px;
    -fx-font-weight: 700;
    -fx-text-fill: -t-text-b;
    -fx-padding: 0 8 0 8;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace;
}
.agenda-top-bar {
    -fx-padding: 6 0 6 0;
    -fx-border-color: transparent transparent -t-bd-lt transparent;
    -fx-border-width: 0 0 1 0;
}

/* ── Colunas de semana ──────────────────────────────────────────────────── */
.day-column {
    -fx-background-color: -t-surface-a;
    -fx-background-radius: 6;
    -fx-border-color: -t-bd;
    -fx-border-radius: 6;
    -fx-border-width: 1;
}
.day-column-today { -fx-background-color: -t-hover; -fx-border-color: -t-pri; -fx-border-width: 2; }
.day-column-header {
    -fx-font-size: 11.5px; -fx-font-weight: 700; -fx-text-fill: -t-text-s;
    -fx-background-color: -t-surface-d; -fx-background-radius: 4;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace; -fx-padding: 4;
}
.day-column-header-today {
    -fx-font-size: 11.5px; -fx-font-weight: 700; -fx-text-fill: -t-text-inv;
    -fx-background-color: -t-pri; -fx-background-radius: 4;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace; -fx-padding: 4;
}

/* ── Grid anual ─────────────────────────────────────────────────────────── */
.year-grid { -fx-padding: 8; }
.year-month-card {
    -fx-background-color: -t-surface; -fx-background-radius: 6;
    -fx-border-color: -t-bd; -fx-border-radius: 6;
    -fx-border-width: 0 0 0 3; -fx-padding: 10 14 10 14;
    -fx-cursor: hand; -fx-pref-width: 160;
    -fx-effect: dropshadow(gaussian, rgba(3,24,62,0.06), 6, 0.15, 0, 1);
}
.year-month-card:hover {
    -fx-background-color: -t-hover; -fx-border-color: -t-pri;
    -fx-effect: dropshadow(gaussian, rgba(21,101,192,0.15), 8, 0.3, 0, 2);
}
.year-month-name  { -fx-font-size: 12.5px; -fx-font-weight: 700; -fx-text-fill: -t-text-b; }
.year-month-count { -fx-font-size: 28px; -fx-font-weight: 800; -fx-font-family: "JetBrains Mono", "Consolas", monospace; -fx-text-fill: -t-pri; }
.year-month-open  { -fx-font-size: 11px; -fx-text-fill: -t-text-m; -fx-font-family: "JetBrains Mono", "Consolas", monospace; }

/* ── Barra de status ────────────────────────────────────────────────────── */
.status-bar {
    -fx-background-color: -t-sb-bg;
    -fx-border-color: -t-sb-bd;
    -fx-border-width: 1 0 0 0;
}
.status-label {
    -fx-text-fill: -t-sb-fg;
    -fx-font-size: 11.5px;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace;
}

/* ── Grid de formulário ─────────────────────────────────────────────────── */
.form-grid { -fx-padding: 4 0 4 0; }
.form-grid .label { -fx-font-weight: 600; -fx-text-fill: -t-text-s; -fx-font-size: 12px; }
.dashboard-cards { -fx-padding: 4; }

/* ── Recorrência de tarefas ─────────────────────────────────────────────── */
.recurrence-day-check {
    -fx-font-size: 11px; -fx-padding: 3 5 3 5; -fx-background-radius: 4;
    -fx-cursor: hand; -fx-font-family: "JetBrains Mono", "Consolas", monospace;
}
.recurrence-day-check:selected { -fx-text-fill: -t-pri; -fx-font-weight: 700; }
.form-label { -fx-font-size: 12px; -fx-text-fill: -t-text-s; -fx-font-weight: 600; }

/* ── Configurações — painéis de categoria ───────────────────────────────── */
.config-section {
    -fx-background-color: -t-surface;
    -fx-background-radius: 8;
    -fx-border-color: -t-bd;
    -fx-border-radius: 8;
    -fx-border-width: 0 0 0 5;
    -fx-effect: dropshadow(gaussian, rgba(3,24,62,0.07), 10, 0.2, 0, 3);
}
.config-task      { -fx-border-color: #1565c0; }
.config-checklist { -fx-border-color: #006d5b; }
.config-study     { -fx-border-color: #e65100; }
.config-study-type{ -fx-border-color: #0097a7; }
.config-idea      { -fx-border-color: #6a1b9a; }
.config-theme     { -fx-border-color: -t-accent; }

/* ── Estado vazio ───────────────────────────────────────────────────────── */
.empty-state-label {
    -fx-font-size: 13px; -fx-text-fill: -t-text-m2;
    -fx-font-style: italic;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace;
}

/* ── ScrollPane sem borda visível ───────────────────────────────────────── */
.edge-to-edge { -fx-background-color: transparent; -fx-border-color: transparent; -fx-padding: 0; }
.edge-to-edge .viewport { -fx-background-color: transparent; }

/* ── Diálogo de confirmação ─────────────────────────────────────────────── */
.confirm-dialog {
    -fx-background-color: -t-surface;
    -fx-border-color: -t-bd;
    -fx-border-width: 1;
    -fx-font-family: "Inter", "Segoe UI", sans-serif;
}
.confirm-dialog .header-panel              { -fx-background-color: -t-header-a; }
.confirm-dialog .header-panel .label       { -fx-text-fill: -t-text-inv; -fx-font-weight: 700; -fx-font-size: 13px; }
.confirm-dialog .content.label             { -fx-text-fill: -t-text-s;   -fx-font-size: 12.5px; }

/* ═══════════════════════════════════════════════════════════════════════════
   ABA DE ESTUDOS E ATIVIDADES
   ═══════════════════════════════════════════════════════════════════════════ */
.study-plan-title  { -fx-font-size: 13px;   -fx-font-weight: 700; -fx-text-fill: -t-text; }
.study-plan-detail { -fx-font-size: 10.5px; -fx-text-fill: -t-text-m; -fx-font-family: "JetBrains Mono", "Consolas", monospace; }

/* ── Badges ─────────────────────────────────────────────────────────────── */
.study-badge {
    -fx-padding: 2 8 2 8; -fx-background-radius: 10;
    -fx-font-size: 10px; -fx-font-weight: 700;
    -fx-font-family: "JetBrains Mono", "Consolas", monospace;
}
.badge-type                { -fx-background-color: #dce8f8; -fx-text-fill: #1565c0; }
.badge-status-planejado    { -fx-background-color: #e8eaf6; -fx-text-fill: #283593; }
.badge-status-em_andamento { -fx-background-color: #fff3e0; -fx-text-fill: #e65100; }
.badge-status-concluido    { -fx-background-color: #e8f5e9; -fx-text-fill: #1b5e20; }
.badge-status-pausado      { -fx-background-color: #fce4ec; -fx-text-fill: #880e4f; }
.badge-status-abandonado   { -fx-background-color: #f5f5f5; -fx-text-fill: #757575; }

/* ── Barra de progresso ─────────────────────────────────────────────────── */
.study-progress-bar               { -fx-pref-height: 9px; -fx-min-height: 9px; }
.study-progress-bar .bar          { -fx-background-color: linear-gradient(to right, #1565c0, #0d47a1); -fx-background-radius: 4; -fx-background-insets: 0; }
.study-progress-bar .track        { -fx-background-color: -t-surface-d; -fx-background-radius: 4; -fx-background-insets: 0; }
.study-progress-bar.progress-complete .bar { -fx-background-color: linear-gradient(to right, #1b5e20, #2e7d32); }
.study-progress-bar.progress-high     .bar { -fx-background-color: linear-gradient(to right, #33691e, #558b2f); }
.study-progress-bar.progress-low      .bar { -fx-background-color: linear-gradient(to right, #b71c1c, #c62828); }
.study-progress-label { -fx-font-size: 11.5px; -fx-font-weight: 700; -fx-text-fill: -t-pri; -fx-font-family: "JetBrains Mono", "Consolas", monospace; }

/* ── Prazos ─────────────────────────────────────────────────────────────── */
.deadline-ok      { -fx-text-fill: #1b5e20; -fx-font-size: 10.5px; -fx-font-family: "JetBrains Mono", "Consolas", monospace; }
.deadline-warn    { -fx-text-fill: #e65100; -fx-font-size: 10.5px; -fx-font-weight: 700; -fx-font-family: "JetBrains Mono", "Consolas", monospace; }
.deadline-overdue { -fx-text-fill: -t-err;  -fx-font-size: 10.5px; -fx-font-weight: 700; -fx-font-family: "JetBrains Mono", "Consolas", monospace; }
.study-dates-label { -fx-font-size: 11.5px; -fx-text-fill: -t-text-m; -fx-font-family: "JetBrains Mono", "Consolas", monospace; }

/* ═══════════════════════════════════════════════════════════════════════════
   DIÁRIO CIENTÍFICO (StudyDiaryWindow)
   ═══════════════════════════════════════════════════════════════════════════ */
.diary-header-bar {
    -fx-background-color: linear-gradient(to right, -t-header-a 0%, -t-header-b 100%);
    -fx-border-color: transparent transparent -t-accent transparent;
    -fx-border-width: 0 0 2 0;
    -fx-effect: dropshadow(gaussian, rgba(0,180,216,0.22), 14, 0.35, 0, 4);
}
.diary-header-bar .page-title { -fx-text-fill: -t-text-inv; }
.diary-header-bar .label      { -fx-text-fill: -t-accent-lbl; }
.diary-stats-label { -fx-text-fill: -t-accent-fg; -fx-font-size: 11px; -fx-font-family: "JetBrains Mono", "Consolas", monospace; }

/* ═══════════════════════════════════════════════════════════════════════════
   KPI COMPACTO
   ═══════════════════════════════════════════════════════════════════════════ */
.kpi-mini {
    -fx-background-color: -t-surface;
    -fx-background-radius: 7; -fx-border-radius: 7;
    -fx-border-color: -t-bd; -fx-border-width: 0 0 0 4;
    -fx-effect: dropshadow(gaussian, rgba(3,24,62,0.07), 6, 0.15, 0, 2);
    -fx-padding: 8 12 8 12; -fx-min-width: 130;
}
.kpi-mini .kpi-title { -fx-font-size: 10px; }
.kpi-mini .kpi-value { -fx-font-size: 22px; }

/* ── Filtros de toggle ──────────────────────────────────────────────────── */
.filter-box {
    -fx-background-color: -t-flt-bg;
    -fx-background-radius: 7; -fx-border-radius: 7;
    -fx-border-color: -t-flt-bd; -fx-padding: 8 10 8 10;
}
.filter-toggle {
    -fx-background-color: -t-surface;
    -fx-background-radius: 14; -fx-border-radius: 14;
    -fx-border-color: -t-bd-mid;
    -fx-text-fill: -t-flt-fg; -fx-font-size: 11.5px;
    -fx-padding: 3 11 3 11; -fx-cursor: hand;
}
.filter-toggle:hover { -fx-background-color: -t-pri-lt2; -fx-border-color: -t-pri-bd; }
.filter-toggle:selected { -fx-background-color: -t-flt-sel; -fx-border-color: -t-flt-sel; -fx-text-fill: -t-text-inv; -fx-font-weight: 700; }
.filter-toggle.period-toggle:selected { -fx-background-color: -t-flt-per; -fx-border-color: -t-flt-per; }

/* ── Calendário de frequência ───────────────────────────────────────────── */
.calendar-week-header { -fx-font-weight: 700; -fx-font-size: 11px; -fx-text-fill: -t-cal-hdr; -fx-padding: 2 0 2 0; }
.calendar-day {
    -fx-background-color: -t-cal-bg;
    -fx-background-radius: 6; -fx-border-radius: 6;
    -fx-border-color: -t-cal-bd; -fx-cursor: default;
}
.calendar-day-num  { -fx-font-size: 11px; -fx-font-weight: 700; -fx-text-fill: -t-text-m; }
.calendar-day-sym  { -fx-font-size: 14px; -fx-font-weight: 700; }
.calendar-today    { -fx-border-color: -t-cal-today !important; -fx-border-width: 2; }

/* Status de frequência — cores semânticas mantidas fixas */
.attend-present     { -fx-background-color: #e8f5e9; }
.attend-present .calendar-day-sym  { -fx-text-fill: #2e7d32; }
.attend-partial     { -fx-background-color: #fff9c4; }
.attend-partial .calendar-day-sym  { -fx-text-fill: #f57f17; }
.attend-absent      { -fx-background-color: #ffebee; }
.attend-absent .calendar-day-sym   { -fx-text-fill: #c62828; }
.attend-compensated { -fx-background-color: #e3f2fd; }
.attend-compensated .calendar-day-sym { -fx-text-fill: #1565c0; }
.attend-future      { -fx-background-color: #f3e5f5; }
.attend-future .calendar-day-sym   { -fx-text-fill: #6a1b9a; }
.attend-none        { -fx-background-color: #f5f5f5; }
.attend-none .calendar-day-sym     { -fx-text-fill: #bdbdbd; }

.calendar-legend { -fx-font-size: 11px; -fx-padding: 1 6 1 6; -fx-background-radius: 10; -fx-border-radius: 10; }
.comp-card {
    -fx-background-color: -t-surface;
    -fx-background-radius: 7; -fx-border-radius: 7;
    -fx-border-color: -t-cal-bd;
    -fx-effect: dropshadow(gaussian, rgba(3,24,62,0.06), 4, 0.1, 0, 1);
}

/* ── Ideias e Projetos — Kanban & Cards ─────────────────────────────────── */
.ideas-kanban-scroll { -fx-background-color: -t-ideas-bg; -fx-border-color: transparent; }
.ideas-kanban-scroll > .viewport { -fx-background-color: -t-ideas-bg; }
.idea-card {
    -fx-background-color: -t-surface;
    -fx-background-radius: 6; -fx-border-radius: 6;
    -fx-border-width: 0 0 0 4; -fx-padding: 8 12 8 12;
    -fx-effect: dropshadow(gaussian, rgba(3,24,62,0.07), 6, 0.2, 0, 2);
    -fx-cursor: hand;
}
.idea-badge { -fx-font-size: 10px; -fx-font-weight: 600; -fx-padding: 2 7 2 7; -fx-background-radius: 10; }

.ideas-list .list-cell {
    -fx-padding: 0; -fx-background-color: -t-surface-b;
    -fx-border-color: transparent transparent -t-bd-lt transparent;
    -fx-border-width: 0 0 1 0;
}
.ideas-list .list-cell:selected { -fx-background-color: -t-selected2; }
.ideas-list .list-cell:odd      { -fx-background-color: -t-surface-c; }
.ideas-list .list-cell:hover    { -fx-background-color: -t-hover; }

.kanban-col-header {
    -fx-font-size: 12px; -fx-font-weight: 700; -fx-text-fill: -t-text-inv;
    -fx-padding: 6 10 6 10; -fx-background-radius: 6 6 0 0;
}
.kanban-col-body { -fx-background-color: -t-kan-bg; -fx-border-radius: 0 0 6 6; -fx-background-radius: 0 0 6 6; }

/* ═══════════════════════════════════════════════════════════════════════════
   AGENDA CIENTÍFICA — TEMA ESCURO
   Inspirado em: GitHub Dark / VS Code Dark+
   ───────────────────────────────────────────────────────────────────────────
   Este arquivo APENAS redefine os tokens do .root declarados em app.css.
   Não repete regras de layout — apenas muda as cores.
   ═══════════════════════════════════════════════════════════════════════════ */
.root {
    /* HEADER / BRAND */
    -t-header-a  : #010b1a;
    -t-header-b  : #051828;
    /* -t-accent permanece #00b4d8 — vibra bem em fundos escuros */
    -t-accent-fg : #58a6ff;
    -t-accent-lbl: #79c0ff;

    /* FUNDOS */
    -t-app-bg    : #0d1117;
    -t-surface   : #161b22;
    -t-surface-a : #1c2128;
    -t-surface-b : #1a1f26;
    -t-surface-c : #21262d;
    -t-surface-d : #1f2937;
    -t-hover     : #21262d;
    -t-selected  : #1f3d65;
    -t-selected2 : #1c3458;

    /* TEXTO */
    -t-text      : #e6edf3;
    -t-text-b    : #c9d1d9;
    -t-text-s    : #cdd9e5;
    -t-text-m    : #8b949e;
    -t-text-m2   : #6e7681;
    -t-text-inv  : #e6edf3;

    /* COR PRIMÁRIA */
    -t-pri       : #388bfd;
    -t-pri-dk    : #1f6feb;
    -t-pri-lt    : #1c3458;
    -t-pri-lt2   : #1f3a5c;
    -t-pri-bd    : #388bfd;

    /* BORDAS */
    -t-bd        : #30363d;
    -t-bd-lt     : #21262d;
    -t-bd-mid    : #30363d;
    -t-bd-sub    : #2d333b;
    -t-bd-cal    : #2d333b;
    -t-bd-list   : #21262d;

    /* ABAS */
    -t-tab-bg    : #21262d;
    -t-tab-hdr   : #161b22;
    -t-tab-sel   : #1c2128;
    -t-tab-fg    : #8b949e;
    -t-tab-sfg   : #e6edf3;

    /* INPUT */
    -t-inp-bg    : #1c2128;
    -t-inp-bd    : #30363d;

    /* BARRA DE STATUS */
    -t-sb-bg     : #010b1a;
    -t-sb-bd     : #21262d;
    -t-sb-fg     : #58a6ff;

    /* FILTROS */
    -t-flt-bg    : #1c2128;
    -t-flt-bd    : #30363d;
    -t-flt-fg    : #8b949e;
    -t-flt-sel   : #388bfd;
    -t-flt-per   : #009688;

    /* PERIGO / ERRO */
    -t-err       : #f85149;
    -t-err-dk    : #ff7b72;
    -t-err-bg    : #2d1b1b;
    -t-err-hov   : #3d2020;

    /* CALENDÁRIO */
    -t-cal-bg    : #1c2128;
    -t-cal-bd    : #2d333b;
    -t-cal-hdr   : #8b949e;
    -t-cal-today : #388bfd;

    /* IDEIAS / KANBAN */
    -t-kan-bg    : #1c2128;
    -t-ideas-bg  : #0d1117;
}

/* ── Overrides de cores semânticas para tema escuro ────────────────────── */

/* Badges de estudo (backgrounds escurecem, texto fica mais vibrante) */
.badge-type                { -fx-background-color: #1c3458; -fx-text-fill: #58a6ff; }
.badge-status-planejado    { -fx-background-color: #1a1f35; -fx-text-fill: #7986cb; }
.badge-status-em_andamento { -fx-background-color: #2d2010; -fx-text-fill: #ffb74d; }
.badge-status-concluido    { -fx-background-color: #0d2b10; -fx-text-fill: #56d364; }
.badge-status-pausado      { -fx-background-color: #2d1020; -fx-text-fill: #f06292; }
.badge-status-abandonado   { -fx-background-color: #21262d; -fx-text-fill: #8b949e; }

/* Calendário de frequência (cores escurecem o fundo, texto fica mais forte) */
.attend-present     { -fx-background-color: #0d2b12; }
.attend-present .calendar-day-sym  { -fx-text-fill: #56d364; }
.attend-partial     { -fx-background-color: #2d2810; }
.attend-partial .calendar-day-sym  { -fx-text-fill: #ffca28; }
.attend-absent      { -fx-background-color: #2d1010; }
.attend-absent .calendar-day-sym   { -fx-text-fill: #f85149; }
.attend-compensated { -fx-background-color: #10243a; }
.attend-compensated .calendar-day-sym { -fx-text-fill: #58a6ff; }
.attend-future      { -fx-background-color: #1f1030; }
.attend-future .calendar-day-sym   { -fx-text-fill: #ce93d8; }
.attend-none        { -fx-background-color: #21262d; }
.attend-none .calendar-day-sym     { -fx-text-fill: #484f58; }

/* KPI cores semânticas — mais brilhantes em fundo escuro */
.kpi-blue  .kpi-value { -fx-text-fill: #58a6ff; }
.kpi-red   .kpi-value { -fx-text-fill: #f85149; }
.kpi-green .kpi-value { -fx-text-fill: #56d364; }

/* Timer inline */
.timer-label-inline {
    -fx-text-fill: #58a6ff;
    -fx-background-color: #1c3458;
    -fx-border-color: #388bfd;
}

/* CSS para o contador inline do timer na célula da tarefa */
.timer-label-inline {
    -fx-font-family: "JetBrains Mono", monospace;
    -fx-font-size: 12px;
    -fx-text-fill: #1976d2;
    -fx-padding: 0 6 0 6;
    -fx-background-color: #e3f2fd;
    -fx-background-radius: 6;
    -fx-border-radius: 6;
    -fx-border-color: #90caf9;
    -fx-border-width: 1;
    -fx-alignment: center;
}

/* CSS para o contador inline do timer na célula da tarefa */
.timer-label-inline {
    -fx-font-family: "JetBrains Mono", monospace;
    -fx-font-size: 12px;
    -fx-text-fill: -t-pri;
    -fx-padding: 0 6 0 6;
    -fx-background-color: -t-pri-lt;
    -fx-background-radius: 6;
    -fx-border-radius: 6;
    -fx-border-color: -t-pri-bd;
    -fx-border-width: 1;
    -fx-alignment: center;
}
